// Resize a File to a JPEG data URL no wider than `maxW` px. Used by all
// photo uploads (profile, personal gallery, team gallery, workout photo)
// so we never blow the 1 MB Firestore doc limit. Default ~600 px / 70%
// quality lands a typical photo at 60-150 KB.
function resizeImageFile(file, maxW = 600, quality = 0.7) {
  return new Promise((resolve, reject) => {
    if (!file) return reject(new Error('No file'));
    if (file.size > 8 * 1024 * 1024) return reject(new Error('Photo too large (max 8 MB before resize)'));
    const reader = new FileReader();
    reader.onload = () => {
      const img = new Image();
      img.onload = () => {
        try {
          const canvas = document.createElement('canvas');
          const scale = Math.min(1, maxW / img.width);
          canvas.width = Math.max(1, Math.round(img.width * scale));
          canvas.height = Math.max(1, Math.round(img.height * scale));
          canvas.getContext('2d').drawImage(img, 0, 0, canvas.width, canvas.height);
          resolve({ dataUrl: canvas.toDataURL('image/jpeg', quality), w: canvas.width, h: canvas.height });
        } catch(e) { reject(e); }
      };
      img.onerror = () => reject(new Error('Image decode failed'));
      img.src = reader.result;
    };
    reader.onerror = () => reject(new Error('File read failed'));
    reader.readAsDataURL(file);
  });
}
// Strava integration
const STRAVA_CLIENT_ID = '213628'; // Set your Strava API client ID here
const STRAVA_REDIRECT_URI = 'https://turboprep.app';
let stravaTokens = null; // { access_token, refresh_token, expires_at, athlete }
let stravaActivities = []; // cached recent activities
let fitbitTokens = null; // { access_token, refresh_token, expires_at, user_id, scope }
let fitbitActivities = [];
// Fitbit Client ID — registered at https://dev.fitbit.com/apps
// Callback URL on the Fitbit app: https://turboprep.app/ (state=fitbit added by the OAuth start helper).
// Client Secret lives only in Netlify env (FITBIT_CLIENT_SECRET) — never in code.
const FITBIT_CLIENT_ID = '23VJKV';
window.FITBIT_CLIENT_ID = FITBIT_CLIENT_ID;
let userWorkouts = [];
let userChecklist = {}; // always an object, never undefined
// Plan overrides = reschedules of plan workouts when the athlete skips a day.
// Shape: { [planId]: { entries: [{ week, day, shiftedTo: 'YYYY-MM-DD', shiftedAt }] } }
// Identity per entry is (week, day) — all workouts scheduled that day shift together.
let userPlanOverrides = {};
let workoutsUnsubscribe = null;
let checklistUnsubscribe = null;
let planOverridesUnsubscribe = null;
let profileUnsubscribe = null;
// XP & Levelling (imported from state.js)
function calcXp() {
  let xp = 0;
  // Base XP: 10 per workout
  xp += userWorkouts.length * 10;
  // Daily 2x bonus: first workout each day gets bonus 10 XP
  // Day-bucket workouts using local-day keys, not UTC — a workout
  // logged 8 AM AEST (22:00 UTC the previous day) used to collapse
  // into "yesterday" and the streak math missed it.
  const dailyDates = new Set();
  userWorkouts.forEach(w => {
    const d = w.date ? (w.date.toDate ? w.date.toDate() : new Date(w.date)) : null;
    if (d) {
      const key = localDateKey(d);
      if (!dailyDates.has(key)) { dailyDates.add(key); xp += 10; } // +10 bonus for first workout of each day
    }
  });
  // Streak calculation with freeze support — same local-day rule.
  const dates = [...new Set(userWorkouts.map(w => {
    const d = w.date ? (w.date.toDate ? w.date.toDate() : new Date(w.date)) : null;
    return d ? localDateKey(d) : null;
  }).filter(Boolean))].sort();
  // Streak compute with freeze accounting. Two prior bugs:
  //   1) Multi-day gap with multiple freezes burned NONE — `diff === 2`
  //      check meant a 14-day streak with 2 freezes still snapped at a
  //      3-day gap.
  //   2) Freezes accrued on streak length, not workout count — when a
  //      freeze was consumed, `cur` advanced over a non-trained day,
  //      so freezes were issued for streak-days that included skips.
  // Now: track activeDays separately; freezes accrue per 7 active days;
  // gaps consume up to (gap-1) freezes if available.
  let best = 0, cur = 0;
  let freezesEarned = 0, freezesUsed = 0;
  let activeDays = 0;
  dates.forEach((d, i) => {
    if (i === 0) {
      cur = 1;
    } else {
      const diff = Math.round((new Date(d) - new Date(dates[i-1])) / 86400000);
      if (diff === 1) {
        cur += 1;
      } else if (diff > 1) {
        const needed = diff - 1;
        if ((freezesEarned - freezesUsed) >= needed) {
          cur += 1;
          freezesUsed += needed;
        } else {
          cur = 1;
        }
      }
    }
    activeDays++;
    if (cur > best) best = cur;
    if (activeDays > 0 && activeDays % 7 === 0) freezesEarned++;
  });
  // Store streak freeze balance for display
  try { localStorage.setItem('tp_streak_freezes', String(Math.max(0, freezesEarned - freezesUsed))); } catch(e) {}
  if (best >= 7) xp += 25;
  if (best >= 14) xp += 50;
  if (best >= 30) xp += 100;
  // Plan completion bonus
  if (userProfile?.activePlanId) {
    const plan = findPlan(userProfile.activePlanId);
    if (plan && plan.workouts) {
      const total = plan.workouts.length;
      let done = 0;
      plan.workouts.forEach((w, i) => {
        const k = userProfile.activePlanId + '-' + w.week + '-' + w.day + '-' + (plan.workouts.filter((ww, ii) => ii < i && ww.week === w.week && ww.day === w.day).length);
        if (userChecklist && userChecklist[k]) done++;
      });
      if (done >= total && total > 0) xp += 75;
    }
  }
  // RPE logging bonus (5 XP per workout with RPE)
  xp += userWorkouts.filter(w => w.rpe).length * 5;
  return xp;
}
// Level-up detection
function checkLevelUp(oldXp, newXp) {
  const oldLvl = getXpLevel(oldXp);
  const newLvl = getXpLevel(newXp);
  if (newLvl.idx > oldLvl.idx) {
    showLevelUpAnimation(newLvl);
  }
}
function showLevelUpAnimation(level) {
  haptic('success');
  const ov = document.createElement('div');
  ov.style.cssText = 'position:fixed;inset:0;z-index:600;background:rgba(0,0,0,.85);display:flex;align-items:center;justify-content:center;flex-direction:column;animation:fadeIn .3s';
  ov.innerHTML = `
    <div style="font-size:80px;animation:bounceIn .6s">${level.icon}</div>
    <div style="font-size:28px;font-weight:800;color:#fff;margin-top:16px;animation:bounceIn .6s .1s both">LEVEL UP!</div>
    <div style="font-size:18px;color:var(--primary);font-weight:700;margin-top:8px;animation:bounceIn .6s .2s both">${level.name}</div>
    <div style="font-size:14px;color:rgba(255,255,255,.6);margin-top:6px;animation:bounceIn .6s .3s both">${level.xp} XP</div>
    <button style="margin-top:24px;padding:12px 32px;font-size:14px;font-weight:700;border-radius:10px;border:none;background:var(--primary);color:var(--primary-fg);cursor:pointer;animation:bounceIn .6s .4s both" id="lvlup-dismiss">Nice!</button>
  `;
  if (!document.getElementById('lvlup-style')) {
    const style = document.createElement('style');
    style.id = 'lvlup-style';
    style.textContent = '@keyframes bounceIn{0%{transform:scale(0);opacity:0}60%{transform:scale(1.1)}100%{transform:scale(1);opacity:1}} @keyframes fadeIn{from{opacity:0}to{opacity:1}}';
    document.head.appendChild(style);
  }
  document.body.appendChild(ov);
  showCelebration('');
  ov.querySelector('#lvlup-dismiss')?.addEventListener('click', () => ov.remove());
  setTimeout(() => { if (ov.parentNode) ov.remove(); }, 8000);
}
