$('signup-btn')?.addEventListener('click', async () => {
  const name = $('signup-name').value.trim();
  const email = $('signup-email').value.trim();
  const password = $('signup-password').value;
  const role = $('signup-role').value || 'student';
  const yearLevel = role === 'student' ? $('signup-year').value : null;
  const tier = role === 'student' ? (document.querySelector('input[name="signup-tier"]:checked')?.value || 'basic') : null;
  const selectedTeamId = role === 'student' ? ($('signup-team')?.value || null) : null;
  const childEmail = role === 'parent' ? ($('signup-child-email')?.value?.trim() || null) : null;
  if (!name || !email || !password) {
    $('signup-error').textContent = 'Please fill in all fields.';
    show('signup-error');
    return;
  }
  if (role === 'parent' && !childEmail) {
    $('signup-error').textContent = 'Please enter your child\'s account email.';
    show('signup-error');
    return;
  }
  if (password.length < 6) {
    $('signup-error').textContent = 'Password must be at least 6 characters.';
    show('signup-error');
    return;
  }
  if (!auth) {
    $('signup-error').textContent = 'Firebase is not loaded. Check your connection or use Demo Mode.';
    show('signup-error');
    return;
  }
  hide('signup-error');
  const btn = $('signup-btn');
  btn.disabled = true;
  const originalLabel = btn.textContent;
  btn.textContent = 'Creating…';
  showLoading('Creating account...');
  try {
    const cred = await createUserWithEmailAndPassword(auth, email, password);
    await updateProfile(cred.user, { displayName: name });
    const userData = {
      displayName: name,
      email: email,
      role: role,
      yearLevel: yearLevel,
      fitnessLevel: tier,
      activePlanId: null,
      teamId: null,
      teamName: null,
      createdAt: serverTimestamp()
    };
    if (role === 'parent') userData.linkedChildEmail = childEmail;
    if (role === 'coach') userData.isCoach = true;
    // Roster pre-fill — if an admin imported this athlete's email via
    // the Excel/CSV roster import, override year/tier/subteam with the
    // coach's values and queue an auto-join to their team. Doc ID is
    // the sanitised lowercase email (matches admin.js sanitiseEmailKey).
    let rosterTeamId = null;
    if (db && role !== 'coach') {
      try {
        const emailKey = email.trim().toLowerCase().replace(/[^a-z0-9._-]/g, '_');
        const rosterSnap = await getDoc(doc(db, 'roster', emailKey));
        if (rosterSnap.exists()) {
          const r = rosterSnap.data();
          if (r.yearLevel) userData.yearLevel = r.yearLevel;
          if (r.fitnessLevel) userData.fitnessLevel = r.fitnessLevel;
          if (r.subteam) userData.subteamName = r.subteam;
          if (r.teamId) rosterTeamId = r.teamId;
        }
      } catch (e) {
        console.warn('Roster lookup failed (non-fatal):', e);
      }
    }
    // Effective team to join: the form selection wins; otherwise fall
    // back to the team the roster import assigned this athlete to.
    const effectiveTeamId = selectedTeamId || rosterTeamId;
    // Auto-join selected team — surface failure to the user instead of
    // silently leaving them without a team (was the source of the
    // post-signup "you can't see anything" complaint).
    let teamJoinNote = '';
    if (effectiveTeamId && db) {
      try {
        const teamSnap = await getDoc(doc(db, 'teams', effectiveTeamId));
        if (teamSnap.exists()) {
          const td = teamSnap.data();
          await updateDoc(doc(db, 'teams', effectiveTeamId), { members: arrayUnion(cred.user.uid) });
          userData.teamId = effectiveTeamId;
          userData.teamName = td.name;
          teamJoinNote = ` Joined ${td.name}.`;
        } else {
          teamJoinNote = ' (Team not found — you can join one in-app.)';
        }
      } catch(e) {
        console.warn('Auto-join team failed:', e);
        teamJoinNote = ' (Could not auto-join team — add yours from the Team tab.)';
      }
    }
    await setDoc(doc(db, 'users', cred.user.uid), userData);
    if (role === 'coach') {
      await submitTeamRequest(cred.user, name, email);
      try { showToast?.('Account created. Coach approval request sent — you\'ll get an email when it\'s reviewed.', 'success'); } catch(_) {}
    } else if (role === 'parent') {
      try { showToast?.('Account created. Linked to ' + childEmail + '.', 'success'); } catch(_) {}
    } else {
      try { showToast?.('Welcome to TurboPrep!' + teamJoinNote, 'success'); } catch(_) {}
    }
    // onAuthStateChanged takes it from here — boots the main app.
  } catch(e) {
    hideLoading();
    btn.disabled = false;
    btn.textContent = originalLabel;
    $('signup-error').textContent = friendlyError(e.code);
    show('signup-error');
  }
});
$('logout-btn')?.addEventListener('click', async () => {
  closeUserMenu();
  try {
    if (workoutsUnsubscribe) { try { workoutsUnsubscribe(); } catch(e) {} workoutsUnsubscribe = null; }
    if (checklistUnsubscribe) { try { checklistUnsubscribe(); } catch(e) {} checklistUnsubscribe = null; }
    if (planOverridesUnsubscribe) { try { planOverridesUnsubscribe(); } catch(e) {} planOverridesUnsubscribe = null; }
    if (profileUnsubscribe) {
      try { typeof profileUnsubscribe === 'function' ? profileUnsubscribe() : clearInterval(profileUnsubscribe); } catch(e) {}
      profileUnsubscribe = null;
    }
    if (teamUnsubscribe) { try { teamUnsubscribe(); } catch(e) {} teamUnsubscribe = null; }
    try { unsubscribeTeamChat(); } catch(e) {}
    if (raceTimerInterval) { clearInterval(raceTimerInterval); raceTimerInterval = null; }
    if (window._tpRaceDayPoll) { clearInterval(window._tpRaceDayPoll); window._tpRaceDayPoll = null; }
    // Clean up the long-lived background tasks added in v3.5.x — these
    // were leaking past sign-out before today's audit pass.
    if (_demoRaceTimer) { try { clearInterval(_demoRaceTimer); } catch(e) {} _demoRaceTimer = null; _demoRaceState = null; }
    if (_trainingReminderInterval) { try { clearInterval(_trainingReminderInterval); } catch(e) {} _trainingReminderInterval = null; }
    if (_announcementsUnsub) { try { _announcementsUnsub(); } catch(e) {} _announcementsUnsub = null; }
    if (_globalSettingsUnsub) { try { _globalSettingsUnsub(); } catch(e) {} _globalSettingsUnsub = null; }
    if (_teamTrainingCueUnsub) { try { _teamTrainingCueUnsub(); } catch(_) {} _teamTrainingCueUnsub = null; }
    // Tear down the persistent centre bar's 1Hz tick + clear any active
    // session flags so a sign-out doesn't leave a stale strip ticking.
    try {
      window._tpTrainingActive = false;
      window._tpRaceDayStintActive = false;
      window.CentreBar?.hide?.();
    } catch(_) {}
    // Clear any cached edition flag so the next sign-in starts neutral.
    try { applyEditionTheme(null); } catch(_) {}
    // Clear coach-tab cross-account caches so signing in as a
    // different coach doesn't see the previous account's compliance
    // grid leak through.
    window._tpComplianceCache = null;
    window._tpComplianceCacheAt = 0;
    window._tpStudentSearch = '';
    window._tpStudentSort = 'compliance';
    await signOut(auth);
    currentUser = null;
    userProfile = null;
    userWorkouts = [];
    userChecklist = {};
    userPlanOverrides = {};
    showAuthLogin();
  } catch(e) {
    console.error('Logout error:', e);
  }
});
function friendlyError(code) {
  const map = {
    'auth/email-already-in-use': 'This email is already registered. Try logging in instead.',
    'auth/invalid-email': 'Please enter a valid email address.',
    'auth/user-not-found': 'No account found with this email.',
    'auth/wrong-password': 'Incorrect password. Please try again.',
    'auth/weak-password': 'Password must be at least 6 characters.',
    'auth/too-many-requests': 'Too many attempts. Please wait a moment and try again.',
    'auth/invalid-credential': 'Invalid email or password. Please try again.',
    'auth/network-request-failed': 'Network error. Check your connection and try again.',
  };
  return map[code] || 'Something went wrong. Please try again.';
}
// User Menu — single state attribute drives both menu and overlay so
// rapid taps and partial cache states can't desync them. The avatar
// button itself sits above the overlay so the user can always tap it
// to close, even while the scrim is up.
const USER_MENU_OPEN_ATTR = 'data-menu-open';
$('user-avatar-btn')?.addEventListener('click', (e) => {
  e.stopPropagation();
  e.preventDefault();
  const isOpen = document.body.getAttribute(USER_MENU_OPEN_ATTR) === '1';
  if (isOpen) closeUserMenu(); else openUserMenu();
});
function openUserMenu() {
  const menu = $('user-menu');
  const overlay = $('user-menu-overlay');
  const btn = $('user-avatar-btn');
  if (!menu || !overlay) return;
  document.body.setAttribute(USER_MENU_OPEN_ATTR, '1');
  menu.classList.remove('hidden');
  menu.style.display = '';
  overlay.classList.remove('hidden');
  overlay.style.display = '';
  btn?.setAttribute('aria-expanded', 'true');
  // Even before userProfile lands we can populate the avatar from auth —
  // otherwise the markup default "U" stays in place on first open.
  const seedInitial = ((userProfile?.displayName || currentUser?.displayName || currentUser?.email || 'U').trim().charAt(0) || 'U').toUpperCase();
  try { const ma0 = $('menu-avatar'); if (ma0) ma0.textContent = seedInitial; } catch(e) {}
  if (!userProfile) return;
  // Guard every element — during a partial cache update (new HTML, stale
  // JS, or vice versa) any of these IDs could be missing. Set what we
  // can; never throw and stop the whole menu from rendering.
  const setText = (id, val) => { const el = $(id); if (el) el.textContent = val; };
  const setDisplay = (id, val) => { const el = $(id); if (el) el.style.display = val; };
  const name = userProfile.displayName || 'User';
  setText('menu-name', name);
  const initial = (name || currentUser?.email || 'U').trim().charAt(0).toUpperCase();
  setText('menu-avatar', initial);
  const sub = (userProfile.yearLevel || 'Y7') + ' · ' + capitalize(userProfile.fitnessLevel || 'basic') + ' tier';
  setText('menu-sub', sub);
  // Legacy element id from the pre-3.4.0 markup. Some clients may still
  // be on a stale service-worker cache that has the old HTML; updating
  // it keeps that menu functional too.
  setText('menu-info', sub);
  const teamEl = $('menu-team');
  if (teamEl) {
    if (userProfile.teamName) {
      teamEl.textContent = userProfile.teamName;
      setDisplay('menu-team', '');
    } else {
      setDisplay('menu-team', 'none');
    }
  }
}
function closeUserMenu() {
  document.body.removeAttribute(USER_MENU_OPEN_ATTR);
  hide('user-menu');
  hide('user-menu-overlay');
  $('user-avatar-btn')?.setAttribute('aria-expanded', 'false');
}
$('user-menu-overlay')?.addEventListener('click', closeUserMenu);
// Esc closes the menu — keyboard users + iOS hardware keyboards.
document.addEventListener('keydown', (e) => {
  if (e.key === 'Escape' && document.body.getAttribute(USER_MENU_OPEN_ATTR) === '1') closeUserMenu();
});
// --- Feature 3: Remember scroll position per tab ---
const scrollPositions = {};
// --- Feature 6: Remember last active tab on reload ---
