/// Compute achievement levels for a single team member from the data
/// already in memory (workouts, streak, race archive, gallery photos).
/// Each entry: { id, label, icon, level: 'bronze'|'silver'|'gold'|null,
/// earned: bool, progress: '7/10', tier: number }. Returned in display
/// order. Pure function — no fetches.
function computeMemberAchievements(member) {
  if (!member) return [];
  const workouts = member.totalWorkouts || 0;
  const streak = member.streak || 0;
  const galleryAll = Array.isArray(window._tpTeamPhotos) ? window._tpTeamPhotos : [];
  const photos = galleryAll.filter(p => p.uploadedBy === member.uid).length;
  const archive = Array.isArray(window._tpRaceArchive) ? window._tpRaceArchive : [];
  const races = archive.filter(r => Array.isArray(r.drivers)
    && r.drivers.some(d => (d.uid && d.uid === member.uid)
      || (d.name && member.displayName && d.name.toLowerCase() === member.displayName.toLowerCase()))).length;
  const tiered = (count, tiers, label, id) => {
    let level = null, nextAt = tiers[0], tierIdx = 0;
    for (let i = tiers.length - 1; i >= 0; i--) {
      if (count >= tiers[i]) { tierIdx = i + 1; level = ['bronze','silver','gold','platinum'][i] || 'gold'; break; }
    }
    if (tierIdx < tiers.length) nextAt = tiers[tierIdx];
    return {
      id, label, level,
      earned: !!level,
      tier: tierIdx,
      maxTier: tiers.length,
      progress: count + ' / ' + nextAt,
      pct: Math.min(100, Math.round((count / nextAt) * 100)),
    };
  };
  return [
    tiered(workouts, [10, 25, 50, 100], 'Workouts logged', 'workouts'),
    tiered(streak,   [3, 7, 14, 30],    'Day streak',      'streak'),
    tiered(races,    [1, 3, 5, 10],     'Races completed', 'races'),
    tiered(photos,   [1, 5, 10, 25],    'Gallery uploads', 'gallery'),
  ];
}

/// Read-only member info sheet — anyone can open this from the Hub
/// members table. Shows the member's basic profile, app activity
/// summary, achievements, and their gallery uploads. Categories will
/// be expanded to mirror the coach's Excel template once shared.
function openMemberSheet(uid) {
  const member = teamMembers.find(m => m.uid === uid);
  if (!member) { showToast?.('Member not found.', 'warn'); return; }
  document.getElementById('member-sheet-backdrop')?.remove();
  const initials = (member.displayName || '?').trim().split(/\s+/)
    .map(w => w[0] || '').join('').slice(0, 2).toUpperCase() || '?';
  const subs = Array.isArray(teamData?.subteams) ? teamData.subteams : [];
  const sub = subs.find(s => Array.isArray(s.members) && s.members.includes(uid));
  const subLabel = sub ? sub.name : 'Whole team';
  const photoUrl = member.photoURL || '';
  // Pull the photos this member uploaded to the team gallery (any scope).
  const galleryAll = Array.isArray(window._tpTeamPhotos) ? window._tpTeamPhotos : [];
  const myPhotos = galleryAll.filter(p => p.uploadedBy === uid);
  const photoCells = myPhotos.length === 0
    ? '<div class="member-sheet-empty">No photos uploaded yet.</div>'
    : '<div class="member-sheet-photos">' +
      myPhotos.slice(0, 9).map(p =>
        `<img src="${escHtml(p.dataUrl)}" alt="${escHtml(p.caption || '')}">`
      ).join('') + '</div>';
  // Race overviews — placeholder card, fed by the race archive entries
  // referencing this member once the Excel structure is wired in.
  const archive = Array.isArray(window._tpRaceArchive) ? window._tpRaceArchive : [];
  const myRaces = archive.filter(r => Array.isArray(r.drivers)
    && r.drivers.some(d => (d.uid && d.uid === uid)
      || (d.name && member.displayName && d.name.toLowerCase() === member.displayName.toLowerCase())));
  const racesBlock = myRaces.length === 0
    ? '<div class="member-sheet-empty">No race overviews yet.</div>'
    : myRaces.slice(0, 6).map(r => `
        <div class="member-sheet-stat" style="grid-column:1 / -1">
          <div class="member-sheet-stat-lbl">${escHtml(r.raceName || 'Race')}${r.raceDate ? ' · ' + escHtml(r.raceDate) : ''}</div>
          <div style="font-size:13px;color:var(--fg);margin-top:4px;line-height:1.4">${escHtml(r.summary || '—')}</div>
        </div>`).join('');
  const ov = document.createElement('div');
  ov.id = 'member-sheet-backdrop';
  ov.className = 'member-sheet-backdrop';
  ov.innerHTML = `
    <div class="member-sheet" role="dialog" aria-label="Member info">
      <button class="member-sheet-close" aria-label="Close">×</button>
      <div class="member-sheet-handle"></div>
      <div class="member-sheet-head">
        <div class="member-sheet-avatar">${photoUrl ? `<img src="${escHtml(photoUrl)}" alt="">` : escHtml(initials)}</div>
        <div style="flex:1;min-width:0">
          <div class="member-sheet-name">${escHtml(member.displayName || 'Member')}</div>
          <div class="member-sheet-sub">${escHtml(subLabel)} · Year ${escHtml(String(member.yearLevel || '—'))}</div>
        </div>
        ${(userProfile?.isCoach && uid !== currentUser?.uid) ? `<button id="member-sheet-manage" type="button" style="padding:8px 14px;border-radius:10px;background:var(--primary);color:var(--primary-fg);border:none;font-weight:700;font-size:13px;cursor:pointer;flex-shrink:0">Manage</button>` : ''}
      </div>

      <div class="member-sheet-cat">
        <div class="member-sheet-cat-title">App Activity</div>
        <div class="member-sheet-stats">
          <div class="member-sheet-stat">
            <div class="member-sheet-stat-lbl">Workouts</div>
            <div class="member-sheet-stat-val">${member.totalWorkouts || 0}</div>
          </div>
          <div class="member-sheet-stat">
            <div class="member-sheet-stat-lbl">Streak</div>
            <div class="member-sheet-stat-val">${member.streak || 0}<span style="font-size:13px;font-weight:700;color:var(--muted-fg)">d</span></div>
          </div>
          <div class="member-sheet-stat">
            <div class="member-sheet-stat-lbl">Plans done</div>
            <div class="member-sheet-stat-val">${member.completedPlans || 0}</div>
          </div>
          <div class="member-sheet-stat">
            <div class="member-sheet-stat-lbl">Last active</div>
            <div class="member-sheet-stat-val" style="font-size:14px">${member.lastActive ? escHtml(new Date(member.lastActive).toLocaleDateString('en-AU')) : '—'}</div>
          </div>
        </div>
      </div>

      ${(userProfile?.isCoach && teamData?.id && uid !== currentUser?.uid) ? `
      <div class="member-sheet-cat">
        <div class="member-sheet-cat-title">Coach Notes <span style="font-size:10px;font-weight:600;color:var(--muted-fg);text-transform:none;letter-spacing:0;margin-left:6px">private — coaches only</span></div>
        <textarea id="member-coach-note" class="input" rows="3" maxlength="2000" placeholder="Private notes about this athlete — only coaches see this." style="font-size:13px"></textarea>
        <div style="display:flex;align-items:center;gap:8px;margin-top:6px">
          <button id="member-coach-note-save" type="button" class="btn btn-secondary" style="padding:7px 14px;font-size:12px">Save note</button>
          <span id="member-coach-note-status" style="font-size:11px;color:var(--muted-fg)"></span>
        </div>
      </div>` : ''}

      <div class="member-sheet-cat">
        <div class="member-sheet-cat-title">Achievements</div>
        <div class="achv-grid">
          ${computeMemberAchievements(member).map(a => `
            <div class="achv-card achv-${a.level || 'none'}">
              <div class="achv-medal" aria-hidden="true">${a.level ? `<svg viewBox="0 0 24 24" fill="currentColor" style="width:22px;height:22px"><path d="M12 2 L14.7 7.5 L20.8 8.4 L16.4 12.6 L17.5 18.6 L12 15.7 L6.5 18.6 L7.6 12.6 L3.2 8.4 L9.3 7.5 Z"/></svg>` : `<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.7" style="width:22px;height:22px"><path d="M12 2 L14.7 7.5 L20.8 8.4 L16.4 12.6 L17.5 18.6 L12 15.7 L6.5 18.6 L7.6 12.6 L3.2 8.4 L9.3 7.5 Z"/></svg>`}</div>
              <div class="achv-body">
                <div class="achv-label">${escHtml(a.label)}</div>
                <div class="achv-meta">${a.level ? a.level.charAt(0).toUpperCase() + a.level.slice(1) + ' · ' : ''}${escHtml(a.progress)}</div>
                <div class="achv-bar"><div class="achv-bar-fill" style="width:${a.pct}%"></div></div>
              </div>
            </div>
          `).join('')}
        </div>
      </div>

      <div class="member-sheet-cat">
        <div class="member-sheet-cat-title">Race Overviews</div>
        ${racesBlock}
      </div>

      <div class="member-sheet-cat">
        <div class="member-sheet-cat-title">Race notes</div>
        <div id="member-sheet-race-notes"><div class="member-sheet-empty">Loading…</div></div>
      </div>

      <div class="member-sheet-cat">
        <div class="member-sheet-cat-title">Gallery uploads</div>
        ${photoCells}
      </div>
    </div>
  `;
  document.body.appendChild(ov);
  const close = () => { ov.remove(); };
  ov.addEventListener('click', (e) => { if (e.target === ov) close(); });
  ov.querySelector('.member-sheet-close')?.addEventListener('click', close);
  ov.querySelector('#member-sheet-manage')?.addEventListener('click', () => {
    close();
    try { openCoachAthleteSheet(uid); } catch(e) {}
  });
  // Coach notes (rec #27) — private per-athlete note visible only to
  // team coaches. Lives at teams/{teamId}/coachNotes/{uid}; Firestore
  // rules gate read + write to the team's coaches.
  (async () => {
    const ta = ov.querySelector('#member-coach-note');
    const saveBtn = ov.querySelector('#member-coach-note-save');
    const status = ov.querySelector('#member-coach-note-status');
    if (!ta || !saveBtn || !db || !teamData?.id) return;
    // Load existing note.
    try {
      const snap = await getDoc(doc(db, 'teams', teamData.id, 'coachNotes', uid));
      if (snap.exists()) {
        ta.value = String(snap.data().note || '');
      }
    } catch (e) {
      console.warn('coach note load:', e);
    }
    saveBtn.addEventListener('click', async () => {
      const note = (ta.value || '').trim().slice(0, 2000);
      saveBtn.disabled = true;
      const orig = saveBtn.textContent;
      saveBtn.textContent = 'Saving…';
      try {
        await setDoc(doc(db, 'teams', teamData.id, 'coachNotes', uid), {
          note,
          updatedAt: serverTimestamp(),
          updatedBy: currentUser?.uid || null,
          updatedByName: userProfile?.displayName || currentUser?.displayName || '',
        });
        if (status) {
          status.textContent = 'Saved.';
          setTimeout(() => { if (status) status.textContent = ''; }, 2000);
        }
      } catch (err) {
        showToast?.('Could not save: ' + (err?.message || err), 'error');
      } finally {
        saveBtn.disabled = false;
        saveBtn.textContent = orig;
      }
    });
  })();
  document.addEventListener('keydown', function esc(e) {
    if (e.key === 'Escape') { close(); document.removeEventListener('keydown', esc); }
  });
  // Async-fill the race-notes block — these are per-rider notes left
  // by the coach during a race-report upload.
  (async () => {
    const rnEl = ov.querySelector('#member-sheet-race-notes');
    if (!rnEl || !db) return;
    try {
      const snap = await getDocs(query(
        collection(db, 'users', uid, 'race_notes'),
        orderBy('createdAt', 'desc'),
        limit(8)
      ));
      if (snap.empty) {
        rnEl.innerHTML = '<div class="member-sheet-empty">No coach race notes yet.</div>';
        return;
      }
      rnEl.innerHTML = snap.docs.map(d => {
        const n = d.data();
        const yearLabel = n.raceYear ? ` · ${n.raceYear}` : '';
        const lapsLabel = (typeof n.laps === 'number' && n.laps > 0) ? ` · ${n.laps} laps` : '';
        const conditions = n.conditions ? `<div style="font-size:11px;color:var(--muted-fg);margin-top:2px">${escHtml(n.conditions)}${n.delays ? ' · ' + escHtml(n.delays) : ''}</div>` : '';
        return `<div class="member-sheet-stat" style="grid-column:1 / -1;padding:10px 12px;background:rgba(var(--primary-rgb),.04);border:1px solid rgba(var(--primary-rgb),.14);border-radius:10px;margin-bottom:8px">
          <div style="display:flex;justify-content:space-between;align-items:baseline;gap:8px"><div class="member-sheet-stat-lbl">${escHtml(n.raceName || 'Race')}${yearLabel}${lapsLabel}</div></div>
          <div style="font-size:13px;color:var(--fg);margin-top:6px;line-height:1.45">${escHtml(n.notes || '—')}</div>
          ${conditions}
        </div>`;
      }).join('');
    } catch (e) {
      rnEl.innerHTML = '<div class="member-sheet-empty">Couldn\'t load race notes.</div>';
    }
  })();
}

/// Open a sheet showing a single athlete's detail — what plan they're on,
/// recent workouts, streak, RPE trend. Quick actions: assign plan, send
/// chat message, view their goals. Coach-only.
async function openCoachAthleteSheet(uid) {
  const member = teamMembers.find(m => m.uid === uid);
  if (!member) { showToast('Athlete not found.', 'warn'); return; }
  openSheet();
  $('sheet-content').innerHTML = `
    <div class="sheet-title">${escHtml(member.displayName || 'Athlete')}</div>
    <div style="font-size:12px;color:var(--muted-fg);margin-bottom:14px">${escHtml(member.email || member.yearLevel || '')}</div>
    <div id="coach-athlete-loading" style="text-align:center;padding:30px;color:var(--muted-fg)">Loading…</div>
  `;
  // Load workouts + plan progress in parallel
  let recentWorkouts = [];
  let planSummary = null;
  let compliance = null;  // { done, scheduled, pct, weekLabel }
  try {
    const promises = [
      getDocs(query(collection(db, 'users', uid, 'workouts'), orderBy('date', 'desc'), limit(20))).catch(() => null),
    ];
    if (member.activePlanId) {
      const plan = findPlan(member.activePlanId);
      if (plan) {
        planSummary = { name: plan.name, category: plan.category, weeks: plan.workouts ? Math.max(...plan.workouts.map(w => w.week || 0)) : 0 };
        // Pull last 7 days of checklist docs to compute weekly compliance.
        const days = [];
        for (let i = 0; i < 7; i++) {
          const d = new Date(); d.setDate(d.getDate() - i);
          days.push(d.toISOString().split('T')[0]);
        }
        promises.push(Promise.all(days.map(dk => getDoc(doc(db, 'users', uid, 'checklist', dk)).catch(() => null))));
      }
    }
    const results = await Promise.all(promises);
    const wSnap = results[0];
    if (wSnap) {
      recentWorkouts = wSnap.docs.map(d => ({ id: d.id, ...d.data() }));
    }
    const checklists = results[1];
    if (planSummary && checklists) {
      // Count scheduled vs done for the last 7 days. Each checklist doc is
      // a per-day map of "key → bool". The keys encode plan week/day/index;
      // we just sum the bools as "done count" and infer scheduled count
      // from the plan's last 7 days.
      let done = 0, scheduled = 0;
      checklists.forEach(snap => {
        if (snap?.exists?.()) {
          const items = snap.data().items || {};
          Object.values(items).forEach(v => {
            scheduled++;
            if (v === true) done++;
          });
        }
      });
      compliance = scheduled > 0 ? { done, scheduled, pct: Math.round((done / scheduled) * 100) } : null;
    }
  } catch(e) {}
  // Compute RPE trend from recents
  const rpes = recentWorkouts.map(w => w.rpe).filter(r => typeof r === 'number' && r > 0);
  const avgRpe = rpes.length ? (rpes.reduce((s, r) => s + r, 0) / rpes.length).toFixed(1) : null;
  const hardCount = rpes.filter(r => r >= 8).length;
  const lastWorkout = recentWorkouts[0];
  const lastDateStr = lastWorkout?.date
    ? (lastWorkout.date.toDate ? lastWorkout.date.toDate() : new Date(lastWorkout.date)).toLocaleDateString('en-AU', { day:'numeric', month:'short' })
    : '—';
  // Compose body
  let html = '';
  // Stats row
  html += `<div style="display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:6px;margin-bottom:12px">
    <div class="card" style="padding:10px;text-align:center"><div style="font-size:20px;font-weight:800;color:var(--primary)">${member.totalWorkouts || 0}</div><div style="font-size:9px;color:var(--muted-fg);text-transform:uppercase;letter-spacing:.04em;margin-top:2px">Workouts</div></div>
    <div class="card" style="padding:10px;text-align:center"><div style="font-size:20px;font-weight:800;color:var(--success)">${member.streak || 0}d</div><div style="font-size:9px;color:var(--muted-fg);text-transform:uppercase;letter-spacing:.04em;margin-top:2px">Streak</div></div>
    <div class="card" style="padding:10px;text-align:center"><div style="font-size:20px;font-weight:800;color:${hardCount >= 4 ? 'var(--warning)' : 'var(--fg)'}">${avgRpe || '—'}</div><div style="font-size:9px;color:var(--muted-fg);text-transform:uppercase;letter-spacing:.04em;margin-top:2px">Avg RPE</div></div>
  </div>`;
  // Plan summary
  if (planSummary) {
    const compHtml = compliance
      ? `<div style="margin-top:10px">
          <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:4px">
            <span style="font-size:10px;color:var(--muted-fg);text-transform:uppercase;letter-spacing:.05em">7-Day Compliance</span>
            <span style="font-size:11px;font-weight:700;color:${compliance.pct >= 80 ? 'var(--success)' : compliance.pct >= 50 ? 'var(--warning)' : 'var(--destructive)'}">${compliance.done}/${compliance.scheduled} · ${compliance.pct}%</span>
          </div>
          <div style="height:6px;background:var(--muted);border-radius:99px;overflow:hidden">
            <div style="height:100%;width:${Math.min(100, compliance.pct)}%;background:${compliance.pct >= 80 ? 'var(--success)' : compliance.pct >= 50 ? 'var(--warning)' : 'var(--destructive)'};transition:width .3s"></div>
          </div>
        </div>`
      : '<div style="margin-top:8px;font-size:11px;color:var(--muted-fg)">No checklist data yet — compliance fills in after they tick a session.</div>';
    html += `<div class="card" style="padding:12px;margin-bottom:12px">
      <div style="font-size:10px;color:var(--muted-fg);text-transform:uppercase;letter-spacing:.05em;margin-bottom:4px">Active Plan</div>
      <div style="font-size:14px;font-weight:700;color:var(--fg)">${escHtml(planSummary.name)}</div>
      <div style="font-size:11px;color:var(--muted-fg);margin-top:2px">${escHtml(planSummary.category || '')}${planSummary.weeks ? ' · ' + planSummary.weeks + ' weeks' : ''}</div>
      ${compHtml}
    </div>`;
  } else {
    html += `<div class="card" style="padding:12px;margin-bottom:12px;border:1px dashed var(--border);text-align:center">
      <div style="font-size:12px;color:var(--muted-fg)">No active plan</div>
    </div>`;
  }
  // Recent workouts
  html += `<div style="font-size:10px;color:var(--muted-fg);text-transform:uppercase;letter-spacing:.05em;margin:12px 0 6px">Recent Workouts</div>`;
  if (recentWorkouts.length === 0) {
    html += '<div style="font-size:13px;color:var(--muted-fg);padding:10px 0;text-align:center">None logged yet.</div>';
  } else {
    html += '<div style="display:flex;flex-direction:column;gap:4px;max-height:200px;overflow-y:auto;margin-bottom:14px">';
    recentWorkouts.forEach(w => {
      const dt = w.date?.toDate ? w.date.toDate() : (w.date ? new Date(w.date) : null);
      const dStr = dt ? dt.toLocaleDateString('en-AU', { day:'numeric', month:'short' }) : '?';
      const rpe = (typeof w.rpe === 'number') ? w.rpe : null;
      const rpeColor = rpe == null ? 'var(--muted-fg)' : rpe >= 8 ? '#f59e0b' : rpe >= 5 ? '#22c55e' :'var(--muted-fg)';
      html += `<div style="display:flex;align-items:center;gap:8px;padding:6px 8px;background:var(--card);border-radius:8px;font-size:12px">
        <span style="flex:1;min-width:0;color:var(--fg);font-weight:600;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${escHtml(w.name || 'Workout')}</span>
        <span style="color:var(--muted-fg);white-space:nowrap">${w.duration || '?'}m</span>
        <span style="color:${rpeColor};font-weight:700;white-space:nowrap;width:38px;text-align:right">${rpe == null ? '' : 'RPE ' + rpe}</span>
        <span style="color:var(--muted-fg);white-space:nowrap;font-size:11px">${dStr}</span>
      </div>`;
    });
    html += '</div>';
  }
  // Quick actions
  html += `<div style="display:flex;flex-direction:column;gap:8px">
    <button id="coach-athlete-msg" class="btn btn-primary" style="width:100%">Send chat message</button>
    <button id="coach-athlete-assign" class="btn btn-secondary" style="width:100%">Assign a plan</button>
    <button id="coach-athlete-close" class="btn btn-secondary" style="width:100%">Close</button>
  </div>`;
  $('sheet-content').innerHTML = `
    <div class="sheet-title">${escHtml(member.displayName || 'Athlete')}</div>
    <div style="font-size:12px;color:var(--muted-fg);margin-bottom:14px">${member.yearLevel ? 'Y' + String(member.yearLevel).replace('Y','') : ''}${member.fitnessLevel ? ' · ' + capitalize(member.fitnessLevel) : ''} · last logged ${lastDateStr}</div>
    ${html}
  `;
  $('coach-athlete-close')?.addEventListener('click', closeSheet);
  $('coach-athlete-msg')?.addEventListener('click', () => {
    closeSheet();
    // Switch to Chat sub-tab + prefill mention. Was setting
    // window._teamSubTab, which renderTeam never read — clicking
    // "Message" silently stayed on the Members tab.
    lbSubTab = 'chat';
    renderTeam();
    setTimeout(() => {
      const ta = document.getElementById('team-chat-input');
      if (ta) {
        ta.value = '@' + (member.displayName || 'athlete') + ' ';
        ta.focus();
      }
    }, 100);
  });
  $('coach-athlete-assign')?.addEventListener('click', () => {
    // Firestore rules gate activePlanId writes to the team's createdBy
    // user only; co-coaches who aren't the creator would tap Assign,
    // pick a plan, then see a generic permission-denied toast. Surface
    // this up-front instead.
    const isHeadCoach = userProfile?.isCoach && teamData?.createdBy === currentUser?.uid;
    if (!isHeadCoach) {
      showToast('Only the head coach can assign plans. Ask them to do it from their account.', 'warn');
      return;
    }
    openPlanPickerForAthlete(uid, member);
  });
}

/// Plan picker — shows visible plans grouped by category. Tapping one
/// writes activePlanId onto the athlete's user doc (allowed by Firestore
/// rule for the team's head coach). Sheet stays open until they confirm.
function openPlanPickerForAthlete(uid, member) {
  const visible = (typeof getVisiblePlans === 'function') ? getVisiblePlans() : (ALL_PLANS || []);
  const yearMatch = visible.filter(p => p.yearLevel === member.yearLevel);
  const tierMatch = visible.filter(p => p.tier === member.fitnessLevel);
  const recommended = (yearMatch.length && tierMatch.length)
    ? yearMatch.filter(p => p.tier === member.fitnessLevel)
    : (yearMatch.length ? yearMatch : tierMatch).slice(0, 6);
  const others = visible.filter(p => !recommended.includes(p)).slice(0, 30);
  const renderCard = (p, recommended = false) => `<button class="coach-plan-pick" data-plan-id="${escHtml(p.id)}" style="display:block;width:100%;text-align:left;padding:10px 12px;margin-bottom:6px;background:${recommended ? 'rgba(var(--primary-rgb),.06)' : 'var(--card)'};border:1px solid ${recommended ? 'rgba(var(--primary-rgb),.30)' : 'var(--border)'};border-radius:10px;cursor:pointer">
    <div style="font-size:13px;font-weight:700;color:var(--fg)">${escHtml(p.name || 'Plan')}${member.activePlanId === p.id ? ' <span style="font-size:9px;color:var(--success);font-weight:800;letter-spacing:.05em">CURRENT</span>' : ''}</div>
    <div style="font-size:11px;color:var(--muted-fg);margin-top:2px">${escHtml(p.category || '')}${p.yearLevel ? ' · ' + escHtml(p.yearLevel) : ''}${p.tier ? ' · ' + escHtml(p.tier) : ''}</div>
  </button>`;
  $('sheet-content').innerHTML = `
    <div class="sheet-title">Assign Plan</div>
    <div style="font-size:12px;color:var(--muted-fg);margin-bottom:12px">For ${escHtml(member.displayName || 'athlete')}. Their active plan switches immediately.</div>
    ${recommended.length ? '<div style="font-size:10px;color:var(--muted-fg);text-transform:uppercase;letter-spacing:.05em;margin-bottom:6px">Recommended</div>' + recommended.map(p => renderCard(p, true)).join('') : ''}
    ${others.length ? '<div style="font-size:10px;color:var(--muted-fg);text-transform:uppercase;letter-spacing:.05em;margin:14px 0 6px">All Plans</div><div style="max-height:340px;overflow-y:auto">' + others.map(p => renderCard(p, false)).join('') + '</div>' : ''}
    <div style="display:flex;gap:8px;margin-top:14px">
      ${member.activePlanId ? '<button class="btn" id="coach-plan-clear" style="flex:1;color:var(--destructive);border:1px solid rgba(var(--destructive-rgb),.3);background:rgba(var(--destructive-rgb),.08)">Cancel current plan</button>' : ''}
      <button class="btn btn-secondary" style="flex:1" id="coach-plan-back">Back</button>
    </div>
  `;
  document.querySelectorAll('.coach-plan-pick').forEach(btn => {
    btn.addEventListener('click', async () => {
      const planId = btn.dataset.planId;
      const plan = findPlan(planId);
      if (!plan) return;
      btn.disabled = true; btn.style.opacity = '0.6';
      try {
        await updateDoc(doc(db, 'users', uid), { activePlanId: planId });
        const target = teamMembers.find(m => m.uid === uid);
        if (target) target.activePlanId = planId;
        showToast('Assigned "' + (plan.name || 'plan') + '" to ' + (member.displayName || 'athlete'), 'success');
        closeSheet();
        renderTeam();
      } catch(e) {
        showToast('Failed: ' + (e?.message || 'try again'), 'error');
        btn.disabled = false; btn.style.opacity = '';
      }
    });
  });
  $('coach-plan-clear')?.addEventListener('click', async () => {
    if (!confirm('Cancel ' + (member.displayName || 'this athlete') + '’s plan?')) return;
    try {
      await updateDoc(doc(db, 'users', uid), { activePlanId: null });
      const target = teamMembers.find(m => m.uid === uid);
      if (target) target.activePlanId = null;
      showToast('Plan cancelled.', 'info');
      closeSheet();
      renderTeam();
    } catch(e) { showToast('Failed: ' + (e?.message || 'try again'), 'error'); }
  });
  $('coach-plan-back')?.addEventListener('click', () => openCoachAthleteSheet(uid));
}

/// Wire the chat composer + per-message delete buttons after the chat panel
/// renders. Safe to call multiple times (re-bind on every render).
function bindTeamChatPanel(c) {
  // Diagnostic "Add my UID to team members[] now" button — explicit,
  // verbose self-heal that surfaces every step's outcome inline. We've
  // been chasing this for a week through silent failures; this exposes
  // the actual rule rejection if any.
  c.querySelector('#chat-diag-fix')?.addEventListener('click', async () => {
    const out = c.querySelector('#chat-diag-result');
    const log = (s) => { if (out) out.textContent += s + '\n'; console.log('[chat-diag]', s); };
    if (out) out.textContent = '';
    if (!db || !currentUser?.uid || !userProfile?.teamId) {
      log('Aborted: missing db / user / teamId.');
      return;
    }
    try {
      log('1. Reading team doc ' + userProfile.teamId + '…');
      const tref = doc(db, 'teams', userProfile.teamId);
      const tsnap = await getDoc(tref);
      if (!tsnap.exists()) { log('   ❌ Team doc does not exist. Profile.teamId is stale.'); return; }
      const td = tsnap.data();
      const members = Array.isArray(td.members) ? td.members : [];
      log('   ✓ Team exists: ' + (td.name || '(unnamed)'));
      log('   createdBy: ' + (td.createdBy || '(none)'));
      log('   members[' + members.length + ']: ' + JSON.stringify(members));
      log('   you (uid): ' + currentUser.uid);
      log('   you in members: ' + members.includes(currentUser.uid));
      if (members.includes(currentUser.uid)) {
        log('Already in members[]. The chat block must be a different cause — try sending a message now.');
      } else {
        log('2. Calling updateDoc to add your uid via arrayUnion…');
        try {
          await updateDoc(tref, { members: arrayUnion(currentUser.uid) });
          log('   ✓ Wrote successfully. Re-reading…');
          const reSnap = await getDoc(tref);
          const newMembers = reSnap.data()?.members || [];
          log('   members now: ' + JSON.stringify(newMembers));
          log('   you in members: ' + newMembers.includes(currentUser.uid));
        } catch(updErr) {
          log('   ❌ Write rejected: code=' + updErr?.code + ' msg=' + updErr?.message);
          log('   This is the rule rejection. Send me this whole text.');
          return;
        }
      }
      log('3. Bust local team cache + reload…');
      try {
        localStorage.removeItem('tp_team_' + userProfile.teamId);
        localStorage.removeItem('tp_team_ts_' + userProfile.teamId);
      } catch(_) {}
      try { await loadTeamData(true); } catch(e) { log('   loadTeamData warn: ' + e?.message); }
      log('4. Reattaching chat listener…');
      _bgChatLive = false;
      _bgChatRetryCount = 0;
      try { unsubscribeTeamChat?.(); } catch(_) {}
      try { attachBackgroundChat(); } catch(e) { log('   attach warn: ' + e?.message); }
      log('Done. Try sending a message now.');
    } catch(err) {
      log('Outer error: code=' + err?.code + ' msg=' + err?.message);
    }
  });
  // Photo attachment — opens iOS photo picker, uploads to Storage,
  // writes a chat message with imageUrl. Works server-side via the
  // onChatWrite Function for push delivery.
  const attachBtn = c.querySelector('#team-chat-attach');
  const photoInput = c.querySelector('#team-chat-photo-input');
  attachBtn?.addEventListener('click', () => photoInput?.click());
  photoInput?.addEventListener('change', async (e) => {
    const file = e.target?.files?.[0];
    if (!file) return;
    photoInput.value = ''; // reset so picking same file twice still fires change
    if (!storageRef || !uploadBytes || !getDownloadURL) {
      showErr('Photo upload not available on this build.');
      return;
    }
    if (!userProfile?.teamId || !currentUser?.uid) {
      showErr('No team yet — join one before sending photos.');
      return;
    }
    const teamId = userProfile.teamId;
    if (file.size > 8 * 1024 * 1024) {
      showErr('Photo too big (max 8 MB).');
      return;
    }
    const clientId = 'pending-img-' + Date.now() + '-' + Math.random().toString(36).slice(2, 8);
    // Optimistic preview — show the local file immediately as a pending image bubble.
    const previewUrl = URL.createObjectURL(file);
    const pendingMsg = {
      _clientId: clientId,
      id: clientId,
      uid: currentUser.uid,
      displayName: ((userProfile?.displayName || currentUser.displayName || currentUser.email || 'Member').toString().trim()) || 'Member',
      text: '',
      kind: 'chat',
      subteamId: getMySubteamId() || (userProfile?.isCoach ? getChatScope() : ''),
      imageUrl: previewUrl,
      createdAt: new Date(),
    };
    try { addPendingChatMessage?.(pendingMsg); } catch(_) {}
    try { refreshTeamChatList(); scrollChatToBottom(); } catch(_) {}
    try {
      const path = `teams/${teamId}/chat/${currentUser.uid}_${Date.now()}.jpg`;
      const ref = storageRef(getStorage(), path);
      await uploadBytes(ref, file, { contentType: file.type || 'image/jpeg' });
      const downloadUrl = await getDownloadURL(ref);
      // Dual-write: chat message (ephemeral, auto-cleared at 24h) and a
      // gallery doc that lives forever. So photos shared in chat
      // permanently appear in the team gallery even after the chat
      // bubble clears.
      const chatWritePromise = addDoc(collection(db, 'teams', teamId, 'chat'), {
        uid: currentUser.uid,
        displayName: pendingMsg.displayName,
        text: '',
        kind: 'chat',
        subteamId: pendingMsg.subteamId,
        imageUrl: downloadUrl,
        imagePath: path,
        fromChat: true,
        createdAt: serverTimestamp(),
      });
      const galleryWritePromise = addDoc(collection(db, 'teams', teamId, 'gallery'), {
        uploadedBy: currentUser.uid,
        uploadedByName: pendingMsg.displayName,
        dataUrl: downloadUrl, // gallery renders from this; works for both Storage URLs and legacy base64
        storagePath: path,
        subteamId: pendingMsg.subteamId || '',
        ts: Date.now(),
        source: 'chat',
        caption: '',
      }).catch(err => {
        // Gallery write is best-effort — chat message is the primary path.
        console.warn('[chat] gallery dual-write failed:', err?.code, err?.message);
      });
      await Promise.all([chatWritePromise, galleryWritePromise]);
      try { removePendingChatMessage?.(clientId); } catch(_) {}
      try { refreshTeamChatList(); } catch(_) {}
    } catch (err) {
      console.error('[chat] photo upload failed:', err);
      try { markPendingChatFailed?.(clientId, err?.code || 'upload-failed'); } catch(_) {}
      try { refreshTeamChatList(); } catch(_) {}
      showErr('Photo upload failed: ' + (err?.message || 'unknown'));
    } finally {
      try { URL.revokeObjectURL(previewUrl); } catch(_) {}
    }
  });
  // Manual retry button on the status pill — resets retry counter and
  // forces a fresh listener attach, attempting membership self-heal in
  // between. Useful when the auto-retry has backed off too far.
  c.querySelector('#chat-status-retry')?.addEventListener('click', async () => {
    try {
      _bgChatRetryCount = 0;
      _bgChatLive = false;
      try { unsubscribeTeamChat?.(); } catch(_) {}
      const pill = c.querySelector('#chat-status-pill');
      if (pill) {
        const lbl = pill.querySelector('.chat-status-label');
        if (lbl) lbl.textContent = 'Connecting…';
      }
      try { await ensureDefaultTeamMembership?.(); } catch(_) {}
      // Drop the team cache so the next read pulls fresh members[].
      try {
        if (userProfile?.teamId) {
          localStorage.removeItem('tp_team_' + userProfile.teamId);
          localStorage.removeItem('tp_team_ts_' + userProfile.teamId);
        }
      } catch(_) {}
      try { await loadTeamData?.(); } catch(_) {}
      attachBackgroundChat();
    } catch(e) {
      console.warn('chat retry:', e);
    }
  });
  // Don't capture teamId at bind time — auto-join can populate it after
  // the chat panel renders and we'd be stuck with a null closure that
  // makes the Send button silently no-op forever.
  // Auto-grow textarea
  const ta = c.querySelector('#team-chat-input');
  if (ta) {
    const grow = () => { ta.style.height = 'auto'; ta.style.height = Math.min(120, ta.scrollHeight) + 'px'; };
    ta.addEventListener('input', grow);
    setTimeout(grow, 0);
  }
  // @mention autocomplete (rec #23) — typing "@" surfaces a dropdown of
  // team members; tapping one inserts "@DisplayName ". Rendered messages
  // highlight known-member mentions (see teamchat.js highlightMentions).
  if (ta) {
    const composer = c.querySelector('.msg-composer');
    let mentionBox = null;
    const closeMentions = () => { if (mentionBox) { mentionBox.remove(); mentionBox = null; } };
    // { token, start } if the cursor sits in an active @mention, else null.
    const activeMention = () => {
      const pos = ta.selectionStart;
      const before = ta.value.slice(0, pos);
      const at = before.lastIndexOf('@');
      if (at === -1) return null;
      if (at > 0 && !/\s/.test(before[at - 1])) return null; // must follow whitespace / line-start
      const token = before.slice(at + 1);
      if (/\n/.test(token) || token.length > 24) return null;
      return { token, start: at };
    };
    const renderMentions = () => {
      const m = activeMention();
      if (!m || !composer) { closeMentions(); return; }
      const members = Array.isArray(teamMembers) ? teamMembers : [];
      const q = m.token.toLowerCase();
      const matches = members
        .filter(mem => mem.uid && mem.uid !== currentUser?.uid)
        .filter(mem => (mem.displayName || '').toLowerCase().includes(q))
        .slice(0, 6);
      if (!matches.length) { closeMentions(); return; }
      if (!mentionBox) {
        mentionBox = document.createElement('div');
        mentionBox.className = 'chat-mention-list';
        composer.insertBefore(mentionBox, composer.firstChild);
      }
      mentionBox.innerHTML = matches.map(mem =>
        `<button type="button" class="chat-mention-item" data-mention-name="${escHtml(mem.displayName || '')}">
           <span class="chat-mention-avatar">${escHtml((mem.displayName || '?').trim().charAt(0).toUpperCase())}</span>
           <span class="chat-mention-name">${escHtml(mem.displayName || 'Member')}</span>
         </button>`).join('');
      mentionBox.querySelectorAll('.chat-mention-item').forEach(btn => {
        // mousedown (not click) so it fires before the textarea blur.
        btn.addEventListener('mousedown', (ev) => {
          ev.preventDefault();
          const name = btn.dataset.mentionName || '';
          const cur = activeMention();
          if (!cur) { closeMentions(); return; }
          const pos = ta.selectionStart;
          const after = ta.value.slice(pos);
          ta.value = ta.value.slice(0, cur.start) + '@' + name + ' ' + after;
          const newPos = cur.start + name.length + 2;
          closeMentions();
          ta.focus();
          ta.setSelectionRange(newPos, newPos);
          ta.dispatchEvent(new Event('input'));
        });
      });
    };
    ta.addEventListener('input', renderMentions);
    ta.addEventListener('keyup', (e) => { if (e.key === 'Escape') closeMentions(); });
    ta.addEventListener('blur', () => setTimeout(closeMentions, 160));
  }
  // Multi-subteam broadcast targets (rec #17) — the targets row only
  // appears when Push is ticked; chips multi-select. The send handler
  // reads the active chips and fans the broadcast out to each.
  const pushBox = c.querySelector('#team-chat-push');
  const targetsRow = c.querySelector('#chat-broadcast-targets');
  if (pushBox && targetsRow) {
    pushBox.addEventListener('change', () => {
      targetsRow.hidden = !pushBox.checked;
      // First reveal — pre-select the coach's current viewing scope.
      if (pushBox.checked && !targetsRow.querySelector('.chat-bt-chip.active')) {
        const cur = getChatScope() || '';
        const match = targetsRow.querySelector('.chat-bt-chip[data-bt-scope="' + cur + '"]');
        if (match) match.classList.add('active');
      }
    });
    targetsRow.querySelectorAll('.chat-bt-chip').forEach(chip => {
      chip.addEventListener('click', () => chip.classList.toggle('active'));
    });
  }
  // Schedule-a-message (rec #25) — opens the scheduled-messages sheet,
  // pre-filled with whatever is in the composer.
  c.querySelector('#team-chat-schedule')?.addEventListener('click', () => {
    const draft = (c.querySelector('#team-chat-input')?.value || '').trim();
    openScheduledMessagesSheet(draft);
  });
  const sendBtn = c.querySelector('#team-chat-send');
  const errBox = c.querySelector('#team-chat-error');
  const showErr = (msg) => {
    if (!errBox) return;
    errBox.textContent = msg;
    errBox.hidden = false;
  };
  const clearErr = () => {
    if (!errBox) return;
    errBox.textContent = '';
    errBox.hidden = true;
  };
  // Pre-flight — only block on conditions Firestore can't recover from.
  // Don't gate on a stale local teamData.members cache: if our copy is
  // out of date, we'd block a send the server would accept. The server
  // path (sendChatMessage → permission-denied → ensureDefaultTeamMembership
  // → retry) handles real membership drift.
  const preflight = () => {
    if (!currentUser) return 'Not signed in.';
    if (!userProfile?.teamId) return 'No team yet — join or create one before chatting.';
    return null;
  };
  ta?.addEventListener('input', clearErr);
  sendBtn?.addEventListener('click', async () => {
    // CRITICAL: re-query the textarea + button on every click. The bind-
    // time refs (ta, sendBtn closure vars) become detached when
    // renderTeamChatPanelInto re-renders the panel for snapshot updates
    // or scope changes. Reading via c.querySelector ensures we're always
    // talking to the current live DOM nodes.
    const taLive = c.querySelector('#team-chat-input');
    const btnLive = c.querySelector('#team-chat-send');
    const teamId = userProfile?.teamId;
    const text = (taLive?.value || '').trim();
    if (!text) { showErr('Type a message first.'); return; }
    clearErr();
    const pre = preflight();
    if (pre) { showErr(pre); console.warn('[chat] preflight blocked:', pre); return; }
    if (!teamId) {
      showErr('No team yet — give the auto-join a moment then try again.');
      return;
    }
    const isCoachUser = !!userProfile?.isCoach;
    const isAdminUser = !!isAdmin;
    // Subteam captain (rec #19) — limited coach powers for their subteam.
    const captainSub = isCoachUser ? '' : getMyCaptainSubteamId();
    const isCaptain = !!captainSub;
    const canBroadcast = isCoachUser || isCaptain;
    // Coaches and admins skip the school-context profanity filter — the
    // underlying send funcs also bypass it for them.
    if (!isCoachUser && !isAdminUser && !isMessageClean(text)) {
      showErr('Message blocked — keep it clean.');
      return;
    }
    if (btnLive?.dataset.sending === '1') return; // prevent double-send
    if (btnLive) {
      btnLive.dataset.sending = '1';
      btnLive.disabled = true;
      btnLive.style.opacity = '0.55';
    }
    const pushChecked = !!c.querySelector('#team-chat-push')?.checked;
    // Multi-subteam broadcast (rec #17): when Push is ticked and the
    // coach has selected target chips, fan the broadcast out to every
    // selected scope. '' = whole-team channel.
    let broadcastScopes = null;
    if (pushChecked && isCoachUser) {
      const tr = c.querySelector('#chat-broadcast-targets');
      if (tr && !tr.hidden) {
        const chips = [...tr.querySelectorAll('.chat-bt-chip.active')];
        if (chips.length) broadcastScopes = chips.map(ch => ch.dataset.btScope || '');
      }
    }
    let ok = false;
    // Resolve target scope. Coaches send into whichever scope the chips
    // select. Captains are pinned to the subteam they captain. Athletes
    // are pinned to their own subteam (or whole-team if they have none).
    const targetScope = isCoachUser
      ? getChatScope()
      : (captainSub || getMySubteamId() || '');
    const targetLabel = (() => {
      if (!targetScope) return 'whole team';
      const sub = (teamData?.subteams || []).find(s => s.id === targetScope);
      return sub ? (sub.name || 'subteam') : 'subteam';
    })();
    // Optimistic insert — the typed message appears in the list right
    // now, before Firestore even gets the write. The snapshot listener
    // dedupes when the real version lands. If the write fails, we mark
    // the pending bubble as failed (with retry affordance).
    const clientId = 'pending-' + Date.now() + '-' + Math.random().toString(36).slice(2, 8);
    const pendingKind = (canBroadcast && pushChecked) ? 'coach' : 'chat';
    const pendingMsg = {
      _clientId: clientId,
      id: clientId,
      uid: currentUser?.uid || '',
      displayName: (userProfile?.displayName || currentUser?.displayName || currentUser?.email || (isCoachUser ? 'Coach' : 'Member')).toString().trim() || (isCoachUser ? 'Coach' : 'Member'),
      text: text,
      kind: pendingKind,
      subteamId: targetScope,
      broadcastPush: pendingKind === 'coach' ? !!pushChecked : false,
      createdAt: new Date(),
    };
    // Optimistic insert — surface failures instead of swallowing.
    let optimisticOk = false;
    try {
      addPendingChatMessage?.(pendingMsg);
      optimisticOk = true;
    } catch(e) {
      console.error('[chat] optimistic insert threw:', e);
    }
    // Clear the input + repaint. Use the fresh textarea ref so we
    // don't write to a detached DOM node from a stale closure.
    const taClear = c.querySelector('#team-chat-input');
    if (taClear) {
      taClear.value = '';
      taClear.style.height = 'auto';
      clearErr();
    }
    if (optimisticOk) {
      try { refreshTeamChatList(); } catch(e) { console.warn('[chat] refresh after optimistic insert:', e); }
      try { scrollChatToBottom(); } catch(e) { console.warn('[chat] scroll after optimistic insert:', e); }
    } else {
      showErr('Could not queue message locally — sending anyway, watch the result.');
    }
    // Direct-write fallback. teamchat.js's exported sendChatMessage
    // depends on its module-internal ctx being populated by initTeamChat.
    // If that context is empty (init race or import failure), the call
    // returns false silently. We do the addDoc ourselves from app.js
    // scope using the real Firebase functions imported here — same
    // payload shape, same Firestore rules.
    const directSend = async () => {
      const safeName = ((userProfile?.displayName || currentUser?.displayName || currentUser?.email || (canBroadcast ? 'Coach' : 'Member')).toString().trim()) || (canBroadcast ? 'Coach' : 'Member');
      const payload = {
        uid: currentUser.uid,
        displayName: safeName,
        text: text,
        kind: (canBroadcast && pushChecked) ? 'coach' : 'chat',
        subteamId: String(targetScope || ''),
        createdAt: serverTimestamp(),
      };
      if (canBroadcast && pushChecked) payload.broadcastPush = true;
      await addDoc(collection(db, 'teams', teamId, 'chat'), payload);
      return true;
    };
    // Inner sender — wraps the actual write so we can retry once after
    // self-healing membership if Firestore says permission-denied.
    const doSend = async () => {
      let result;
      try {
        if (canBroadcast && pushChecked) {
          result = await sendCoachBroadcast(teamId, text, { push: true, subteamId: targetScope });
        } else {
          result = await sendChatMessage(teamId, text, { subteamId: targetScope });
        }
      } catch (e) {
        throw e; // rethrow so outer catch handles permission-denied retry
      }
      // If the wrapped function returned false (module ctx missing or
      // some other silent abort), fall back to a direct write so the
      // user's message actually goes through.
      if (result === false) {
        console.warn('[chat] sendChat returned false — falling back to direct addDoc');
        return await directSend();
      }
      return result;
    };
    try {
      if (isCoachUser && pushChecked && broadcastScopes && broadcastScopes.length) {
        // Multi-target broadcast — one message per selected scope.
        const names = broadcastScopes.map(s => {
          if (!s) return 'Whole team';
          const sub = (teamData?.subteams || []).find(x => x.id === s);
          return sub ? (sub.name || 'Subteam') : 'Subteam';
        });
        if (!confirm(`Broadcast this push to ${names.join(', ')}?`)) {
          ok = false;
        } else {
          let sent = 0;
          for (const scope of broadcastScopes) {
            try {
              const r = await sendCoachBroadcast(teamId, text, { push: true, subteamId: scope });
              if (r !== false) sent++;
            } catch (e) { console.warn('[chat] broadcast to scope failed:', scope, e); }
          }
          ok = sent > 0;
          if (ok) showToast?.('Broadcast sent to ' + sent + ' channel' + (sent === 1 ? '' : 's') + '.', 'success');
          if (!ok) showErr('Broadcast failed — try again.');
        }
      } else if (canBroadcast && pushChecked) {
        if (!confirm(`Send this as a push notification to ${targetLabel}?`)) {
          ok = false;
        } else {
          ok = await doSend();
        }
      } else {
        ok = await doSend();
      }
    } catch (err) {
      // Auto-heal on permission-denied: the most common cause is the
      // user's uid having drifted out of team.members[]. Run the
      // self-heal then retry the send once before giving up.
      if (err?.code === 'permission-denied') {
        console.warn('[chat] permission-denied on send → self-heal + retry');
        try {
          await ensureDefaultTeamMembership?.();
          // Drop the local team cache so the next read sees fresh members[].
          try {
            if (userProfile?.teamId) {
              localStorage.removeItem('tp_team_' + userProfile.teamId);
              localStorage.removeItem('tp_team_ts_' + userProfile.teamId);
            }
          } catch(_) {}
          ok = await doSend();
        } catch (retryErr) {
          console.error('[chat] send retry failed:', retryErr);
          try { markPendingChatFailed?.(clientId, retryErr?.code || 'failed'); } catch(_) {}
          showErr(retryErr?.code === 'permission-denied'
            ? 'Still blocked after self-heal. Coach needs to add you to the team manually.'
            : (retryErr?.message || 'Send failed.'));
          ok = false;
        }
      } else {
        console.error('[chat] send handler threw:', err);
        try { markPendingChatFailed?.(clientId, err?.code || 'failed'); } catch(_) {}
        showErr(err?.message || 'Send failed.');
        ok = false;
      }
    } finally {
      // Re-query the button — the bind-time ref is detached if the
      // chat list re-rendered during the await. Reset whichever is live.
      const finallyBtn = c.querySelector('#team-chat-send');
      if (finallyBtn) {
        finallyBtn.dataset.sending = '';
        finallyBtn.disabled = false;
        finallyBtn.style.opacity = '';
      }
      // Drop the pending — onSnapshot will land the real version.
      // We don't refresh here on success; the listener fires its own
      // refresh, double-rendering DOM-replaces the chat list twice.
      // On failure, refresh once so the failed indicator shows.
      if (ok) {
        try { removePendingChatMessage?.(clientId); } catch(_) {}
      } else {
        try { refreshTeamChatList(); } catch(_) {}
      }
    }
    if (ok) {
      // Input was already cleared at optimistic insert. Belt-and-braces
      // re-attach the listener if it isn't currently live (rare; e.g.
      // teamId arrived late). Idempotent — subscribeTeamChat unsubs
      // any prior listener.
      if (!_bgChatLive && typeof attachBackgroundChat === 'function') {
        try { attachBackgroundChat(); } catch(_) {}
      }
    }
    // Note: no generic "Send failed" fallback here. sendChatMessage
    // surfaces its own context errors via showToast (no team / not
    // signed in), and any actual write failure lands in the catch
    // block above which already populates errBox via showErr. A
    // double "Send failed" was firing on every successful send when
    // errBox was missing from the DOM (optional-chaining false alarm).
  });
  // Send on Enter (Shift+Enter inserts a newline). Mobile keyboards that
  // submit on Enter feel right; long messages can use Shift+Enter.
  ta?.addEventListener('keydown', (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      c.querySelector('#team-chat-send')?.click();
    }
  });
  // Per-message delete (author or head coach only). Read teamId fresh
  // for the same reason as the send handler.
  c.querySelectorAll('.chat-msg-del').forEach(btn => {
    btn.addEventListener('click', async (e) => {
      e.stopPropagation();
      if (!confirm('Delete this message?')) return;
      const id = btn.dataset.delId;
      const tid = userProfile?.teamId;
      if (id && tid) await deleteChatMessage(tid, id);
    });
  });
}

async function renderTeamSearchResults(container, query) {
  const el = container.querySelector('#team-search-results');
  if (!el) return;
  el.innerHTML = '<div style="text-align:center;padding:16px"><div class="spinner"></div></div>';
  const clubs = await getApprovedClubs();
  const q = query.toLowerCase().trim();
  const filtered = q ? clubs.filter(c => (c.name || '').toLowerCase().includes(q) || (c.description || '').toLowerCase().includes(q)) : clubs;
  if (filtered.length === 0) {
    el.innerHTML = q
      ? '<div style="font-size:13px;color:var(--muted-fg);text-align:center;padding:16px">No clubs found.</div>'
      : '<div style="font-size:13px;color:var(--muted-fg);text-align:center;padding:16px">No approved clubs yet.</div>';
    return;
  }
  el.innerHTML = filtered.map(club => `
    <div class="card card-pad" style="margin-bottom:8px;display:flex;align-items:center;gap:12px">
      <div style="flex:1;min-width:0">
        <div style="font-size:14px;font-weight:700;color:var(--fg)">${escHtml(club.name || '')}</div>
        ${club.description ? `<div style="font-size:12px;color:var(--muted-fg);margin-top:2px">${escHtml(club.description)}</div>` : ''}
        <div style="font-size:11px;color:var(--muted-fg);margin-top:3px">${club.memberCount ? club.memberCount + ' members' : ''}</div>
      </div>
      <button class="btn btn-primary" style="flex-shrink:0;font-size:12px;padding:8px 14px;min-height:36px" data-club-team="${escHtml(club.teamId || '')}">Join</button>
    </div>
  `).join('');
  el.querySelectorAll('[data-club-team]').forEach(btn => {
    btn.addEventListener('click', async () => {
      const teamId = btn.dataset.clubTeam;
      if (!teamId) { showToast('This club has no team yet.', 'warn'); return; }
      if (demoMode) { showToast('Teams require an account. Exit demo mode.', 'warn'); return; }
      btn.disabled = true;
      showLoading('Joining team...');
      try {
        const teamDoc = await getDoc(doc(db, 'teams', teamId));
        if (!teamDoc.exists()) { hideLoading(); showToast('Team not found.', 'error'); return; }
        await updateDoc(doc(db, 'teams', teamId), { members: arrayUnion(currentUser.uid) });
        await updateDoc(doc(db, 'users', currentUser.uid), { teamId, teamName: teamDoc.data().name });
        userProfile.teamId = teamId;
        userProfile.teamName = teamDoc.data().name;
        await loadTeamData();
        try { attachTeamLiveListener(); } catch(e) {}
        hideLoading();
        showToast('Joined ' + teamDoc.data().name + '!', 'success');
        lbSubTab = 'team';
        renderTeam();
      } catch(e) {
        hideLoading();
        showError('Failed to join team', 'team', e, { action: 'join' });
      }
    });
  });
}

// --- Coach Feature Toggles ---
const COACH_FEATURES = [
  { id: 'ai_coach', label: 'AI Coach' },
  { id: 'leaderboard', label: 'Leaderboard' },
  { id: 'race_log', label: 'Race Log' },
  { id: 'plans', label: 'Training Plans' },
  { id: 'demos', label: 'Exercise Demos' },
  { id: 'health', label: 'Health Tab' },
  { id: 'strava', label: 'Strava Sync' },
];
function renderCoachFeatureToggles() {
  return COACH_FEATURES.map(f => {
    const enabled = teamData?.features?.[f.id] !== false;
    return `<div style="display:flex;align-items:center;justify-content:space-between">
      <span style="font-size:13px;color:var(--fg)">${f.label}</span>
      <button class="admin-toggle coach-feat-toggle ${enabled ? 'on' : ''}" data-feat="${f.id}" aria-label="Toggle ${f.label}"></button>
    </div>`;
  }).join('');
}

// Edit core team details — name, description, and the share blurb that
// goes out with Invite. Only the head coach (createdBy) can save. Code
// is shown read-only because it identifies the team across the app.
// Single entry-point for all coach team-management operations. Replaces
// the stack of 4 full-width buttons (Edit / Add Co-Coach / Manage
// Subteams / Delete) + Feature Toggles card that used to sit on the
// Team page. Each row routes to its existing sheet so we don't have
// to duplicate any logic.
function openManageTeamSheet() {
  // Wrap the entire body in try/catch so a hidden bug surfaces as a
  // toast instead of a silent crash. Was: silently doing nothing on
  // tap because errors were swallowed by the addEventListener.
  try {
  if (!teamData?.id) { showToast('No team yet.', 'warn'); return; }
  // Admin + master + co-coaches in teamData.coaches[] + head coach.
  const isMaster = isMasterAccount(currentUser?.email);
  const teamCoachesSet = Array.isArray(teamData?.coaches) ? new Set(teamData.coaches) : new Set();
  const isHead = teamData.createdBy === currentUser?.uid;
  const isCoCoach = teamCoachesSet.has(currentUser?.uid);
  if (!isHead && !isCoCoach && !isAdmin && !isMaster) {
    showToast('Only coaches can manage the team.', 'warn');
    return;
  }
  const sheetEl = $('sheet-content');
  if (!sheetEl) {
    showToast('Sheet container missing — reload the app.', 'error');
    return;
  }
  sheetEl.innerHTML = `
    <div class="sheet-title">Manage Team</div>
    <div style="display:flex;flex-direction:column;gap:8px;margin-top:6px">
      <button class="btn btn-secondary mt-row" id="mt-edit" style="width:100%;text-align:left;padding:14px 14px;display:flex;align-items:center;justify-content:space-between">
        <span><div style="font-size:14px;font-weight:700;color:var(--fg)">Edit team details</div><div style="font-size:11px;color:var(--muted-fg);margin-top:2px;font-weight:500">Name, description, invite blurb</div></span>
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="width:14px;height:14px;color:var(--muted-fg)"><polyline points="9 18 15 12 9 6"/></svg>
      </button>
      <button class="btn btn-secondary mt-row" id="mt-cocoach" style="width:100%;text-align:left;padding:14px 14px;display:flex;align-items:center;justify-content:space-between">
        <span><div style="font-size:14px;font-weight:700;color:var(--fg)">Add a co-coach</div><div style="font-size:11px;color:var(--muted-fg);margin-top:2px;font-weight:500">Promote an existing team member</div></span>
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="width:14px;height:14px;color:var(--muted-fg)"><polyline points="9 18 15 12 9 6"/></svg>
      </button>
      <button class="btn btn-secondary mt-row" id="mt-subteams" style="width:100%;text-align:left;padding:14px 14px;display:flex;align-items:center;justify-content:space-between">
        <span><div style="font-size:14px;font-weight:700;color:var(--fg)">Manage subteams</div><div style="font-size:11px;color:var(--muted-fg);margin-top:2px;font-weight:500">Create, rename, assign athletes</div></span>
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="width:14px;height:14px;color:var(--muted-fg)"><polyline points="9 18 15 12 9 6"/></svg>
      </button>
      <button class="btn btn-secondary mt-row" id="mt-features" style="width:100%;text-align:left;padding:14px 14px;display:flex;align-items:center;justify-content:space-between">
        <span><div style="font-size:14px;font-weight:700;color:var(--fg)">Feature toggles</div><div style="font-size:11px;color:var(--muted-fg);margin-top:2px;font-weight:500">Show / hide tabs for the team</div></span>
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="width:14px;height:14px;color:var(--muted-fg)"><polyline points="9 18 15 12 9 6"/></svg>
      </button>
      <button class="btn mt-row" id="mt-delete" style="width:100%;margin-top:14px;text-align:left;padding:14px 14px;color:var(--destructive);border:1px solid rgba(var(--destructive-rgb),.3);background:rgba(var(--destructive-rgb),.06);display:flex;align-items:center;justify-content:space-between">
        <span><div style="font-size:14px;font-weight:700;color:var(--destructive)">Delete team</div><div style="font-size:11px;color:rgba(var(--destructive-rgb),.7);margin-top:2px;font-weight:500">Removes every member's team association</div></span>
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="width:14px;height:14px;color:var(--destructive)"><polyline points="9 18 15 12 9 6"/></svg>
      </button>
    </div>
  `;
  openSheet();
  // Wrap each row's handler in try/catch so a downstream sheet failure
  // (e.g. openEditTeamSheet throws on a missing field) shows a toast
  // instead of looking like Manage Team did nothing.
  const safeRoute = (fn, label) => () => {
    closeSheet();
    setTimeout(() => {
      try { fn(); }
      catch (err) {
        console.error('[manage-team] ' + label + ' threw:', err);
        showToast(label + ' failed: ' + (err?.message || 'unknown error'), 'error');
      }
    }, 80);
  };
  $('mt-edit')?.addEventListener('click', safeRoute(openEditTeamSheet, 'Edit team'));
  $('mt-cocoach')?.addEventListener('click', safeRoute(openAddCoCoachSheet, 'Add co-coach'));
  $('mt-subteams')?.addEventListener('click', safeRoute(openManageSubteamsSheet, 'Manage subteams'));
  $('mt-features')?.addEventListener('click', safeRoute(openFeatureTogglesSheet, 'Feature toggles'));
  $('mt-delete')?.addEventListener('click', safeRoute(deleteTeam, 'Delete team'));
  } catch (err) {
    console.error('[manage-team] open threw:', err);
    showToast('Manage Team error: ' + (err?.message || 'unknown'), 'error');
  }
}

// Feature toggles, extracted into their own sheet (was inline on the
// Team page as a card with a list of seven on/off rows).
function openFeatureTogglesSheet() {
  if (!teamData?.id) { showToast('No team yet.', 'warn'); return; }
  // Permission gate — head coach, co-coaches, admin, master account.
  const teamCoachesSet = Array.isArray(teamData?.coaches) ? new Set(teamData.coaches) : new Set();
  const isHead = teamData.createdBy === currentUser?.uid;
  const isCoCoach = teamCoachesSet.has(currentUser?.uid);
  const isMaster = isMasterAccount(currentUser?.email);
  if (!isHead && !isCoCoach && !isAdmin && !isMaster) {
    showToast('Only coaches can change features.', 'warn');
    return;
  }
  $('sheet-content').innerHTML = `
    <div class="sheet-title">Feature Toggles</div>
    <p style="font-size:12px;color:var(--muted-fg);margin-bottom:14px">Hide or show tabs for everyone on the team. Changes take effect immediately for all members.</p>
    <div style="display:flex;flex-direction:column;gap:10px" id="ft-toggles">${renderCoachFeatureToggles()}</div>
    <button class="btn btn-primary" style="width:100%;margin-top:14px" id="ft-done">Done</button>
  `;
  openSheet();
  document.querySelectorAll('#ft-toggles .coach-feat-toggle').forEach(btn => {
    btn.addEventListener('click', async () => {
      const feat = btn.dataset.feat;
      const current = teamData.features?.[feat] !== false;
      const newVal = !current;
      btn.classList.toggle('on', newVal);
      try {
        if (db) await updateDoc(doc(db, 'teams', userProfile.teamId), { ['features.' + feat]: newVal });
        if (!teamData.features) teamData.features = {};
        teamData.features[feat] = newVal;
      } catch(e) { console.warn('feature toggle:', e); }
    });
  });
  $('ft-done')?.addEventListener('click', () => { closeSheet(); renderTeam(); });
}

function openEditTeamSheet() {
  if (!teamData?.id) { showToast('No team yet.', 'warn'); return; }
  // Widened gate: head coach, co-coaches, admin, master account can
  // all edit. Was head-coach-only — silently blocked everyone else
  // with a confusing toast even though they had legitimate access.
  const teamCoachesSet = Array.isArray(teamData?.coaches) ? new Set(teamData.coaches) : new Set();
  const isHead = teamData.createdBy === currentUser?.uid;
  const isCoCoach = teamCoachesSet.has(currentUser?.uid);
  const isMaster = isMasterAccount(currentUser?.email);
  if (!isHead && !isCoCoach && !isAdmin && !isMaster) {
    showToast('Only coaches can edit team details.', 'warn');
    return;
  }
  const cur = {
    name: teamData.name || '',
    description: teamData.description || '',
    inviteBlurb: teamData.inviteBlurb || '',
  };
  $('sheet-content').innerHTML = `
    <div class="sheet-title">Edit Team</div>
    <p style="font-size:12px;color:var(--muted-fg);margin-bottom:14px">Changes appear instantly for every member.</p>
    <label style="font-size:11px;font-weight:700;color:var(--muted-fg);text-transform:uppercase;letter-spacing:.06em">Team name</label>
    <input class="input" id="edit-team-name" type="text" maxlength="60" value="${escHtml(cur.name)}" style="margin:6px 0 14px">
    <label style="font-size:11px;font-weight:700;color:var(--muted-fg);text-transform:uppercase;letter-spacing:.06em">Description</label>
    <textarea class="input" id="edit-team-desc" rows="3" maxlength="240" placeholder="Short description shown on the team header (optional)" style="margin:6px 0 14px;resize:vertical;font-family:inherit">${escHtml(cur.description)}</textarea>
    <label style="font-size:11px;font-weight:700;color:var(--muted-fg);text-transform:uppercase;letter-spacing:.06em">Invite blurb</label>
    <textarea class="input" id="edit-team-blurb" rows="2" maxlength="280" placeholder="Custom message included when sharing the join code (optional)" style="margin:6px 0 14px;resize:vertical;font-family:inherit">${escHtml(cur.inviteBlurb)}</textarea>
    <div style="font-size:11px;color:var(--muted-fg);margin-bottom:6px">Team code <span style="font-family:var(--font-mono);color:var(--fg);font-weight:700">${escHtml(teamData.code || '')}</span> · cannot be changed</div>
    <div style="display:flex;gap:8px;margin-top:8px">
      <button class="btn btn-secondary" style="flex:1" id="edit-team-cancel">Cancel</button>
      <button class="btn btn-primary" style="flex:1" id="edit-team-save">Save</button>
    </div>
  `;
  openSheet();
  $('edit-team-cancel')?.addEventListener('click', closeSheet);
  $('edit-team-save')?.addEventListener('click', async () => {
    const name = ($('edit-team-name')?.value || '').trim();
    const description = ($('edit-team-desc')?.value || '').trim();
    const inviteBlurb = ($('edit-team-blurb')?.value || '').trim();
    if (!name || name.length < 2) { showToast('Team name is required.', 'warn'); return; }
    try {
      await updateDoc(doc(db, 'teams', teamData.id), { name, description, inviteBlurb });
      teamData.name = name;
      teamData.description = description;
      teamData.inviteBlurb = inviteBlurb;
      if (userProfile.teamName !== name) {
        userProfile.teamName = name;
        try { await updateDoc(doc(db, 'users', currentUser.uid), { teamName: name }); } catch(e) {}
      }
      closeSheet();
      showToast('Team updated.', 'success');
      renderTeam();
    } catch(e) {
      showError('Failed to save team', 'team', e, { action: 'edit' });
    }
  });
}

// --- Manage Subteams ---
function openAddCoCoachSheet() {
  if (!teamData?.id) { showToast('No team yet.', 'warn'); return; }
  // Permission gate — head coach, co-coaches, admin, master account.
  const teamCoachesSet = Array.isArray(teamData?.coaches) ? new Set(teamData.coaches) : new Set();
  const isHead = teamData.createdBy === currentUser?.uid;
  const isCoCoach = teamCoachesSet.has(currentUser?.uid);
  const isMaster = isMasterAccount(currentUser?.email);
  if (!isHead && !isCoCoach && !isAdmin && !isMaster) {
    showToast('Only coaches can add co-coaches.', 'warn');
    return;
  }
  $('sheet-content').innerHTML = `
    <div class="sheet-title">Add Co-Coach</div>
    <p style="font-size:13px;color:var(--muted-fg);margin-bottom:12px">
      Promote an existing team member to co-coach. They will get access to
      Coach tabs and can manage students, but cannot delete the team.
    </p>
    <input class="input" id="cocoach-search" type="text" placeholder="Search by name or email…" autocomplete="off" style="margin-bottom:10px">
    <div id="cocoach-results" style="display:flex;flex-direction:column;gap:6px;max-height:50vh;overflow-y:auto"></div>
  `;
  openSheet();
  const renderResults = (q) => {
    const ql = (q || '').toLowerCase().trim();
    const candidates = teamMembers
      .filter(m => m.uid !== currentUser?.uid)
      .filter(m => !ql || (m.displayName || '').toLowerCase().includes(ql) || (m.email || '').toLowerCase().includes(ql))
      .slice(0, 30);
    const list = $('cocoach-results');
    if (!list) return;
    if (candidates.length === 0) {
      list.innerHTML = `<div style="font-size:12px;color:var(--muted-fg);text-align:center;padding:12px">${ql ? 'No matches.' : 'No members in your team yet.'}</div>`;
      return;
    }
    list.innerHTML = candidates.map(m => {
      const already = m.isCoach || m.role === 'coach';
      return `<div style="display:flex;align-items:center;gap:10px;padding:10px;background:var(--card);border:1px solid var(--border);border-radius:10px">
        <div class="user-avatar" style="background:var(--primary);color:var(--primary-fg);font-size:12px">${escHtml((m.displayName || m.email || '?').slice(0,1).toUpperCase())}</div>
        <div style="flex:1;min-width:0">
          <div style="font-size:13px;font-weight:600;color:var(--fg);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${escHtml(m.displayName || 'Unknown')}</div>
          <div style="font-size:11px;color:var(--muted-fg);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${escHtml(m.email || '')}</div>
        </div>
        ${already
          ? '<span style="font-size:11px;font-weight:700;color:var(--primary);padding:6px 10px;border:1px solid rgba(var(--primary-rgb),.4);border-radius:999px">COACH</span>'
          : `<button class="btn btn-primary cocoach-promote" data-uid="${m.uid}" style="padding:6px 12px;font-size:12px">Promote</button>`
        }
      </div>`;
    }).join('');
    list.querySelectorAll('.cocoach-promote').forEach(btn => {
      btn.addEventListener('click', () => promoteToCoach(btn.dataset.uid, btn));
    });
  };
  renderResults('');
  $('cocoach-search')?.addEventListener('input', e => renderResults(e.target.value));
}

async function promoteToCoach(uid, btn) {
  if (!uid || !teamData?.id) return;
  // Permission gate — Firestore rules also enforce, but check client-side
  // so a stray call can't kick off a doomed write that confuses the UI.
  const isMaster = isMasterAccount(currentUser?.email);
  if (teamData.createdBy !== currentUser?.uid && !isAdmin && !isMaster) {
    showToast('Only the head coach can promote co-coaches.', 'warn');
    return;
  }
  btn.disabled = true; btn.textContent = '…';
  try {
    if (!demoMode && db) {
      await updateDoc(doc(db, 'users', uid), { isCoach: true });
      const coaches = Array.isArray(teamData.coaches) ? teamData.coaches : [];
      if (!coaches.includes(uid)) {
        coaches.push(uid);
        await updateDoc(doc(db, 'teams', teamData.id), { coaches });
        teamData.coaches = coaches;
      }
    }
    const member = teamMembers.find(m => m.uid === uid);
    if (member) member.isCoach = true;
    showToast('Promoted to coach.', 'success');
    btn.replaceWith(Object.assign(document.createElement('span'), {
      style: 'font-size:11px;font-weight:700;color:var(--primary);padding:6px 10px;border:1px solid rgba(var(--primary-rgb),.4);border-radius:999px',
      textContent: 'COACH',
    }));
  } catch (e) {
    showToast('Failed: ' + (e.message || e), 'error');
    btn.disabled = false; btn.textContent = 'Promote';
  }
}

// Scheduled messages (rec #25) — coaches/captains queue a chat message
// for a future time. Stored in teams/{teamId}/scheduled; the
// deliverScheduledMessages Cloud Function posts due ones into /chat.
async function openScheduledMessagesSheet(draftText) {
  const teamId = userProfile?.teamId;
  if (!teamId) { showToast('Join a team first.', 'warn'); return; }
  const isCoachUser = !!userProfile?.isCoach;
  const captainSub = isCoachUser ? '' : getMyCaptainSubteamId();
  if (!isCoachUser && !captainSub && !isAdmin) {
    showToast('Only coaches and captains can schedule messages.', 'warn');
    return;
  }
  const subs = Array.isArray(teamData?.subteams) ? teamData.subteams : [];
  const pad = n => String(n).padStart(2, '0');
  const toLocalInput = d => `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}`;
  const minDt = new Date(Date.now() + 5 * 60 * 1000);
  $('sheet-content').innerHTML = `
    <div class="sheet-title">Schedule a Message</div>
    <div class="form-group">
      <label class="label">Message</label>
      <textarea class="input" id="sched-text" rows="3" maxlength="500" placeholder="What do you want to send later?">${escHtml(draftText || '')}</textarea>
    </div>
    <div class="form-group">
      <label class="label">Send at</label>
      <input class="input" type="datetime-local" id="sched-when" min="${toLocalInput(minDt)}" value="${toLocalInput(new Date(Date.now() + 60*60*1000))}">
    </div>
    ${isCoachUser && subs.length ? `
      <div class="form-group">
        <label class="label">Channel</label>
        <select class="input" id="sched-scope">
          <option value="">Whole team</option>
          ${subs.map(s => `<option value="${escHtml(s.id)}">${escHtml(s.name || 'Subteam')}</option>`).join('')}
        </select>
      </div>` : ''}
    <label style="display:flex;align-items:center;gap:8px;font-size:13px;margin-bottom:14px">
      <input type="checkbox" id="sched-push" checked> Send as a push notification
    </label>
    <button class="btn btn-primary" id="sched-create" style="width:100%;margin-bottom:16px">Schedule</button>
    <div style="font-size:12px;font-weight:700;color:var(--muted-fg);text-transform:uppercase;letter-spacing:.04em;margin-bottom:8px">Pending</div>
    <div id="sched-list"><div style="font-size:12px;color:var(--muted-fg);text-align:center;padding:10px">Loading…</div></div>
  `;
  openSheet();

  const loadPending = async () => {
    const listEl = $('sched-list');
    if (!listEl) return;
    try {
      const snap = await getDocs(collection(db, 'teams', teamId, 'scheduled'));
      const items = snap.docs.map(d => ({ id: d.id, ...d.data() }))
        .sort((a, b) => (a.scheduledFor?.toMillis?.() || 0) - (b.scheduledFor?.toMillis?.() || 0));
      if (!items.length) {
        listEl.innerHTML = '<div style="font-size:12px;color:var(--muted-fg);text-align:center;padding:10px">No scheduled messages.</div>';
        return;
      }
      listEl.innerHTML = items.map(it => {
        const when = it.scheduledFor?.toDate ? it.scheduledFor.toDate() : null;
        const whenStr = when ? when.toLocaleString('en-AU', { weekday:'short', day:'numeric', month:'short', hour:'numeric', minute:'2-digit' }) : '—';
        const scopeName = it.subteamId ? ((subs.find(s => s.id === it.subteamId) || {}).name || 'Subteam') : 'Whole team';
        return `<div style="display:flex;gap:8px;padding:9px 10px;background:var(--card);border:1px solid var(--border);border-radius:10px;margin-bottom:6px">
          <div style="flex:1;min-width:0">
            <div style="font-size:13px;color:var(--fg);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${escHtml(it.text || '')}</div>
            <div style="font-size:11px;color:var(--muted-fg);margin-top:2px">${escHtml(whenStr)} · ${escHtml(scopeName)}${it.broadcastPush ? ' · push' : ''}</div>
          </div>
          <button class="sched-cancel" data-sched-id="${escHtml(it.id)}" style="flex-shrink:0;background:transparent;border:1px solid var(--border);color:var(--destructive);border-radius:8px;padding:4px 10px;font-size:11px;font-weight:700;cursor:pointer">Cancel</button>
        </div>`;
      }).join('');
      listEl.querySelectorAll('.sched-cancel').forEach(btn => {
        btn.addEventListener('click', async () => {
          try {
            await deleteDoc(doc(db, 'teams', teamId, 'scheduled', btn.dataset.schedId));
            showToast('Scheduled message cancelled.', 'info');
            loadPending();
          } catch(e) { showToast('Could not cancel.', 'error'); }
        });
      });
    } catch(e) {
      listEl.innerHTML = '<div style="font-size:12px;color:var(--destructive);text-align:center;padding:10px">Could not load scheduled messages.</div>';
    }
  };
  loadPending();

  $('sched-create')?.addEventListener('click', async () => {
    const text = ($('sched-text')?.value || '').trim();
    const whenVal = $('sched-when')?.value || '';
    if (!text) { showToast('Type a message.', 'warn'); return; }
    if (!whenVal) { showToast('Pick a send time.', 'warn'); return; }
    const when = new Date(whenVal);
    if (isNaN(when) || when.getTime() < Date.now() + 60 * 1000) {
      showToast('Pick a time at least a few minutes from now.', 'warn');
      return;
    }
    const scope = isCoachUser ? ($('sched-scope')?.value || '') : (captainSub || '');
    const push = !!$('sched-push')?.checked;
    const safeName = ((userProfile?.displayName || currentUser?.displayName || 'Coach').toString().trim()) || 'Coach';
    const btn = $('sched-create');
    if (btn) { btn.disabled = true; btn.textContent = 'Scheduling…'; }
    try {
      await addDoc(collection(db, 'teams', teamId, 'scheduled'), {
        uid: currentUser.uid,
        displayName: safeName,
        text,
        kind: push ? 'coach' : 'chat',
        subteamId: String(scope || ''),
        broadcastPush: push,
        scheduledFor: Timestamp.fromDate(when),
        createdAt: serverTimestamp(),
      });
      showToast('Message scheduled.', 'success');
      const t = $('sched-text'); if (t) t.value = '';
      loadPending();
    } catch(e) {
      console.error('schedule failed:', e);
      showToast('Could not schedule: ' + (e.message || e), 'error');
    } finally {
      if (btn) { btn.disabled = false; btn.textContent = 'Schedule'; }
    }
  });
}

function openManageSubteamsSheet() {
  // Permission gate — head coach, co-coach (in teamData.coaches[]),
  // admin, or master account. Was previously open to any caller, so a
  // direct function call could let any team member manage subteams.
  const teamCoaches = Array.isArray(teamData?.coaches) ? new Set(teamData.coaches) : new Set();
  const isHeadCoach = teamData?.createdBy === currentUser?.uid;
  const isCoCoach = teamCoaches.has(currentUser?.uid);
  if (!isHeadCoach && !isCoCoach && !isAdmin && !isMasterAccount(currentUser?.email)) {
    showToast('Only coaches can manage subteams.', 'warn');
    return;
  }
  const subteams = teamData?.subteams || [];
  // Captain backfill (rec #19): the rules check `subCoaches[]` on the
  // team doc, but teams created before that change only had subCoachUid
  // on each subteam. Sync the flat array opportunistically whenever the
  // coach opens this sheet so old captains gain their permissions
  // without needing to reassign anyone.
  (async () => {
    try {
      const actual = [...new Set(subteams.map(s => s.subCoachUid).filter(Boolean))].sort();
      const stored = [...((teamData?.subCoaches || []))].sort();
      const same = actual.length === stored.length && actual.every((u, i) => u === stored[i]);
      if (!same && userProfile?.teamId && db) {
        await updateDoc(doc(db, 'teams', userProfile.teamId), { subCoaches: actual });
        teamData.subCoaches = actual;
      }
    } catch (_) {}
  })();
  // Roster overview (rec #16): work out who's assigned where so the
  // coach can see, at a glance, which athletes still need a subteam.
  const assignedUids = new Set();
  subteams.forEach(s => {
    (s.members || []).forEach(u => assignedUids.add(u));
    if (s.subCoachUid) assignedUids.add(s.subCoachUid);
  });
  const unassigned = (Array.isArray(teamMembers) ? teamMembers : [])
    .filter(m => m.uid && !assignedUids.has(m.uid));
  const totalAthletes = (Array.isArray(teamMembers) ? teamMembers : []).length;
  $('sheet-content').innerHTML = `
    <div class="sheet-title">Manage Subteams</div>
    <p style="font-size:13px;color:var(--muted-fg);margin-bottom:14px">Create subteams within your club (e.g. "Venom"). Tap a subteam to assign members and set a sub-coach.</p>
    ${totalAthletes > 0 ? `<div style="font-size:11px;color:var(--muted-fg);margin-bottom:8px;font-weight:700;letter-spacing:.03em;text-transform:uppercase">${assignedUids.size}/${totalAthletes} athletes assigned</div>` : ''}
    <div id="subteams-list" style="display:flex;flex-direction:column;gap:8px;margin-bottom:14px">
      ${subteams.length === 0
        ? '<div style="font-size:13px;color:var(--muted-fg);text-align:center;padding:12px">No subteams yet.</div>'
        : subteams.map(s => {
            const sc = s.subCoachUid ? teamMembers.find(m => m.uid === s.subCoachUid) : null;
            return `<button class="subteam-row" data-sub-id="${escHtml(s.id)}" style="display:flex;align-items:center;gap:8px;padding:10px 12px;background:var(--card);border:1px solid var(--border);border-radius:10px;cursor:pointer;text-align:left;width:100%">
              <div style="flex:1;min-width:0">
                <div style="font-size:14px;font-weight:700;color:var(--fg)">${escHtml(s.name)}</div>
                <div style="font-size:11px;color:var(--muted-fg);margin-top:2px">${(s.members || []).length} members${sc ? ' · sub-coach ' + escHtml(sc.displayName || sc.email || '?') : ''}</div>
              </div>
              <span style="color:var(--muted-fg);font-size:14px">›</span>
            </button>`;
          }).join('')
      }
    </div>
    ${unassigned.length > 0 ? `
      <div style="font-size:11px;color:var(--primary);margin-bottom:6px;font-weight:700;letter-spacing:.03em;text-transform:uppercase">Unassigned — ${unassigned.length}</div>
      <div style="display:flex;flex-direction:column;gap:4px;margin-bottom:14px;max-height:180px;overflow-y:auto">
        ${unassigned.map(m => `
          <div style="display:flex;align-items:center;gap:8px;padding:7px 10px;background:var(--card);border:1px solid var(--border);border-radius:8px">
            <div style="flex:1;min-width:0;font-size:13px;color:var(--fg);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${escHtml(m.displayName || m.email || 'Unknown')}</div>
            <span style="font-size:11px;color:var(--muted-fg)">${escHtml(m.yearLevel || '—')}</span>
          </div>`).join('')}
      </div>
      <p style="font-size:11px;color:var(--muted-fg);margin:-6px 0 14px">Tap a subteam above to add these athletes.</p>
    ` : (totalAthletes > 0 && subteams.length > 0 ? '<p style="font-size:12px;color:var(--success,#22c55e);margin-bottom:14px">Every athlete is assigned to a subteam.</p>' : '')}
    <div class="form-group">
      <label class="label" for="new-subteam-name">New Subteam Name</label>
      <input class="input" type="text" id="new-subteam-name" placeholder="e.g. Venom" maxlength="40">
    </div>
    <div style="display:flex;gap:8px;margin-top:4px">
      <button class="btn btn-secondary" style="flex:1" id="subteam-cancel-btn">Done</button>
      <button class="btn btn-primary" style="flex:1" id="subteam-create-btn">+ Create</button>
    </div>
  `;
  openSheet();
  $('subteam-cancel-btn').addEventListener('click', closeSheet);
  $('subteam-create-btn').addEventListener('click', async () => {
    const name = $('new-subteam-name').value.trim();
    if (!name) { showToast('Enter a subteam name.', 'warn'); return; }
    const newSub = { id: 'sub_' + Date.now(), name, members: [], subCoachUid: null, createdAt: new Date().toISOString() };
    const updated = [...(teamData.subteams || []), newSub];
    try {
      await updateDoc(doc(db, 'teams', userProfile.teamId), { subteams: updated });
      teamData.subteams = updated;
      openManageSubteamsSheet();  // reopen so the new row shows + form clears
      showToast('Subteam "' + name + '" created.', 'success');
    } catch(e) { showToast('Failed: ' + (e.message || e), 'error'); }
  });
  document.querySelectorAll('.subteam-row').forEach(btn => {
    btn.addEventListener('click', () => openSubteamDetailSheet(btn.dataset.subId));
  });
}

/// Detail sheet — head coach can edit a subteam's members + sub-coach + delete.
function openSubteamDetailSheet(subId) {
  // Gate matches openManageSubteamsSheet — head coach, co-coach, admin,
  // master account.
  const teamCoaches = Array.isArray(teamData?.coaches) ? new Set(teamData.coaches) : new Set();
  const isHeadCoach = teamData?.createdBy === currentUser?.uid;
  const isCoCoach = teamCoaches.has(currentUser?.uid);
  if (!isHeadCoach && !isCoCoach && !isAdmin && !isMasterAccount(currentUser?.email)) {
    showToast('Only coaches can manage subteams.', 'warn');
    return;
  }
  const subteams = teamData?.subteams || [];
  const sub = subteams.find(s => s.id === subId);
  if (!sub) { showToast('Subteam not found.', 'warn'); return; }
  const memberSet = new Set(sub.members || []);
  const renderMemberRow = (m) => {
    const inSub = memberSet.has(m.uid);
    const isSubCoach = sub.subCoachUid === m.uid;
    return `<div style="display:flex;align-items:center;gap:8px;padding:8px 10px;background:var(--card);border:1px solid var(--border);border-radius:10px">
      <div class="user-avatar" style="background:var(--primary);color:var(--primary-fg);font-size:12px">${escHtml((m.displayName || m.email || '?').slice(0,1).toUpperCase())}</div>
      <div style="flex:1;min-width:0">
        <div style="font-size:13px;font-weight:600;color:var(--fg);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${escHtml(m.displayName || 'Unknown')}${isSubCoach ? ' · <span style="color:var(--primary)">SUB-COACH</span>' : ''}</div>
        <div style="font-size:11px;color:var(--muted-fg);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${escHtml(m.email || '')}</div>
      </div>
      <button class="sub-toggle" data-uid="${m.uid}" style="padding:6px 10px;font-size:11px;font-weight:700;border-radius:8px;border:1px solid ${inSub ? 'rgba(var(--success-rgb),.4)' : 'var(--border)'};background:${inSub ? 'rgba(var(--success-rgb),.10)' : 'transparent'};color:${inSub ? 'var(--success)' : 'var(--muted-fg)'};cursor:pointer">${inSub ? '✓ In' : '+ Add'}</button>
      ${inSub && !isSubCoach ? `<button class="sub-promote" data-uid="${m.uid}" title="Make sub-coach" style="padding:6px 8px;font-size:11px;border:1px solid var(--border);background:transparent;border-radius:8px;cursor:pointer;color:var(--muted-fg)">★</button>` : ''}
    </div>`;
  };
  $('sheet-content').innerHTML = `
    <div class="sheet-title">${escHtml(sub.name)}</div>
    <p style="font-size:12px;color:var(--muted-fg);margin-bottom:12px">${(sub.members||[]).length} members${sub.subCoachUid ? ' · ★ marks sub-coach' : ''}</p>
    <div style="display:flex;flex-direction:column;gap:6px;max-height:50vh;overflow-y:auto;margin-bottom:14px">
      ${teamMembers.filter(m => m.uid !== currentUser?.uid).map(renderMemberRow).join('') || '<div style="font-size:12px;color:var(--muted-fg);text-align:center;padding:12px">No team members to assign yet.</div>'}
    </div>
    <div style="display:flex;gap:8px">
      <button class="btn" style="flex:1;color:var(--destructive);border:1px solid rgba(var(--destructive-rgb),.3);background:rgba(var(--destructive-rgb),.08)" id="subteam-delete-btn">Delete</button>
      <button class="btn btn-primary" style="flex:1" id="subteam-back-btn">Done</button>
    </div>
  `;
  // Member toggle
  document.querySelectorAll('.sub-toggle').forEach(btn => {
    btn.addEventListener('click', async () => {
      const uid = btn.dataset.uid;
      const cur = memberSet.has(uid);
      cur ? memberSet.delete(uid) : memberSet.add(uid);
      const updatedSubs = subteams.map(s => s.id === subId
        ? { ...s, members: Array.from(memberSet), updatedAt: new Date().toISOString() }
        : s);
      try {
        await updateDoc(doc(db, 'teams', userProfile.teamId), { subteams: updatedSubs });
        teamData.subteams = updatedSubs;
        sub.members = Array.from(memberSet);
        openSubteamDetailSheet(subId);
      } catch(e) {
        showToast('Failed: ' + (e.message || e), 'error');
        cur ? memberSet.add(uid) : memberSet.delete(uid);
      }
    });
  });
  // Sub-coach assign. We also maintain a flat `subCoaches` array on the
  // team doc — the Firestore rules check membership of that array to
  // grant captains their limited coach powers (rec #19); rules can't
  // reach into the subteams array to verify a per-subteam subCoachUid.
  document.querySelectorAll('.sub-promote').forEach(btn => {
    btn.addEventListener('click', async () => {
      const uid = btn.dataset.uid;
      const updatedSubs = subteams.map(s => s.id === subId
        ? { ...s, subCoachUid: uid, updatedAt: new Date().toISOString() }
        : s);
      const subCoaches = [...new Set(updatedSubs.map(s => s.subCoachUid).filter(Boolean))];
      try {
        await updateDoc(doc(db, 'teams', userProfile.teamId), { subteams: updatedSubs, subCoaches });
        teamData.subteams = updatedSubs;
        teamData.subCoaches = subCoaches;
        showToast('Captain set — they can broadcast + pin in this subteam.', 'success');
        openSubteamDetailSheet(subId);
      } catch(e) { showToast('Failed: ' + (e.message || e), 'error'); }
    });
  });
  $('subteam-back-btn').addEventListener('click', openManageSubteamsSheet);
  $('subteam-delete-btn').addEventListener('click', async () => {
    const ok = await confirmModal('Delete subteam?', 'Members keep team membership but lose this subteam grouping.');
    if (!ok) return;
    const updatedSubs = subteams.filter(s => s.id !== subId);
    const subCoaches = [...new Set(updatedSubs.map(s => s.subCoachUid).filter(Boolean))];
    try {
      await updateDoc(doc(db, 'teams', userProfile.teamId), { subteams: updatedSubs, subCoaches });
      teamData.subteams = updatedSubs;
      teamData.subCoaches = subCoaches;
      showToast('Subteam deleted.', 'info');
      openManageSubteamsSheet();
    } catch(e) { showToast('Failed: ' + (e.message || e), 'error'); }
  });
}

// Delete-team — only the creator should call this. Cleans up:
//   1. sharedPlans subcollection (Firestore doesn't cascade-delete)
//   2. Every other member's userProfile.teamId / teamName
//   3. Local per-team localStorage cache (capture the id BEFORE we null out
//      userProfile — the previous implementation cleared teamId first, then
//      read userProfile.teamId for the cache key and got 'tp_team_null')
// Does NOT flip isCoach off — the creator may want to start another team.
async function deleteTeam() {
  const tid = userProfile?.teamId;
  if (!currentUser || !tid) return;
  // Destructive — head coach + admin + master only. Co-coaches can
  // edit team details but can't nuke the whole team.
  const isHead = teamData?.createdBy === currentUser?.uid;
  const isMaster = isMasterAccount(currentUser?.email);
  if (!isHead && !isAdmin && !isMaster) {
    showToast('Only the head coach can delete the team.', 'warn');
    return;
  }
  if (demoMode) {
    teamData = null; teamMembers = []; userProfile.teamId = null; userProfile.teamName = null;
    window._teamLbFilter = undefined;
    if (teamUnsubscribe) { try { teamUnsubscribe(); } catch(e) {} teamUnsubscribe = null; }
    showToast('Team deleted.', 'info'); renderTeam(); return;
  }
  if (!db) return;
  const ok = await confirmModal(
    'Delete team?',
    'Permanently delete this team? All members will lose access. This cannot be undone.'
  );
  if (!ok) return;
  showLoading('Deleting team...');
  try {
    // 1. Remove shared plans under the team so the doc can delete cleanly.
    try {
      const sp = await getDocs(collection(db, 'teams', tid, 'sharedPlans'));
      await Promise.allSettled(sp.docs.map(d =>
        deleteDoc(doc(db, 'teams', tid, 'sharedPlans', d.id))
      ));
    } catch(e) { logError('delete-team-sharedplans', e, { tid }); }
    // 2. Clear teamId on every member's profile so their UI doesn't dangle.
    const memberIds = Array.isArray(teamData?.members) ? teamData.members : [currentUser.uid];
    await Promise.allSettled(memberIds.map(uid =>
      updateDoc(doc(db, 'users', uid), { teamId: null, teamName: null })
        .catch(e => logError('delete-team-member-profile', e, { uid, tid }))
    ));
    // 3. Delete the team doc itself.
    await deleteDoc(doc(db, 'teams', tid));
    // 4. Local cleanup.
    try {
      localStorage.removeItem('tp_team_' + tid);
      localStorage.removeItem('tp_team_ts_' + tid);
    } catch(e) {}
    teamData = null; teamMembers = [];
    userProfile.teamId = null; userProfile.teamName = null;
    hideLoading();
    showToast('Team deleted.', 'info');
    renderTeam();
  } catch(e) {
    hideLoading();
    logError('delete-team', e, { tid });
    showError('Failed to delete team', 'team', e, { action: 'delete' });
  }
}

async function leaveTeam() {
  if (!currentUser || !userProfile?.teamId) return;
  const teamName = teamData?.name || 'this team';
  showModal('Leave Team', '<div style="font-size:14px;color:var(--fg)">Are you sure you want to leave <strong>' + escHtml(teamName) + '</strong>? You can rejoin later with the team code.</div>', async () => {
    if (demoMode) {
      teamData = null;
      teamMembers = [];
      userProfile.teamId = null;
      userProfile.teamName = null;
      showToast('Left team.', 'info');
      renderTeam();
      return;
    }
    if (!db) return;
    showLoading('Leaving team...');
    try {
      const tid = userProfile.teamId;
      const teamSnap = await getDoc(doc(db, 'teams', tid));
      if (teamSnap.exists()) {
        const members = teamSnap.data().members || [];
        const isMember = members.includes(currentUser.uid);
        if (isMember && members.length <= 1) {
          // Last member: delete team — rules block updates that empty members.
          await deleteDoc(doc(db, 'teams', tid));
        } else if (isMember) {
          await updateDoc(doc(db, 'teams', tid), { members: arrayRemove(currentUser.uid) });
        }
        // If teamId is set but user isn't in members (corrupt state), skip the team
        // write and just clear the profile below so they can escape.
      }
      await updateDoc(doc(db, 'users', currentUser.uid), { teamId: null, teamName: null });
      userProfile.teamId = null;
      userProfile.teamName = null;
      teamData = null;
      teamMembers = [];
      hideLoading();
      showToast('Left team.', 'info');
      renderTeam();
    } catch(e) {
      hideLoading();
      console.error('Leave team error:', e);
      showError('Failed to leave team', 'team', e, { action: 'leave' });
    }
  });
}
/// Flag the only existing team as the CGS premium edition. Because
/// there's just one club at launch, "the club" IS the CGS one — we
/// don't create new teams, we just tag what's there. Idempotent:
/// re-runs every admin signin but only writes when needed.
///
///   • 0 teams in Firestore → no-op (admin should create their team
///     manually via the Coach > Manage flow first).
///   • Exactly 1 team       → patch edition='cgs' if not already set.
///   • Multiple teams       → no-op (we'd be guessing which is CGS).
///                            Admin can set the flag manually from the
///                            Firestore console if a multi-team future
///                            ever arrives.
async function ensureCgsTeam() {
  if (!db || !currentUser) return;
  try {
    const snap = await getDocs(collection(db, 'teams'));
    if (snap.empty) {
      console.log('[cgs] no teams yet — skipping seed');
      return;
    }
    if (snap.size > 1) {
      console.log(`[cgs] ${snap.size} teams found — skipping auto-flag (ambiguous)`);
      return;
    }
    const doc0 = snap.docs[0];
    const data = doc0.data();
    if (data.edition === 'cgs') {
      console.log('[cgs] only team already flagged as cgs:', doc0.id);
      return doc0.id;
    }
    try {
      await updateDoc(doc0.ref, { edition: 'cgs' });
      console.log('[cgs] flagged only team as cgs:', doc0.id, 'name:', data.name);
      showToast?.(`${data.name || 'Team'} upgraded to CGS premium edition`, 'success');
    } catch (e) {
      console.warn('[cgs] flag write failed (rules?):', e?.message || e);
    }
    return doc0.id;
  } catch (e) {
    console.warn('[cgs] ensureCgsTeam failed:', e?.message || e);
  }
}

/// One-shot rollback helper — strips edition='cgs' off whatever team
/// holds it. Runs every admin signin while the broken theme is in
/// the field. Safe to remove once we re-ship the premium theme.
async function clearCgsEdition() {
  if (!db || !currentUser) return;
  try {
    const snap = await getDocs(query(collection(db, 'teams'), where('edition', '==', 'cgs')));
    for (const d of snap.docs) {
      try { await updateDoc(d.ref, { edition: null }); console.log('[cgs] cleared edition on', d.id); }
      catch (e) { console.warn('[cgs] clear edition failed:', d.id, e?.message); }
    }
  } catch (e) {
    console.warn('[cgs] query for edition=cgs failed:', e?.message || e);
  }
}

async function loadTeamData(forceRefresh=false) {
  if (!currentUser || !userProfile?.teamId) {
    teamData = null; teamMembers = []; return;
  }
  if (demoMode) return;
  if (!db) return;

  // Cache team members for 5 minutes — saves N reads per page load
  const cacheKey = 'tp_team_' + userProfile.teamId;
  const cacheTs  = 'tp_team_ts_' + userProfile.teamId;
  if (!forceRefresh) {
    try {
      const ts = parseInt(localStorage.getItem(cacheTs)||'0');
      if (Date.now()-ts < 5*60*1000) {
        const cached = JSON.parse(localStorage.getItem(cacheKey)||'null');
        if (cached) { teamData=cached.teamData; teamMembers=cached.members; return; }
      }
    } catch(e) {}
  }

  try {
    const teamSnap = await getDoc(doc(db, 'teams', userProfile.teamId));
    if (!teamSnap.exists()) {
      userProfile.teamId = null; userProfile.teamName = null;
      teamData = null; teamMembers = []; return;
    }
    const td = teamSnap.data();
    // Include EVERY field the rest of the app reads — previously only
    // {id,name,code,members} were spread, so on every page load we lost
    // subteams/coaches/createdBy/features and the head-coach-only UI
    // (Manage Subteams, Add Co-Coach, Race-Day controls) silently
    // disappeared until the next manual write put them back in memory.
    teamData = {
      id: teamSnap.id,
      name: td.name,
      code: td.code,
      edition: td.edition || null,        // 'cgs' unlocks the gold-on-white theme
      members: td.members || [],
      coaches: td.coaches || [],
      createdBy: td.createdBy || null,
      subteams: td.subteams || [],
      features: td.features || {},
      weeklyIntent: td.weeklyIntent || null,
      weeklyIntentSetAt: td.weeklyIntentSetAt || null,
    };
    // Flip the edition theme + brand the second teamData lands.
    applyEditionTheme(teamData);
    // Load each member's data — parallelised. Was 3 sequential reads
    // per member; with 20 athletes that's 60 round-trips serially. Now
    // 3 batches of N parallel reads ≈ 3 round-trips total.
    const today = new Date();
    const dateKey = today.getFullYear() + '-' + String(today.getMonth()+1).padStart(2,'0') + '-' + String(today.getDate()).padStart(2,'0');
    const memberIds = teamData.members;
    const [profileResults, workoutResults, checklistResults] = await Promise.all([
      Promise.all(memberIds.map(uid => getDoc(doc(db, 'users', uid)).catch(() => null))),
      Promise.all(memberIds.map(uid => getDocs(collection(db, 'users', uid, 'workouts')).catch(() => null))),
      Promise.all(memberIds.map(uid => getDoc(doc(db, 'users', uid, 'checklist', dateKey)).catch(() => null))),
    ]);
    const members = memberIds.map((uid, i) => {
      const uSnap = profileResults[i];
      const wSnap = workoutResults[i];
      const clSnap = checklistResults[i];
      const uData = uSnap?.exists?.() ? uSnap.data() : {};
      const totalWorkouts = wSnap?.size || 0;
      // Streak
      let streak = 0;
      if (wSnap && totalWorkouts > 0) {
        const workoutDates = new Set();
        wSnap.docs.forEach(d => {
          const wd = d.data().date;
          const dt = wd?.toDate ? wd.toDate() : (wd ? new Date(wd) : null);
          if (dt) workoutDates.add(dt.getFullYear()+'-'+(dt.getMonth()+1)+'-'+dt.getDate());
        });
        let check = new Date(today);
        check.setHours(0,0,0,0);
        let todayKey = check.getFullYear()+'-'+(check.getMonth()+1)+'-'+check.getDate();
        if (!workoutDates.has(todayKey)) check.setDate(check.getDate()-1);
        while (true) {
          const key = check.getFullYear()+'-'+(check.getMonth()+1)+'-'+check.getDate();
          if (workoutDates.has(key)) { streak++; check.setDate(check.getDate()-1); }
          else break;
        }
      }
      // Today checklist
      let checklistPct = 0;
      if (clSnap?.exists?.()) {
        const items = clSnap.data().items || {};
        const vals = Object.values(items);
        if (vals.length > 0) checklistPct = (vals.filter(v => v === true).length / vals.length) * 100;
      }
      return {
        uid,
        displayName: uData.displayName || 'Unknown',
        photoURL: uData.photoURL || null,
        // email + isCoach were missing from the projection; the
        // Add-Co-Coach search-by-email path could never find anyone
        // and the Promote button always rendered for existing
        // co-coaches because m.isCoach was always undefined.
        email: uData.email || '',
        isCoach: !!uData.isCoach,
        yearLevel: uData.yearLevel || null,
        fitnessLevel: uData.fitnessLevel || 'basic',
        activePlanId: uData.activePlanId || null,
        totalWorkouts,
        streak,
        checklistPct,
      };
    });
    teamMembers = members;
    // Save to cache
    try {
      localStorage.setItem('tp_team_'+userProfile.teamId, JSON.stringify({teamData,members}));
      localStorage.setItem('tp_team_ts_'+userProfile.teamId, Date.now().toString());
    } catch(e) {}
  } catch(e) {
    console.error('Load team error:', e);
    teamData = null;
    teamMembers = [];
  }
}

/// Attach the team-chat listener as a background subscription that lasts
/// the user's whole session — like Messages on a phone, the listener
/// runs whether or not the chat tab is currently visible. The chat tab
/// just paints from chatCache instead of trying to bring up its own
/// listener with a "Connecting" state.
let _bgChatLive = false;
let _bgChatPending = false;
let _bgChatRetryTimer = null;
let _bgChatRetryCount = 0;

function _scheduleChatRetry() {
  if (_bgChatRetryTimer) return;
  if (_bgChatRetryCount > 60) return; // 60×3s = 3 minutes; give up after that
  _bgChatRetryTimer = setTimeout(() => {
    _bgChatRetryTimer = null;
    _bgChatRetryCount++;
    if (!_bgChatLive && currentUser) {
      console.log('[chat] retry attach (#' + _bgChatRetryCount + ')');
      attachBackgroundChat();
    }
  }, 3000);
}

async function attachBackgroundChat() {
  if (!currentUser) { console.log('[chat] no currentUser, skipping'); return; }
  if (!userProfile?.teamId) {
    console.log('[chat] no teamId yet, will retry');
    _scheduleChatRetry();
    return;
  }
  if (_bgChatLive) return; // already attached
  const sigStr = (typeof subscribeTeamChat === 'function') ? subscribeTeamChat.toString() : '';
  const isStub = sigStr === '() => null' || sigStr.replace(/\s+/g, '') === '()=>null';
  if (typeof subscribeTeamChat !== 'function' || isStub) {
    console.log('[chat] subscribe fn not ready yet (stub=' + isStub + '), will retry');
    _bgChatPending = true;
    _scheduleChatRetry();
    return;
  }
  _bgChatPending = false;
  // Pre-flight: read the team doc directly (no cache) and ensure our
  // uid is in members[] BEFORE attaching the listener. This eliminates
  // the permission-denied → backoff → retry cycle that left chat
  // "eternally connecting" for users with stale localStorage.
  try {
    const tref = doc(db, 'teams', userProfile.teamId);
    const tsnap = await getDoc(tref);
    if (tsnap.exists()) {
      const td = tsnap.data();
      const members = Array.isArray(td.members) ? td.members : [];
      if (!members.includes(currentUser.uid)) {
        console.warn('[chat] preflight: uid not in members[], adding now', { uid: currentUser.uid, members });
        try {
          await updateDoc(tref, { members: arrayUnion(currentUser.uid) });
          // Wait briefly for propagation to read replicas before listener attach.
          await new Promise(r => setTimeout(r, 300));
        } catch (heal) {
          console.error('[chat] preflight self-heal write failed:', heal?.code, heal?.message);
          window._tpChatLastError = 'preflight-write-' + (heal?.code || 'fail') + ': ' + (heal?.message || '');
          // Don't bail — try the listener anyway. Some rules still allow
          // read where they don't allow write.
        }
        try {
          localStorage.removeItem('tp_team_' + userProfile.teamId);
          localStorage.removeItem('tp_team_ts_' + userProfile.teamId);
        } catch(_) {}
      }
    } else {
      console.warn('[chat] preflight: team doc does not exist', userProfile.teamId);
      window._tpChatLastError = 'team-doc-missing';
    }
  } catch (preErr) {
    console.warn('[chat] preflight team-read failed:', preErr?.code, preErr?.message);
    window._tpChatLastError = 'preflight-read-' + (preErr?.code || 'fail');
    // Continue anyway — better to try the listener than abort.
  }
  console.log('[chat] attaching listener for teamId=' + userProfile.teamId);
  try {
    subscribeTeamChat(userProfile.teamId, () => {
      if (!_bgChatLive) console.log('[chat] first snapshot received → Live');
      _bgChatLive = true;
      _bgChatRetryCount = 0;
      if (currentPage === 'team' && lbSubTab === 'chat') {
        try { refreshTeamChatList(); } catch(_) {}
        // Viewing the thread → keep it marked read as messages arrive.
        try { markChatRead(); } catch(_) {}
        const pill = document.getElementById('chat-status-pill');
        if (pill) pill.hidden = true;
      } else {
        // Not looking at chat — refresh the unread badge on the tab.
        try { updateChatUnreadBadge(); } catch(_) {}
      }
    }, (err) => {
      _bgChatLive = false;
      _bgChatRetryCount++;
      const code = err?.code || err?.message || String(err || 'unknown');
      console.warn('[chat] listener error (#' + _bgChatRetryCount + '):', code);
      window._tpChatLastError = code;
      // Force the chat panel to re-render so the diagnostic strip appears
      // (it's gated on lastErr; without re-render, the previous render
      // never sees the new error).
      if (currentPage === 'team' && lbSubTab === 'chat' && _bgChatRetryCount >= 2) {
        const cc = document.getElementById('lb-chat-content');
        if (cc) { try { renderTeamChatPanelInto(cc); } catch(_) {} }
      }
      // Surface the actual error in the pill — generic "Reconnecting…"
      // gave us no signal to debug with. Cached messages keep chat
      // functional, so don't show the pill if we have any.
      if (currentPage === 'team' && lbSubTab === 'chat') {
        const cache = (typeof getTeamChatCache === 'function') ? getTeamChatCache() : [];
        const hasCache = Array.isArray(cache) && cache.length > 0;
        const pill = document.getElementById('chat-status-pill');
        if (pill) {
          if (_bgChatRetryCount >= 2 && !hasCache) {
            pill.classList.remove('chat-status-connecting', 'chat-status-live');
            pill.classList.add('chat-status-error');
            pill.hidden = false;
            const lbl = pill.querySelector('.chat-status-label');
            if (lbl) {
              const friendly = (code === 'permission-denied')
                ? 'Permission denied — tap Retry'
                : (code === 'unavailable')
                  ? 'Offline — tap Retry'
                  : ('Error: ' + String(code).slice(0, 36));
              lbl.textContent = friendly;
            }
          } else {
            pill.hidden = true;
          }
        }
      }
      // Auto-retry with backoff. Most errors are membership-drift races
      // that ensureDefaultTeamMembership fixes by adding uid to members[].
      const backoff = Math.min(1500 * _bgChatRetryCount, 15000);
      setTimeout(() => {
        if (userProfile?.teamId) {
          try { ensureDefaultTeamMembership?.().catch(() => {}); } catch(_) {}
          setTimeout(() => attachBackgroundChat(), 700);
        }
      }, backoff);
    });
  } catch(e) { console.warn('attachBackgroundChat:', e); }
}

/// Attach (or re-attach) the live snapshot listener on teams/{teamId}.
/// Reacts to `members[]` growth, subteam edits, coach promotions, etc.
/// Drops the local cache so changes propagate immediately and re-renders
/// the Team page if the user is viewing it.
function attachTeamLiveListener() {
  if (teamUnsubscribe) { try { teamUnsubscribe(); } catch(e) {} teamUnsubscribe = null; }
  if (!db || !userProfile?.teamId) return;
  try {
    teamUnsubscribe = onSnapshot(doc(db, 'teams', userProfile.teamId), async (snap) => {
      if (!snap.exists()) return;
      const td = snap.data();
      const prevMemberIds = new Set((teamData?.members) || []);
      const nextMemberIds = td.members || [];
      const newJoiners = nextMemberIds.filter(uid => !prevMemberIds.has(uid));
      // Refresh the team-data shape (keeps subteams/coaches/etc. fresh).
      teamData = {
        id: snap.id, name: td.name, code: td.code,
        members: nextMemberIds, coaches: td.coaches || [],
        createdBy: td.createdBy || null, subteams: td.subteams || [],
        features: td.features || {},
      };
      // If members actually changed, re-fetch member metadata + bust cache.
      if (newJoiners.length > 0 || nextMemberIds.length !== prevMemberIds.size) {
        try { localStorage.removeItem('tp_team_ts_' + snap.id); } catch(e) {}
        try { await loadTeamData(true); } catch(e) {}
        // If MY uid just got added to members[], the chat listener was
        // probably failing with permission-denied. Force-reattach now
        // that we have permission so the user doesn't have to tap Retry.
        if (currentUser?.uid && nextMemberIds.includes(currentUser.uid) && !prevMemberIds.has(currentUser.uid)) {
          console.log('[chat] our uid joined members[], reattaching listener');
          _bgChatLive = false;
          _bgChatRetryCount = 0;
          try { unsubscribeTeamChat?.(); } catch(_) {}
          try { attachBackgroundChat?.(); } catch(_) {}
        }
      }
      if (currentPage === 'team') renderTeam();
    }, (err) => {
      console.warn('team listener:', err);
    });
  } catch(e) { console.warn('attachTeamLiveListener:', e); }
}
// Utilities (escHtml, capitalize imported from state.js)
// Find a plan by ID from built-in + custom plans
function findPlan(id) {
  if (!id) return null;
  // Migration: 'invehicle-*' plan ids were renamed to 'bike-*' when the
  // category was relabelled. Existing users' activePlanId still points at
  // the legacy id; rewrite on lookup so the rest of the app finds the
  // current plan instead of a null.
  if (typeof id === 'string' && id.startsWith('invehicle-')) {
    id = 'bike-' + id.slice('invehicle-'.length);
  }
  return ALL_PLANS.find(p => p.id === id) || customPlans.find(p => p.id === id) || null;
}
function getTimeAgo(dateStr) {
  try {
    const d = new Date(dateStr);
    const now = new Date();
    const diffMs = now - d;
    const mins = Math.floor(diffMs / 60000);
    if (mins < 1) return 'Just now';
    if (mins < 60) return mins + 'm ago';
    const hrs = Math.floor(mins / 60);
    if (hrs < 24) return hrs + 'h ago';
    const days = Math.floor(hrs / 24);
    if (days < 7) return days + 'd ago';
    return d.toLocaleDateString('en-AU', { day: 'numeric', month: 'short' });
  } catch(e) { return ''; }
}
function getEmbedUrl(url) {
  if (!url) return '';
  try {
    // Already an embed URL
    if (url.includes('/embed/')) return url.split('?')[0];
    // YouTube Shorts: /shorts/VIDEO_ID
    const shortsMatch = url.match(/youtube\.com\/shorts\/([A-Za-z0-9_-]+)/);
    if (shortsMatch) return 'https://www.youtube.com/embed/' + shortsMatch[1];
    // Standard watch: ?v=VIDEO_ID
    const watchMatch = url.match(/[?&]v=([A-Za-z0-9_-]+)/);
    if (watchMatch) return 'https://www.youtube.com/embed/' + watchMatch[1];
    // youtu.be short link
    const shortMatch = url.match(/youtu\.be\/([A-Za-z0-9_-]+)/);
    if (shortMatch) return 'https://www.youtube.com/embed/' + shortMatch[1];
  } catch(e) {}
  return url;
}
// Firebase Listeners
// Team-training cue listener — fires when the coach hits "Start team
// training now" in Coach > Race Day. Each athlete gets a toast + the
// Start Training button highlighted. Mute one cue per device by
// stashing its ID in localStorage.
let _teamTrainingCueUnsub = null;
function listenTeamTrainingCue() {
  try { _teamTrainingCueUnsub?.(); } catch(_) {}
  _teamTrainingCueUnsub = null;
  if (!db || !userProfile?.teamId) return;
  try {
    _teamTrainingCueUnsub = onSnapshot(
      doc(db, 'teams', userProfile.teamId, 'cues', 'training'),
      (snap) => {
        if (!snap.exists()) return;
        const d = snap.data();
        if (!d.active) return;
        const cueAt = d.startedAt?.toMillis?.() || 0;
        if (Date.now() - cueAt > 30 * 60 * 1000) return;     // ignore stale (>30min)
        const ackKey = 'tp_team_train_ack_' + (cueAt || 'now');
        try { if (localStorage.getItem(ackKey)) return; } catch(_) {}
        try { localStorage.setItem(ackKey, '1'); } catch(_) {}
        if (d.startedBy === currentUser?.uid) return;        // don't notify the coach who started it
        showToast?.(`${d.startedByName || 'Coach'} started team training`, 'info');
        // Flash the Start Training button + nudge the user to today.
        try {
          if (currentPage !== 'today') {
            const btn = document.querySelector('[data-page="today"]');
            btn?.click();
          }
          setTimeout(() => {
            const cta = document.getElementById('today-start-training');
            if (cta) {
              cta.style.outline = '3px solid var(--primary)';
              cta.style.outlineOffset = '3px';
              cta.scrollIntoView({ behavior: 'smooth', block: 'center' });
              setTimeout(() => { cta.style.outline = ''; cta.style.outlineOffset = ''; }, 4000);
            }
          }, 250);
        } catch(_) {}
      },
      (err) => console.warn('team-train cue listener:', err?.message || err)
    );
  } catch (e) { console.warn('listenTeamTrainingCue:', e?.message || e); }
}

function setupListeners(uid) {
  // Listen to workouts. Debounce the re-render so a burst — e.g. a
  // Strava sync writing 30 workouts in <1s — coalesces into a single
  // paint instead of 30 full list rebuilds (each one reparses
  // tp_photos / vf_routes from localStorage and re-mounts every
  // mini-map).
  if (workoutsUnsubscribe) workoutsUnsubscribe();
  const wRef = query(collection(db, 'users', uid, 'workouts'), orderBy('date', 'desc'));
  let _workoutsRenderTimer = null;
  workoutsUnsubscribe = onSnapshot(wRef, (snap) => {
    userWorkouts = snap.docs.map(d => ({ _id: d.id, ...d.data() }));
    if (_workoutsRenderTimer) clearTimeout(_workoutsRenderTimer);
    _workoutsRenderTimer = setTimeout(() => {
      _workoutsRenderTimer = null;
      if (currentPage === 'fitness' && fitnessSubTab === 'workouts') renderWorkouts();
      else if (currentPage === 'today') renderToday();
    }, 80);
  }, (err) => {
    console.error('Workouts listener error:', err);
    userWorkouts = [];
  });
  // Listen to today's checklist
  if (checklistUnsubscribe) checklistUnsubscribe();
  const today = new Date();
  const dateKey = today.getFullYear() + '-' + String(today.getMonth()+1).padStart(2,'0') + '-' + String(today.getDate()).padStart(2,'0');
  const clRef = doc(db, 'users', uid, 'checklist', dateKey);
  checklistUnsubscribe = onSnapshot(clRef, (snap) => {
    if (snap.exists()) {
      userChecklist = snap.data().items || {};
    } else {
      userChecklist = {};
    }
    if (currentPage === 'today') renderToday();
  }, (err) => {
    console.error('Checklist listener error:', err);
    userChecklist = {};
  });
  // Listen to plan overrides for the active plan
  if (planOverridesUnsubscribe) planOverridesUnsubscribe();
  const activeId = userProfile?.activePlanId;
  if (activeId) {
    const poRef = doc(db, 'users', uid, 'planOverrides', activeId);
    planOverridesUnsubscribe = onSnapshot(poRef, (snap) => {
      userPlanOverrides[activeId] = snap.exists()
        ? (snap.data() || { entries: [] })
        : { entries: [] };
      if (currentPage === 'today') renderToday();
    }, (err) => {
      console.error('Plan overrides listener error:', err);
      userPlanOverrides[activeId] = { entries: [] };
    });
  }
}
async function loadUserProfile(uid) {
  try {
    const snap = await getDoc(doc(db, 'users', uid));
    if (snap.exists()) {
      userProfile = snap.data();
      // One-time migration: if the user's activePlanId was set to a legacy
      // 'invehicle-*' id (from before the bike rename), rewrite it to the
      // current 'bike-*' id and persist. Idempotent — runs at most once.
      if (typeof userProfile.activePlanId === 'string' && userProfile.activePlanId.startsWith('invehicle-')) {
        const newId = 'bike-' + userProfile.activePlanId.slice('invehicle-'.length);
        userProfile.activePlanId = newId;
        try { await updateDoc(doc(db, 'users', uid), { activePlanId: newId }); } catch(e) {}
      }
    } else {
      userProfile = {
        displayName: currentUser.displayName || 'User',
        email: currentUser.email || '',
        yearLevel: 'Y7',
        fitnessLevel: 'basic',
        activePlanId: null,
        createdAt: serverTimestamp()
      };
      await setDoc(doc(db, 'users', uid), userProfile);
    }
    // Live profile updates via onSnapshot — was a 30s setInterval that
    // burned ~120 reads/hour per user and needed clearInterval semantics
    // hidden inside profileUnsubscribe (a misnomer for setInterval handle).
    // Now: real-time, free, and stops on signOut via the same handle.
    if (profileUnsubscribe) {
      // Could be either an interval id (legacy) or an unsubscribe fn (new) —
      // try both shapes safely.
      try { typeof profileUnsubscribe === 'function' ? profileUnsubscribe() : clearInterval(profileUnsubscribe); } catch(e) {}
      profileUnsubscribe = null;
    }
    profileUnsubscribe = onSnapshot(doc(db, 'users', uid), (refreshSnap) => {
      if (!refreshSnap.exists()) return;
      const newData = refreshSnap.data();
      // Was previously gating on `health` JSON only — every other field
      // (activePlanId, teamId, teamName, displayName, isCoach, year/tier,
      // notification prefs, coach Pro entitlement) was silently ignored
      // until a manual page reload. So an admin's plan reassignment, a
      // co-coach promotion, even renaming the team didn't reflect on
      // the user's open session.
      // Coach Pro paywall was removed — no longer watching coachPro* keys.
      const importantKeys = [
        'health', 'activePlanId', 'teamId', 'teamName', 'displayName',
        'isCoach', 'yearLevel', 'fitnessLevel', 'role',
        'notificationPrefs', 'tutorialSeen',
      ];
      const oldKey = importantKeys.map(k => JSON.stringify(userProfile?.[k] ?? null)).join('|');
      const newKey = importantKeys.map(k => JSON.stringify(newData?.[k] ?? null)).join('|');
      if (oldKey !== newKey) {
        userProfile = newData;
        // Re-render whichever surface depends on this profile field.
        try { renderCurrentPage(); } catch(e) {}
      }
    }, (err) => { console.warn('profile listener:', err); });
  } catch(e) {
    console.error('Load profile error:', e);
    userProfile = {
      displayName: currentUser?.displayName || 'User',
      email: currentUser?.email || '',
      yearLevel: 'Y7',
      fitnessLevel: 'basic',
      activePlanId: null
    };
  }
}

// Auto-place a signed-in athlete into the default team when they have no
// team yet, AND self-heal the case where the user has a teamId set on
// their profile but isn't actually in the team's `members[]` array — a
// drift state that breaks every team-scoped Firestore rule (chat sends,
// roster reads, etc.). Re-adding their uid is permitted by the team
// update rule for self-join.
async function ensureDefaultTeamMembership() {
  if (!db || !currentUser || !userProfile) return;
  // Path A: user has a teamId — make sure they're in members[].
  // (This branch runs for every role including parent — earlier
  // versions skipped parent and they were stuck with permission-denied
  // toasts forever if they drifted out of members[].)
  if (userProfile.teamId) {
    try {
      const tref = doc(db, 'teams', userProfile.teamId);
      const tsnap = await getDoc(tref);
      if (!tsnap.exists()) {
        // Team was deleted out from under them — clear their teamId so
        // the join-team UI re-appears next render.
        await updateDoc(doc(db, 'users', currentUser.uid), { teamId: null, teamName: null });
        userProfile.teamId = null;
        userProfile.teamName = null;
        console.warn('[auto-join] team referenced by profile no longer exists; cleared teamId.');
        return;
      }
      const td = tsnap.data();
      const members = Array.isArray(td.members) ? td.members : [];
      if (!members.includes(currentUser.uid)) {
        console.warn('[auto-join] uid missing from team.members; adding.', { teamId: userProfile.teamId, uid: currentUser.uid });
        await updateDoc(tref, { members: arrayUnion(currentUser.uid) });
        // Drop the stale 5-minute team cache so the next loadTeamData
        // pulls fresh members[] including this uid.
        try {
          localStorage.removeItem('tp_team_' + userProfile.teamId);
          localStorage.removeItem('tp_team_ts_' + userProfile.teamId);
        } catch(e) {}
      }
      // Mirror the team name back onto the user profile if it drifted.
      if (td.name && td.name !== userProfile.teamName) {
        await updateDoc(doc(db, 'users', currentUser.uid), { teamName: td.name });
        userProfile.teamName = td.name;
      }
    } catch(e) { console.warn('[auto-join] members self-heal failed:', e); }
    return;
  }
  // Path B: no team — drop them into the default team. Skip coach +
  // parent accounts because they manage their own membership.
  if (userProfile.isCoach) return;
  if (userProfile.role === 'parent') return;
  const tid = (globalSettings && globalSettings.defaultTeamId) || DEFAULT_TEAM_ID;
  if (!tid) return;
  try {
    const teamSnap = await getDoc(doc(db, 'teams', tid));
    if (!teamSnap.exists()) return;
    const td = teamSnap.data();
    await updateDoc(doc(db, 'teams', tid), { members: arrayUnion(currentUser.uid) });
    await updateDoc(doc(db, 'users', currentUser.uid), { teamId: tid, teamName: td.name });
    userProfile.teamId = tid;
    userProfile.teamName = td.name;
  } catch(e) {
    console.warn('[auto-join] default team failed:', e);
  }
}

/// Lazy-load SheetJS (xlsx.js) from a CDN. We don't bundle it — it's
/// ~600KB minified and only used on the rare Excel-export tap. Returns
/// the global XLSX once loaded; rejects if the network is offline.
function _loadSheetJS() {
  if (window.XLSX) return Promise.resolve(window.XLSX);
  if (window._xlsxLoading) return window._xlsxLoading;
  window._xlsxLoading = new Promise((resolve, reject) => {
    const s = document.createElement('script');
    s.src = 'https://cdn.jsdelivr.net/npm/xlsx@0.20.3/dist/xlsx.full.min.js';
    s.onload = () => window.XLSX ? resolve(window.XLSX) : reject(new Error('XLSX load: global missing'));
    s.onerror = () => reject(new Error('XLSX load: network'));
    document.head.appendChild(s);
  });
  return window._xlsxLoading;
}

/// Export today's race-day data to a multi-sheet Excel workbook:
/// (1) Stints summary, (2) per-stint lap times, (3) pit log. Triggers
/// a browser download. Tap target lives on the post-stint sheet + the
/// race-day overlay header.
async function exportRaceDayExcel(opts = {}) {
  if (!db || !currentUser) {
    showToast('Sign in to export.', 'info');
    return;
  }
  const dateKey = opts.dateKey || (() => {
    const d = new Date();
    return d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-' + String(d.getDate()).padStart(2,'0');
  })();
  showLoading('Building Excel…');
  try {
    const XLSX = await _loadSheetJS();
    // Pull every stint from today across the whole team.
    let stints = [];
    try {
      const snap = await getDocs(collection(db, 'race_day', dateKey, 'stints'));
      stints = snap.docs.map(d => ({ id: d.id, ...d.data() }));
    } catch(e) { console.warn('Excel: stints read failed:', e); }
    if (stints.length === 0) {
      hideLoading();
      showToast('No stints recorded today.', 'info');
      return;
    }
    const fmtMs = (ms) => {
      if (!ms || !isFinite(ms)) return '—';
      const m = Math.floor(ms / 60000);
      const s = Math.floor((ms % 60000) / 1000);
      const cs = Math.floor((ms % 1000) / 10);
      return m > 0 ? `${m}:${String(s).padStart(2,'0')}.${String(cs).padStart(2,'0')}`
                   : `${s}.${String(cs).padStart(2,'0')}s`;
    };
    const fmtSec = (sec) => {
      if (!sec || !isFinite(sec)) return '—';
      const m = Math.floor(sec / 60);
      const s = Math.floor(sec % 60);
      return `${m}:${String(s).padStart(2,'0')}`;
    };

    // Sheet 1 — stint summary, one row per rider stint.
    const summary = stints.map(s => {
      const laps = Array.isArray(s.laps) ? s.laps : [];
      const lapMs = laps.map(l => Number(l.duration) || 0).filter(n => n > 0);
      const best = lapMs.length ? Math.min(...lapMs) : null;
      const avg = lapMs.length ? Math.round(lapMs.reduce((a,b)=>a+b,0) / lapMs.length) : null;
      const startMs = s.startTime || (s.lastWatchStintAt && Number(s.lastWatchStintAt));
      const endMs = s.endTime || s.lastWatchStintAt;
      return {
        Rider: s.displayName || '—',
        UID: s.uid || '—',
        'Started at': startMs ? new Date(Number(startMs)).toLocaleString('en-AU') : '—',
        Duration: s.duration ? fmtSec(s.duration / 1000) : '—',
        Laps: laps.length,
        'Best lap': fmtMs(best),
        'Avg lap': fmtMs(avg),
        'Pit stops': s.pitStops || 0,
        Position: s.finishPosition || '—',
        RPE: s.rpe || '—',
        Notes: s.notes || '',
      };
    });

    // Sheet 2 — per-lap detail across all riders.
    const lapsRows = [];
    stints.forEach(s => {
      const laps = Array.isArray(s.laps) ? s.laps : [];
      laps.forEach((l, i) => {
        lapsRows.push({
          Rider: s.displayName || '—',
          'Lap #': l.number || (i + 1),
          Duration: fmtMs(Number(l.duration) || 0),
          'Duration (ms)': Number(l.duration) || 0,
          'Recorded at': l.recordedAt ? new Date(Number(l.recordedAt)).toLocaleTimeString('en-AU') : '—',
          Source: l.source || '—',
        });
      });
    });

    // Sheet 3 — pit log (timestamps if available).
    const pitRows = [];
    stints.forEach(s => {
      const pitTs = Array.isArray(s.pitTimestamps) ? s.pitTimestamps : [];
      const count = s.pitStops || pitTs.length;
      if (count === 0) return;
      if (pitTs.length > 0) {
        pitTs.forEach((t, i) => {
          pitRows.push({
            Rider: s.displayName || '—',
            'Pit #': i + 1,
            'Time': new Date(Number(t)).toLocaleTimeString('en-AU'),
          });
        });
      } else {
        // Count without timestamps — write a single-row summary.
        pitRows.push({ Rider: s.displayName || '—', 'Pit #': '1..' + count, 'Time': '(count only)' });
      }
    });

    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(summary), 'Stints');
    XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(lapsRows.length ? lapsRows : [{Note:'No laps recorded'}]), 'Laps');
    XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(pitRows.length ? pitRows : [{Note:'No pit stops recorded'}]), 'Pit Log');
    const teamName = (teamData?.name || userProfile?.teamName || 'team').replace(/[^a-z0-9]/gi, '-').toLowerCase();
    const fname = `raceday-${teamName}-${dateKey}.xlsx`;
    XLSX.writeFile(wb, fname);
    hideLoading();
    showToast('Excel downloaded.', 'success');
  } catch(e) {
    hideLoading();
    console.error('Race day Excel export failed:', e);
    showToast('Couldn\'t build the Excel file. Check your connection.', 'error');
  }
}

