/// Plan reveal modal (#1, Shred-inspired) — animated reveal of the
/// matched plan based on year level + tier + race target. Demo-friendly
/// "your plan: <name>" hero moment that drops the user straight into
/// Today via the CTA. Uses existing matching logic from welcome flow.
function showPlanRevealModal() {
  document.getElementById('plan-reveal-modal')?.remove();
  const year = userProfile?.yearLevel || 'Y9';
  const tier = userProfile?.fitnessLevel || 'basic';
  // Match in priority order: floor + year + tier, then year + tier, then tier, fallback first.
  const match = ALL_PLANS.find(p => p.yearLevel === year && p.tier === tier && p.category === 'floor')
    || ALL_PLANS.find(p => p.yearLevel === year && p.tier === tier)
    || ALL_PLANS.find(p => p.tier === tier)
    || ALL_PLANS[0];
  if (!match) { showToast('Could not find a matching plan.', 'warn'); return; }
  const pd = (typeof getPlanDisplayData === 'function') ? getPlanDisplayData(match) : { name: match.id };
  const phase = (typeof computeRacePhase === 'function') ? computeRacePhase() : null;
  const raceName = phase?.race ? (phase.race.name || '').replace(/^Vic HPR /, '') : null;
  const daysOut = phase?.daysOut;
  const weekCount = match.weekCount || match.weeks || (Array.isArray(match.workouts) ? Math.max(...match.workouts.map(w => w.week || 1)) : 0);
  const targetLine = raceName
    ? `${weekCount}-week build to <strong>${escHtml(raceName)}</strong>${daysOut != null ? ' · ' + daysOut + 'd to go' : ''}`
    : `${weekCount}-week training block`;
  const ov = document.createElement('div');
  ov.id = 'plan-reveal-modal';
  ov.style.cssText = 'position:fixed;inset:0;z-index:206;background:rgba(0,0,0,.85);display:flex;align-items:center;justify-content:center;padding:24px;animation:planRevealFade .3s ease-out';
  ov.innerHTML = `
    <style>
      @keyframes planRevealFade{from{opacity:0}to{opacity:1}}
      @keyframes planRevealPop{0%{opacity:0;transform:scale(.86) translateY(20px)}60%{transform:scale(1.04) translateY(-4px)}100%{opacity:1;transform:scale(1) translateY(0)}}
    </style>
    <div style="max-width:380px;width:100%;background:linear-gradient(135deg, rgba(var(--primary-rgb),.18), rgba(var(--primary-rgb),.04));border:1px solid rgba(var(--primary-rgb),.4);border-radius:22px;padding:28px 22px 22px;text-align:center;animation:planRevealPop .55s cubic-bezier(.34,1.56,.64,1);box-shadow:0 20px 60px rgba(0,0,0,.6)">
      <div style="font-size:11px;font-weight:800;letter-spacing:.18em;color:var(--primary);text-transform:uppercase;margin-bottom:8px">YOUR PLAN</div>
      <div style="font-size:30px;font-weight:800;color:var(--fg);letter-spacing:-.01em;line-height:1.15;margin-bottom:10px">${escHtml(pd.name || match.id)}</div>
      <div style="font-size:14px;color:var(--muted-fg);margin-bottom:16px">${targetLine}</div>
      <div style="display:flex;flex-wrap:wrap;justify-content:center;gap:6px;margin-bottom:22px">
        <span style="font-size:10.5px;font-weight:800;letter-spacing:.06em;padding:5px 11px;border-radius:99px;background:rgba(255,255,255,.07);border:1px solid var(--border);color:var(--muted-fg)">YEAR ${escHtml(match.yearLevel || '—')}</span>
        <span style="font-size:10.5px;font-weight:800;letter-spacing:.06em;padding:5px 11px;border-radius:99px;background:rgba(255,255,255,.07);border:1px solid var(--border);color:var(--muted-fg)">${escHtml((match.tier || 'standard').toUpperCase())}</span>
        <span style="font-size:10.5px;font-weight:800;letter-spacing:.06em;padding:5px 11px;border-radius:99px;background:rgba(255,255,255,.07);border:1px solid var(--border);color:var(--muted-fg)">${escHtml((match.category || 'mixed').replace('_',' ').toUpperCase())}</span>
      </div>
      <button id="plan-reveal-activate" style="width:100%;padding:14px;border-radius:12px;background:var(--primary);color:var(--primary-fg);border:none;font-weight:800;font-size:15px;cursor:pointer;margin-bottom:8px;letter-spacing:.01em">Start this plan →</button>
      <button id="plan-reveal-close" style="width:100%;padding:10px;background:transparent;border:none;color:var(--muted-fg);font-weight:600;font-size:12px;cursor:pointer">Maybe later</button>
    </div>
  `;
  document.body.appendChild(ov);
  const close = () => ov.remove();
  ov.addEventListener('click', (e) => { if (e.target === ov) close(); });
  ov.querySelector('#plan-reveal-close')?.addEventListener('click', close);
  ov.querySelector('#plan-reveal-activate')?.addEventListener('click', async () => {
    haptic('medium');
    try {
      await activatePlan(match.id);
      showToast('Plan activated!', 'success');
    } catch (_) {}
    close();
    try { switchPage('today'); } catch(_) {}
  });
}

/// Race-report preview sheet. After a coach uploads an xlsx, this shows
/// the parsed stints + lap chart + AI brief and lets them confirm the
/// push. Push routes to: race_archive/{raceId}/years/{year}/teams/{teamId}
/// plus per-rider users/{uid}/race_notes/{raceId}.
function openRaceReportPreview(parsed, fileName) {
  document.getElementById('rr-preview-bd')?.remove();
  const raceIdGuess = (parsed.title || 'race').toLowerCase()
    .replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '').slice(0, 48) || 'race';
  const yearGuess = new Date().getFullYear();
  const bd = document.createElement('div');
  bd.id = 'rr-preview-bd';
  bd.style.cssText = 'position:fixed;inset:0;z-index:9200;background:rgba(0,0,0,.55);backdrop-filter:blur(8px);-webkit-backdrop-filter:blur(8px);display:flex;align-items:flex-end;justify-content:center;padding:20px';
  document.body.appendChild(bd);
  const sortedRiders = (parsed.riderData || []).slice().sort((a, b) => (b.lapsTotal || 0) - (a.lapsTotal || 0));
  bd.innerHTML = `
    <div role="dialog" aria-label="Race report preview" style="background:var(--bg);border-radius:24px;width:100%;max-width:520px;max-height:90vh;padding:20px 20px 16px;overflow-y:auto;box-shadow:0 -16px 60px rgba(0,0,0,.4)">
      <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:10px;margin-bottom:10px">
        <div style="flex:1;min-width:0">
          <div style="font-size:10px;font-weight:800;letter-spacing:.14em;color:var(--primary);text-transform:uppercase">Race report</div>
          <div style="font-size:20px;font-weight:900;color:var(--fg);line-height:1.2;margin-top:4px">${escHtml(parsed.title || 'Race')}</div>
          <div style="font-size:12px;color:var(--muted-fg);margin-top:2px">${escHtml(parsed.sub || '')}  ·  ${parsed.stints.length} stints  ·  ${parsed.totalLaps} laps</div>
        </div>
        <button id="rr-cancel" type="button" aria-label="Close" style="background:none;border:none;color:var(--muted-fg);font-size:22px;cursor:pointer;padding:0 4px;line-height:1">×</button>
      </div>
      <div style="margin-bottom:12px;padding:10px 12px;border-radius:10px;background:rgba(var(--primary-rgb),.05);border:1px solid rgba(var(--primary-rgb),.18);font-size:11px;color:var(--muted-fg)">
        Source: <span style="color:var(--fg);font-weight:600">${escHtml(fileName || 'uploaded file')}</span>
      </div>
      <div style="font-size:10px;font-weight:800;letter-spacing:.10em;color:var(--muted-fg);text-transform:uppercase;margin:14px 0 8px">Laps per rider</div>
      <div id="rr-chart"></div>
      <div style="font-size:10px;font-weight:800;letter-spacing:.10em;color:var(--muted-fg);text-transform:uppercase;margin:16px 0 6px">Stints</div>
      <div style="font-size:12px;color:var(--fg);line-height:1.5">
        ${parsed.stints.map(s => `<div style="display:flex;gap:8px;align-items:center;padding:5px 0;border-bottom:1px solid var(--border)"><span style="font-weight:800;color:var(--primary);min-width:18px">#${s.stintNumber}</span><span style="color:var(--muted-fg);min-width:96px">${escHtml(s.timeWindow)}</span><span style="font-weight:700;flex:1;min-width:0;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${escHtml(s.rider)}</span><span style="color:var(--muted-fg);font-size:11px">${s.durationMin}m</span></div>`).join('')}
      </div>
      <div style="font-size:10px;font-weight:800;letter-spacing:.10em;color:var(--muted-fg);text-transform:uppercase;margin:16px 0 6px">AI brief</div>
      <div id="rr-ai-brief" style="font-size:12.5px;color:var(--fg);line-height:1.55;padding:10px 12px;border-radius:10px;background:rgba(var(--primary-rgb),.04);border:1px solid rgba(var(--primary-rgb),.15);min-height:50px">
        <span style="color:var(--muted-fg);font-style:italic">Generating…</span>
      </div>
      <div style="display:flex;gap:8px;flex-direction:column;margin-top:18px">
        <label style="font-size:11px;color:var(--muted-fg);display:flex;flex-direction:column;gap:4px">
          Race ID
          <input id="rr-race-id" value="${escAttr(raceIdGuess)}" style="padding:8px 10px;border:1px solid var(--border);border-radius:8px;background:var(--card,transparent);color:var(--fg);font-family:var(--font-mono,monospace);font-size:12px">
        </label>
        <label style="font-size:11px;color:var(--muted-fg);display:flex;flex-direction:column;gap:4px">
          Year
          <input id="rr-race-year" type="number" min="2020" max="2099" value="${yearGuess}" style="padding:8px 10px;border:1px solid var(--border);border-radius:8px;background:var(--card,transparent);color:var(--fg);font-size:13px">
        </label>
      </div>
      <div style="display:flex;gap:8px;margin-top:16px">
        <button id="rr-cancel-2" type="button" style="flex:1;padding:12px;border-radius:12px;background:rgba(var(--fg-rgb,20,22,28),.06);border:1px solid var(--border);color:var(--fg);font-weight:700;font-size:13px;cursor:pointer">Cancel</button>
        <button id="rr-push" type="button" data-haptic="success" style="flex:2;padding:12px;border-radius:12px;background:var(--primary);color:var(--primary-fg);border:none;font-weight:800;font-size:14px;cursor:pointer">Push to archive</button>
      </div>
    </div>
  `;
  bd.querySelector('#rr-cancel').addEventListener('click', () => bd.remove());
  bd.querySelector('#rr-cancel-2').addEventListener('click', () => bd.remove());
  bd.addEventListener('click', (e) => { if (e.target === bd) bd.remove(); });
  // Paint chart
  window.RaceReport.renderChart({ ...parsed, riderData: sortedRiders }, bd.querySelector('#rr-chart'));
  // AI brief — fire async, fill when it lands
  window.RaceReport.requestAiBrief(parsed).then(text => {
    const el = bd.querySelector('#rr-ai-brief');
    if (!el) return;
    if (text) el.textContent = text;
    else el.innerHTML = '<span style="color:var(--muted-fg);font-style:italic">AI brief unavailable — push without it or check your connection.</span>';
  });
  // Push
  bd.querySelector('#rr-push').addEventListener('click', async () => {
    const raceId = (bd.querySelector('#rr-race-id').value || raceIdGuess).trim();
    const raceYear = parseInt(bd.querySelector('#rr-race-year').value, 10) || yearGuess;
    if (!teamData?.id) { showToast?.('Join a team first.', 'warn'); return; }
    try {
      const result = await window.RaceReport.pushRaceReport({
        parsed, raceId, raceYear,
        teamId: teamData.id,
        teamMembers,
        fb: { db, doc, collection, setDoc, serverTimestamp },
      });
      bd.remove();
      const tag = result.unmatched.length
        ? `Race saved · ${result.notesWritten}/${result.totalRiders} matched · unmatched: ${result.unmatched.join(', ')}`
        : `Race saved · ${result.notesWritten}/${result.totalRiders} riders auto-linked to profiles`;
      showToast?.(tag, 'success');
    } catch (err) {
      console.warn('Push race report failed:', err);
      showToast?.('Push failed: ' + (err?.message || 'check rules'), 'error');
    }
  });
}

/// Archive browser — lists every race report this team has uploaded.
/// Walks race_archive/{raceId}/years/{year}/teams/{teamId}, which is
/// where pushRaceReport writes. Tapping an entry re-opens the preview
/// modal so the coach can re-view the chart + stints + AI brief.
async function openRaceReportArchive() {
  if (!teamData?.id) { showToast?.('Join a team first.', 'warn'); return; }
  document.getElementById('rr-arch-bd')?.remove();
  const bd = document.createElement('div');
  bd.id = 'rr-arch-bd';
  bd.style.cssText = 'position:fixed;inset:0;z-index:9200;background:rgba(0,0,0,.55);backdrop-filter:blur(8px);-webkit-backdrop-filter:blur(8px);display:flex;align-items:flex-end;justify-content:center;padding:20px';
  bd.innerHTML = `
    <div role="dialog" aria-label="Past race reports" style="background:var(--bg);border-radius:24px;width:100%;max-width:520px;max-height:90vh;padding:20px;overflow-y:auto;box-shadow:0 -16px 60px rgba(0,0,0,.4)">
      <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:14px">
        <div><div style="font-size:10px;font-weight:800;letter-spacing:.14em;color:var(--primary);text-transform:uppercase">Race archive</div>
        <div style="font-size:20px;font-weight:900;color:var(--fg);line-height:1.2;margin-top:4px">Past race reports</div>
        <div style="font-size:11.5px;color:var(--muted-fg);margin-top:4px">${escHtml(teamData.name || 'Team')}</div></div>
        <button id="rra-cancel" type="button" aria-label="Close" style="background:none;border:none;color:var(--muted-fg);font-size:22px;cursor:pointer;padding:0 4px">×</button>
      </div>
      <div id="rra-list"><div style="padding:30px 0;text-align:center;color:var(--muted-fg);font-size:13px"><div class="spinner" style="margin:0 auto 10px"></div>Loading…</div></div>
    </div>
  `;
  document.body.appendChild(bd);
  bd.addEventListener('click', (e) => { if (e.target === bd) bd.remove(); });
  bd.querySelector('#rra-cancel').addEventListener('click', () => bd.remove());
  // Walk race_archive collection-group style — Firestore doesn't allow
  // truly "all teams across all years" in one query without an index,
  // so we read year by year (last 3 years) and filter for THIS team.
  try {
    if (!db) { bd.querySelector('#rra-list').innerHTML = '<div style="color:var(--muted-fg);text-align:center;padding:30px">Database offline.</div>'; return; }
    const thisYear = new Date().getFullYear();
    const years = [thisYear, thisYear - 1, thisYear - 2];
    const entries = [];
    // List all race documents under race_archive
    const raceSnap = await getDocs(collection(db, 'race_archive'));
    await Promise.all(raceSnap.docs.map(async (raceDoc) => {
      for (const y of years) {
        try {
          const teamDoc = await getDoc(doc(db, 'race_archive', raceDoc.id, 'years', String(y), 'teams', teamData.id));
          if (teamDoc.exists()) {
            entries.push({ raceId: raceDoc.id, year: y, ...teamDoc.data() });
          }
        } catch(_) {}
      }
    }));
    entries.sort((a, b) => (b.createdAt?.toMillis?.() || 0) - (a.createdAt?.toMillis?.() || 0));
    const listEl = bd.querySelector('#rra-list');
    if (!entries.length) {
      listEl.innerHTML = `<div style="padding:30px 14px;text-align:center;color:var(--muted-fg);font-size:13px;line-height:1.5">
        No race reports uploaded yet.<br>
        <span style="font-size:11px">Upload one from this tab and it lands here automatically.</span>
      </div>`;
      return;
    }
    listEl.innerHTML = entries.map((e, i) => `
      <button data-rra-idx="${i}" type="button" style="display:block;width:100%;padding:12px 14px;margin-bottom:8px;background:var(--card,rgba(var(--fg-rgb,20,22,28),.04));border:1px solid var(--border);border-radius:12px;cursor:pointer;text-align:left">
        <div style="display:flex;justify-content:space-between;align-items:baseline;gap:8px">
          <div style="font-size:14px;font-weight:800;color:var(--fg);min-width:0;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${escHtml(e.raceName || e.raceId)}</div>
          <div style="font-size:10px;font-weight:700;color:var(--muted-fg);letter-spacing:.06em">${e.year}</div>
        </div>
        <div style="font-size:11.5px;color:var(--muted-fg);margin-top:4px">${e.stintCount || 0} stints · ${e.totalLaps || 0} laps · ${(e.drivers || []).length} riders</div>
        ${e.summary ? `<div style="font-size:11.5px;color:var(--fg);margin-top:6px;line-height:1.4">${escHtml(e.summary)}</div>` : ''}
      </button>
    `).join('');
    listEl.querySelectorAll('[data-rra-idx]').forEach(btn => {
      btn.addEventListener('click', () => {
        const e = entries[parseInt(btn.dataset.rraIdx, 10)];
        if (!e) return;
        bd.remove();
        // Reconstruct the parsed shape the preview modal expects.
        const parsed = {
          title: e.raceName || e.raceId,
          sub: e.schedule || '',
          stints: e.stints || [],
          riderData: (e.drivers || []).map((d, i) => ({
            riderNumber: i + 1,
            name: d.name,
            foamMm: d.foamMm,
            headRest: d.headRest,
            posIn: d.posIn,
            posOut: d.posOut,
            lapTally: d.laps != null ? String(d.laps) : null,
            lapsPrimary: d.laps,
            lapsBonus: 0,
            lapsTotal: d.laps,
            conditions: d.conditions,
            delays: d.delays,
            notes: d.notes,
          })),
          totalLaps: e.totalLaps || 0,
        };
        openRaceReportPreview(parsed, `${e.raceId} (archived ${e.year})`);
      });
    });
  } catch (err) {
    bd.querySelector('#rra-list').innerHTML = `<div style="padding:30px 14px;text-align:center;color:var(--destructive);font-size:13px">Couldn't load: ${escHtml(err?.message || 'unknown')}</div>`;
  }
}

/// Blank template builder. Picks a subteam (or whole team), lets the
/// coach drag-reorder riders so stint #1 = the rider they want first,
/// then writes the xlsx to the device.
function openRaceReportTemplateBuilder() {
  if (!teamData?.id) { showToast?.('Join a team first.', 'warn'); return; }
  document.getElementById('rr-tmpl-bd')?.remove();
  const subs = Array.isArray(teamData.subteams) ? teamData.subteams : [];
  let chosenScope = subs.length ? subs[0].id : 'all';
  let raceName = '';
  let stintCount = 8;
  let stintMin = 45;
  let startTime = '10:00 AM';
  let order = [];                  // uids in user-chosen order

  function membersForScope() {
    if (chosenScope === 'all') return (teamMembers || []).slice();
    const sub = subs.find(s => s.id === chosenScope);
    if (!sub) return [];
    const set = new Set(sub.members || []);
    return (teamMembers || []).filter(m => set.has(m.uid));
  }
  function syncOrderToScope() {
    const m = membersForScope();
    const inScope = new Set(m.map(x => x.uid));
    order = order.filter(uid => inScope.has(uid));
    m.forEach(x => { if (!order.includes(x.uid)) order.push(x.uid); });
  }
  syncOrderToScope();

  const bd = document.createElement('div');
  bd.id = 'rr-tmpl-bd';
  bd.style.cssText = 'position:fixed;inset:0;z-index:9200;background:rgba(0,0,0,.55);backdrop-filter:blur(8px);-webkit-backdrop-filter:blur(8px);display:flex;align-items:flex-end;justify-content:center;padding:20px';
  document.body.appendChild(bd);

  function render() {
    const m = membersForScope();
    const byUid = Object.fromEntries(m.map(x => [x.uid, x]));
    bd.innerHTML = `
      <div role="dialog" aria-label="Generate blank race report" style="background:var(--bg);border-radius:24px;width:100%;max-width:520px;max-height:90vh;padding:20px;overflow-y:auto;box-shadow:0 -16px 60px rgba(0,0,0,.4)">
        <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:10px;margin-bottom:12px">
          <div><div style="font-size:10px;font-weight:800;letter-spacing:.14em;color:var(--primary);text-transform:uppercase">Race template</div>
          <div style="font-size:20px;font-weight:900;color:var(--fg);line-height:1.2;margin-top:4px">Blank race report</div></div>
          <button id="rrt-cancel" type="button" aria-label="Close" style="background:none;border:none;color:var(--muted-fg);font-size:22px;cursor:pointer;padding:0 4px">×</button>
        </div>

        <label style="font-size:11px;color:var(--muted-fg);display:flex;flex-direction:column;gap:4px;margin-bottom:10px">
          Race name
          <input id="rrt-name" value="${escAttr(raceName)}" placeholder="e.g. Casey Fields — Race #2" style="padding:9px 10px;border:1px solid var(--border);border-radius:8px;background:var(--card,transparent);color:var(--fg);font-size:13px">
        </label>

        ${subs.length ? `<label style="font-size:11px;color:var(--muted-fg);display:flex;flex-direction:column;gap:4px;margin-bottom:10px">
          Subteam
          <select id="rrt-scope" style="padding:9px 10px;border:1px solid var(--border);border-radius:8px;background:var(--card,transparent);color:var(--fg);font-size:13px">
            ${subs.map(s => `<option value="${escAttr(s.id)}"${s.id === chosenScope ? ' selected' : ''}>${escHtml(s.name)} (${(s.members || []).length})</option>`).join('')}
            <option value="all"${chosenScope === 'all' ? ' selected' : ''}>Whole team (${(teamMembers || []).length})</option>
          </select>
        </label>` : ''}

        <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px;margin-bottom:14px">
          <label style="font-size:11px;color:var(--muted-fg);display:flex;flex-direction:column;gap:4px">
            Stints
            <input id="rrt-count" type="number" min="1" max="20" value="${stintCount}" style="padding:9px 10px;border:1px solid var(--border);border-radius:8px;background:var(--card,transparent);color:var(--fg);font-size:13px">
          </label>
          <label style="font-size:11px;color:var(--muted-fg);display:flex;flex-direction:column;gap:4px">
            Min each
            <input id="rrt-min" type="number" min="10" max="180" value="${stintMin}" style="padding:9px 10px;border:1px solid var(--border);border-radius:8px;background:var(--card,transparent);color:var(--fg);font-size:13px">
          </label>
          <label style="font-size:11px;color:var(--muted-fg);display:flex;flex-direction:column;gap:4px">
            Start
            <input id="rrt-start" type="text" value="${escAttr(startTime)}" style="padding:9px 10px;border:1px solid var(--border);border-radius:8px;background:var(--card,transparent);color:var(--fg);font-size:13px">
          </label>
        </div>

        <div style="font-size:10px;font-weight:800;letter-spacing:.10em;color:var(--muted-fg);text-transform:uppercase;margin:14px 0 6px">Stint order — drag to reorder</div>
        <div id="rrt-list" style="display:flex;flex-direction:column;gap:4px;max-height:36vh;overflow-y:auto;padding:4px;border:1px solid var(--border);border-radius:10px">
          ${order.map((uid, i) => {
            const m = byUid[uid];
            if (!m) return '';
            return `
              <div data-uid="${escAttr(uid)}" draggable="true" style="display:flex;align-items:center;gap:8px;padding:9px 10px;background:var(--card,rgba(var(--fg-rgb,20,22,28),.04));border:1px solid var(--border);border-radius:8px;cursor:grab">
                <span style="font-size:11px;font-weight:800;color:var(--primary);min-width:24px">#${i + 1}</span>
                <span style="flex:1;min-width:0;font-weight:700;font-size:13px;color:var(--fg);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${escHtml(m.displayName || '?')}</span>
                <span style="font-size:10.5px;color:var(--muted-fg)">${escHtml(m.yearLevel || '')}</span>
                <button type="button" data-move-up="${escAttr(uid)}" style="background:none;border:none;color:var(--muted-fg);cursor:pointer;padding:2px 6px;font-size:14px" aria-label="Move up">↑</button>
                <button type="button" data-move-dn="${escAttr(uid)}" style="background:none;border:none;color:var(--muted-fg);cursor:pointer;padding:2px 6px;font-size:14px" aria-label="Move down">↓</button>
              </div>`;
          }).join('')}
        </div>

        <div style="display:flex;gap:8px;margin-top:16px">
          <button id="rrt-cancel-2" type="button" style="flex:1;padding:12px;border-radius:12px;background:rgba(var(--fg-rgb,20,22,28),.06);border:1px solid var(--border);color:var(--fg);font-weight:700;font-size:13px;cursor:pointer">Cancel</button>
          <button id="rrt-download" type="button" data-haptic="success" style="flex:2;padding:12px;border-radius:12px;background:var(--primary);color:var(--primary-fg);border:none;font-weight:800;font-size:14px;cursor:pointer">Download .xlsx</button>
        </div>
      </div>
    `;
    // Wire input changes
    bd.querySelector('#rrt-name').addEventListener('input', e => raceName = e.target.value);
    bd.querySelector('#rrt-scope')?.addEventListener('change', e => { chosenScope = e.target.value; syncOrderToScope(); render(); });
    bd.querySelector('#rrt-count').addEventListener('input', e => { stintCount = Math.max(1, Math.min(20, parseInt(e.target.value, 10) || 8)); });
    bd.querySelector('#rrt-min').addEventListener('input', e => { stintMin = Math.max(10, Math.min(180, parseInt(e.target.value, 10) || 45)); });
    bd.querySelector('#rrt-start').addEventListener('input', e => startTime = e.target.value);
    // Move buttons
    bd.querySelectorAll('[data-move-up]').forEach(b => b.addEventListener('click', (e) => {
      e.stopPropagation();
      const uid = b.dataset.moveUp;
      const i = order.indexOf(uid);
      if (i > 0) { const tmp = order[i - 1]; order[i - 1] = order[i]; order[i] = tmp; render(); }
    }));
    bd.querySelectorAll('[data-move-dn]').forEach(b => b.addEventListener('click', (e) => {
      e.stopPropagation();
      const uid = b.dataset.moveDn;
      const i = order.indexOf(uid);
      if (i >= 0 && i < order.length - 1) { const tmp = order[i + 1]; order[i + 1] = order[i]; order[i] = tmp; render(); }
    }));
    // HTML5 drag-and-drop reorder
    let dragUid = null;
    bd.querySelectorAll('[data-uid]').forEach(row => {
      row.addEventListener('dragstart', (e) => { dragUid = row.dataset.uid; row.style.opacity = '0.4'; });
      row.addEventListener('dragend',   () => { row.style.opacity = '1'; dragUid = null; });
      row.addEventListener('dragover',  (e) => { e.preventDefault(); });
      row.addEventListener('drop', (e) => {
        e.preventDefault();
        if (!dragUid || dragUid === row.dataset.uid) return;
        const fromIdx = order.indexOf(dragUid);
        const toIdx = order.indexOf(row.dataset.uid);
        if (fromIdx < 0 || toIdx < 0) return;
        order.splice(toIdx, 0, ...order.splice(fromIdx, 1));
        render();
      });
    });
    // Buttons
    bd.querySelector('#rrt-cancel').addEventListener('click', () => bd.remove());
    bd.querySelector('#rrt-cancel-2').addEventListener('click', () => bd.remove());
    bd.querySelector('#rrt-download').addEventListener('click', async () => {
      try {
        const members = membersForScope();
        const fname = await window.RaceReport.generateBlankTemplate({
          raceName: raceName || (teamData?.name || 'Race') + ' — race report',
          teamLabel: teamData?.id || '',
          members,
          order,
          stintCount, stintMin, startTime,
        });
        bd.remove();
        showToast?.('Downloaded ' + fname, 'success');
      } catch (err) {
        console.warn('Template generate failed:', err);
        showToast?.('Could not generate: ' + (err?.message || 'unknown'), 'error');
      }
    });
  }
  bd.addEventListener('click', (e) => { if (e.target === bd) bd.remove(); });
  render();
}

function renderCoachRaceDay(el) {
  if (!el) return;
  const isActive = getRaceDayActive();
  const demoOn = isDemoRaceRunning();
  el.innerHTML = `
    <div style="text-align:center;padding:20px 16px">
      <div style="width:56px;height:56px;border-radius:16px;background:rgba(var(--primary-rgb),.1);border:1px solid rgba(var(--primary-rgb),.2);display:flex;align-items:center;justify-content:center;margin:0 auto 12px"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="width:28px;height:28px;color:var(--primary)"><path d="M4 15s1-1 4-1 5 2 8 2 4-1 4-1V3s-1 1-4 1-5-2-8-2-4 1-4 1z"/><line x1="4" y1="22" x2="4" y2="15"/></svg></div>
      <div style="font-size:18px;font-weight:700;margin-bottom:8px">${isActive ? 'Race Day is LIVE' : 'Race Day Mode'}</div>
      <div style="font-size:13px;color:var(--muted-fg);margin-bottom:20px;line-height:1.5">${isActive ? 'All team members are in race day mode. Tap below to end.' : 'Activating race day mode locks all users into the race day interface for the day.'}</div>
      ${isActive
        ? `<button id="coach-rd-end" style="width:100%;padding:14px;border-radius:12px;background:rgba(var(--destructive-rgb),.1);border:1px solid rgba(var(--destructive-rgb),.3);color:var(--destructive);font-weight:700;font-size:15px;cursor:pointer">End Race Day Mode</button>
           <button id="coach-rd-open" style="width:100%;padding:12px;border-radius:12px;background:var(--primary);color:var(--primary-fg);font-weight:700;font-size:14px;cursor:pointer;margin-top:8px">Open Race Day Interface</button>`
        : `<button id="coach-rd-start" style="width:100%;padding:14px;border-radius:12px;background:linear-gradient(135deg,var(--success),#16a34a);color:#fff;font-weight:700;font-size:15px;cursor:pointer;box-shadow:0 4px 15px rgba(var(--success-rgb),.3)">Activate Race Day Mode</button>`
      }
    </div>

    <div style="margin-top:8px;padding:14px;border-top:1px solid var(--border);display:flex;flex-direction:column;gap:8px">
      <div style="font-size:11px;font-weight:800;letter-spacing:.06em;text-transform:uppercase;color:var(--muted-fg);margin-bottom:2px">Team training</div>
      <div style="font-size:12.5px;color:var(--muted-fg);line-height:1.45">Broadcast a training session to every athlete on the team. They get a push notification + the Start Training button is highlighted on their Today page.</div>
      <button id="coach-team-train-start" data-haptic="medium" style="padding:11px;border-radius:10px;background:var(--primary);color:var(--primary-fg);border:none;font-weight:700;font-size:13px;cursor:pointer">Start team training now</button>
    </div>

    <div style="margin-top:8px;padding:14px;border-top:1px solid var(--border);display:flex;flex-direction:column;gap:8px">
      <div style="font-size:11px;font-weight:800;letter-spacing:.06em;text-transform:uppercase;color:var(--muted-fg);margin-bottom:2px">Race reports</div>
      <div style="font-size:12.5px;color:var(--muted-fg);line-height:1.45">Upload a completed Excel race report — the app extracts every stint, attaches per-rider notes to their public profile, and pushes a copy to the race archive. Or generate a blank template pre-filled with your subteam.</div>
      <input id="rr-file-input" type="file" accept=".xlsx,.xls,.csv" style="display:none">
      <div style="display:flex;gap:8px;flex-wrap:wrap">
        <button id="rr-upload-btn" data-haptic="medium" style="flex:1;min-width:140px;padding:11px;border-radius:10px;background:var(--primary);color:var(--primary-fg);border:none;font-weight:700;font-size:13px;cursor:pointer">Upload race report</button>
        <button id="rr-template-btn" style="flex:1;min-width:140px;padding:11px;border-radius:10px;background:transparent;border:1px solid var(--border);color:var(--fg);font-weight:700;font-size:13px;cursor:pointer">Blank template</button>
      </div>
      <button id="rr-list-btn" style="margin-top:6px;padding:9px;border-radius:10px;background:transparent;border:1px solid var(--border);color:var(--fg);font-weight:600;font-size:12px;cursor:pointer;display:flex;align-items:center;justify-content:center;gap:6px">
        <svg viewBox="0 0 24 24" width="13" height="13" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M3 3h18v18H3z"/><path d="M3 9h18M3 15h18M9 3v18M15 3v18"/></svg>
        View past race reports
      </button>
    </div>

    <div style="margin-top:8px;padding:14px;border-top:1px solid var(--border);display:flex;flex-direction:column;gap:8px">
      <div style="font-size:11px;font-weight:800;letter-spacing:.06em;text-transform:uppercase;color:var(--muted-fg);margin-bottom:2px">Spectator link</div>
      <div style="font-size:12.5px;color:var(--muted-fg);line-height:1.45">Share the live race-day spectator view with parents and supporters.</div>
      <button id="coach-demo-link" style="padding:9px;border-radius:10px;background:transparent;border:1px solid var(--border);color:var(--fg);font-weight:600;font-size:12px;cursor:pointer">Copy spectator link</button>
    </div>

  `;
  el.querySelector('#coach-rd-start')?.addEventListener('click', async () => {
    const ok = await activateRaceDay();
    if (ok) {
      try { pushWatchState(); } catch(e) {}
      showToast('Race day activated!','success');
      openRaceDayOverlay();
    }
  });
  el.querySelector('#coach-rd-end')?.addEventListener('click', async () => {
    await deactivateRaceDay();
    try { pushWatchState(); } catch(e) {}
    renderCoachPage();
  });
  el.querySelector('#coach-rd-open')?.addEventListener('click', () => openRaceDayOverlay());
  el.querySelector('#coach-demo-start')?.addEventListener('click', async () => {
    const ok = await startDemoRace();
    if (ok) renderCoachPage();
  });
  el.querySelector('#coach-demo-stop')?.addEventListener('click', async () => {
    await stopDemoRace();
    renderCoachPage();
  });
  // ── Team-wide training broadcast ─────────────────────────────────
  el.querySelector('#coach-team-train-start')?.addEventListener('click', async () => {
    if (!teamData?.id || !db) { showToast?.('Join a team first.', 'warn'); return; }
    if (!confirm('Start training for the whole team? Everyone gets a push + the Start button highlighted.')) return;
    try {
      // Write a team-wide training cue. Every athlete listens for this
      // doc (via onSnapshot in setupListeners) and surfaces the prompt.
      await setDoc(doc(db, 'teams', teamData.id, 'cues', 'training'), {
        active: true,
        startedAt: serverTimestamp(),
        startedBy: currentUser?.uid || null,
        startedByName: userProfile?.displayName || 'Coach',
        title: 'Team training',
        type: 'ride',
      });
      showToast?.('Team training started — everyone notified.', 'success');
      try { startTrainingSession({ type: 'ride', title: 'Team training' }); } catch(_) {}
    } catch (e) {
      console.warn('Team training broadcast failed:', e);
      showToast?.('Could not start: ' + (e?.message || 'check rules'), 'error');
    }
  });

  // ── Race report wiring ───────────────────────────────────────────
  const fileInput = el.querySelector('#rr-file-input');
  el.querySelector('#rr-upload-btn')?.addEventListener('click', () => fileInput?.click());
  fileInput?.addEventListener('change', async (e) => {
    const f = e.target.files?.[0];
    if (!f) return;
    showToast?.('Parsing ' + f.name + '…', 'info');
    try {
      const parsed = await window.RaceReport.parseRaceReport(f);
      openRaceReportPreview(parsed, f.name);
    } catch (err) {
      console.warn('Race report parse failed:', err);
      showToast?.('Could not parse: ' + (err?.message || 'bad format'), 'error');
    } finally {
      fileInput.value = '';
    }
  });
  el.querySelector('#rr-template-btn')?.addEventListener('click', () => openRaceReportTemplateBuilder());
  el.querySelector('#rr-list-btn')?.addEventListener('click', () => openRaceReportArchive());

  el.querySelector('#coach-demo-link')?.addEventListener('click', async () => {
    // Pass the local-AEST date so the netlify spectator function looks up
    // the right race_day/{date} doc — it defaults to the server's UTC
    // date which can be a day off from Melbourne for ~10h each day.
    const url = location.origin + '/spectate.html?date=' + encodeURIComponent(localDateKey());
    try {
      await navigator.clipboard.writeText(url);
      showToast('Spectator link copied', 'success');
    } catch(_) {
      prompt('Copy spectator link:', url);
    }
  });
}

// ── Demo race (Albert Park) ──────────────────────────────────────────────────
//
// Streams a fake live driver around an approximate Albert Park polyline so
// the spectator view can be exercised without a real rider on track.
// Writes under the CURRENT user's uid (Firestore rules require
// `isOwner(uid)` on race_day/{date}/live/{uid}, so we can't impersonate
// a 'demo-driver-001' uid). Lap times are randomised in a realistic range
// (6:30–9:00 per lap for cycling).
const ALBERT_PARK_WAYPOINTS = [
  [-37.8462, 144.9700], [-37.8470, 144.9720], [-37.8478, 144.9745],
  [-37.8492, 144.9760], [-37.8510, 144.9770], [-37.8528, 144.9772],
  [-37.8540, 144.9760], [-37.8548, 144.9740], [-37.8550, 144.9720],
  [-37.8546, 144.9700], [-37.8536, 144.9680], [-37.8520, 144.9670],
  [-37.8500, 144.9665], [-37.8480, 144.9670], [-37.8470, 144.9685],
];
let _demoRaceTimer = null;
let _demoRaceState = null;
function isDemoRaceRunning() { return !!_demoRaceTimer; }

async function startDemoRace() {
  if (!db || !currentUser) { showToast('Sign in first.', 'warn'); return false; }
  const isMaster = currentUser.email?.toLowerCase() === ADMIN_EMAIL.toLowerCase();
  // Firestore rules require isAdmin() to write race_day/{date}. The demo
  // races against the same path so a plain coach (without admin rights)
  // can't run it without rules changes — surface that clearly instead of
  // failing silently in the setDoc below.
  if (!isAdmin && !isMaster) {
    showToast('Demo race needs admin rights — Firestore rules only allow admins to activate race day.', 'warn');
    return false;
  }
  const date = localDateKey();
  try {
    // 1) Activate race-day with Albert Park as the start point. Mirrors
    //    activateRaceDay's data shape so the rest of the app treats this
    //    as a real race day; isDemo flag lets us clean up later.
    await setDoc(doc(db, 'race_day', date), {
      active: true,
      date,
      raceName: 'Demo · Albert Park',
      teamId: userProfile?.teamId || null,
      activatedBy: currentUser.uid,
      activatedAt: serverTimestamp(),
      activatedAtMs: Date.now(),
      startPoint: { lat: ALBERT_PARK_WAYPOINTS[0][0], lng: ALBERT_PARK_WAYPOINTS[0][1] },
      startPointSet: true,
      maxDurationMs: 25 * 60 * 60 * 1000,
      isDemo: true,
    }, { merge: true });
  } catch(e) {
    console.error('demo activate:', e);
    showToast('Demo activate failed: ' + (e?.message || 'unknown'), 'error');
    return false;
  }

  _demoRaceState = {
    date,
    pathIdx: 0,
    lapCount: 0,
    bestLap: null,
    lastLap: null,
    stintStart: Date.now(),
  };

  const tick = async () => {
    if (!_demoRaceState) return;
    const s = _demoRaceState;
    s.pathIdx = (s.pathIdx + 1) % ALBERT_PARK_WAYPOINTS.length;
    if (s.pathIdx === 0) {
      s.lapCount++;
      // 6:30–9:00 in ms — typical HPR / cycling lap range for Albert Park.
      s.lastLap = Math.floor((Math.random() * 150 + 390) * 1000);
      if (!s.bestLap || s.lastLap < s.bestLap) s.bestLap = s.lastLap;
    }
    const [lat, lng] = ALBERT_PARK_WAYPOINTS[s.pathIdx];
    try {
      await setDoc(doc(db, 'race_day', s.date, 'live', currentUser.uid), {
        uid: currentUser.uid,
        displayName: 'Demo Driver · Cooper',
        live: true,
        startTime: s.stintStart,
        elapsed: Date.now() - s.stintStart,
        lapCount: s.lapCount,
        bestLap: s.bestLap,
        lastLap: s.lastLap,
        coord: { lat, lng, ts: Date.now() },
        updatedAt: serverTimestamp(),
        isDemo: true,
      });
    } catch(e) { console.warn('demo tick:', e); }
  };
  await tick();
  _demoRaceTimer = setInterval(tick, 1000);
  showToast('Demo race started — open the spectator link.', 'success');
  return true;
}

async function stopDemoRace() {
  if (_demoRaceTimer) { clearInterval(_demoRaceTimer); _demoRaceTimer = null; }
  if (!db || !currentUser) { _demoRaceState = null; return; }
  const date = (_demoRaceState && _demoRaceState.date) || localDateKey();
  _demoRaceState = null;
  try {
    await setDoc(doc(db, 'race_day', date, 'live', currentUser.uid), {
      uid: currentUser.uid, live: false, updatedAt: serverTimestamp(),
    }, { merge: true });
  } catch(_) {}
  try {
    // Only flip 'active' off if THIS demo set it; never trample a real race.
    const snap = await getDoc(doc(db, 'race_day', date));
    if (snap.exists() && snap.data().isDemo) {
      await updateDoc(doc(db, 'race_day', date), { active: false });
    }
  } catch(_) {}
  showToast('Demo race stopped.', 'info');
}

function checkAdmin(email) {
  const e = (email || '').toLowerCase();
  const isMaster = e === ADMIN_EMAIL.toLowerCase();
  // Delegated admins: listed in config/adminEmails either as a bare email
  // (legacy) or as { email, perms: [...] } in adminPerms.
  const isDelegatedByEmail = Array.isArray(adminEmails)
    && adminEmails.some(x => String(x || '').toLowerCase() === e);
  const delegatedPerms = Array.isArray(adminPerms)
    ? adminPerms.find(p => p && String(p.email || '').toLowerCase() === e)
    : null;
  const isDelegated = isDelegatedByEmail || !!delegatedPerms;
  isAdmin = isMaster || isDelegated;
  currentAdminPerms = isMaster
    ? ALL_ADMIN_FEATURES.map(f => f.id)
    : (delegatedPerms?.perms || (isDelegatedByEmail ? ALL_ADMIN_FEATURES.map(f => f.id) : []));

  const studentView = localStorage.getItem('tp_student_view') === 'true';
  const adminTab = document.getElementById('admin-tab');
  if (adminTab) adminTab.style.display = (isAdmin && !studentView) ? '' : 'none';
  const coachTab = document.getElementById('coach-tab');
  const isCoach = userProfile?.isCoach === true;
  if (coachTab) coachTab.style.display = ((isCoach || isMaster) && !studentView) ? '' : 'none';
}
async function loadAdminData() {
  if (!isAdmin || !db) return;
  try {
    // Load announcements
    const annSnap = await getDoc(doc(db, 'config', 'announcements'));
    adminAnnouncements = annSnap.exists() ? (annSnap.data().items || []) : [];
    try { localStorage.setItem('tp_announcements', JSON.stringify(adminAnnouncements)); } catch(e) {}
    // Load races from Firestore
    const raceSnap = await getDoc(doc(db, 'config', 'races'));
    adminRaces = raceSnap.exists() ? (raceSnap.data().races || null) : null;
    // Load race footage, videos & exercise/plan overrides
    await loadRaceFootage();
    await loadRaceLogVideos();
    await loadExerciseOverrides();
    await loadPlanOverrides();
    await loadExerciseDemoVideos();
    // Load hidden plans
    const hpSnap = await getDoc(doc(db, 'config', 'hiddenPlans'));
    hiddenPlans = new Set(hpSnap.exists() ? (hpSnap.data().ids || []) : []);
  } catch(e) {
    console.error('Load admin data error:', e);
  }
}
async function loadAnnouncements() {
  if (!db) return;
  // Use cached announcements on load, refresh in background
  try {
    const cached = JSON.parse(localStorage.getItem('tp_announcements')||'null');
    if (cached) { adminAnnouncements = cached; renderCurrentPage(); }
  } catch(e) {}
  try {
    const annSnap = await getDoc(doc(db, 'config', 'announcements'));
    adminAnnouncements = annSnap.exists() ? (annSnap.data().items || []) : [];
  } catch(e) {
    adminAnnouncements = [];
  }
}
let lastSeenAnnId = '';
try { lastSeenAnnId = localStorage.getItem('tp_lastSeenAnn') || ''; } catch(e) {}
async function requestNotificationPermission() {
  if (!('Notification' in window)) return false;
  if (Notification.permission === 'granted') return true;
  if (Notification.permission === 'denied') return false;
  const result = await Notification.requestPermission();
  return result === 'granted';
}
function showInAppAnnouncementBanner(title, message) {
  let b = document.getElementById('tp-ann-banner');
  if (b) b.remove();
  b = document.createElement('div');
  b.id = 'tp-ann-banner';
  b.setAttribute('role', 'alert');
  b.setAttribute('aria-live', 'assertive');
  b.innerHTML = `
    <div class="tp-ann-banner-inner">
      <div class="tp-ann-banner-icon">📣</div>
      <div class="tp-ann-banner-text">
        <div class="tp-ann-banner-title">${escHtml(title || 'Announcement')}</div>
        <div class="tp-ann-banner-msg">${escHtml(message || '')}</div>
      </div>
      <button class="tp-ann-banner-close" aria-label="Dismiss">×</button>
    </div>`;
  document.body.appendChild(b);
  requestAnimationFrame(() => b.classList.add('show'));
  const close = () => {
    b.classList.remove('show');
    setTimeout(() => b.remove(), 300);
  };
  b.querySelector('.tp-ann-banner-close').addEventListener('click', close);
  setTimeout(close, 8000);
}

function showAnnouncementNotification(title, message) {
  // Always render an in-app banner (works inside WKWebView where the
  // Notification API is stripped). Try haptic so it feels like a real ping.
  showInAppAnnouncementBanner(title, message);
  try { window.tpNative?.haptic?.('medium'); } catch(e) {}
  if (!('Notification' in window) || Notification.permission !== 'granted') return;
  // Prefer service worker showNotification (required for iOS PWA)
  if (navigator.serviceWorker && navigator.serviceWorker.ready) {
    navigator.serviceWorker.ready.then(reg => {
      reg.showNotification('TurboPrep: ' + title, {
        body: message,
        icon: document.querySelector('link[rel="apple-touch-icon"]')?.href || '',
        badge: document.querySelector('link[rel="apple-touch-icon"]')?.href || '',
        tag: 'vf-announcement-' + Date.now(),
        renotify: true,
        data: { url: location.href }
      });
    }).catch(() => {
      // Fallback to Notification constructor (desktop/Android)
      try {
        const n = new Notification('TurboPrep: ' + title, {
          body: message,
          icon: document.querySelector('link[rel="apple-touch-icon"]')?.href || '',
          tag: 'vf-announcement',
          renotify: true
        });
        n.onclick = () => { window.focus(); n.close(); };
      } catch(e) {}
    });
  } else {
    try {
      const n = new Notification('TurboPrep: ' + title, {
        body: message,
        tag: 'vf-announcement',
        renotify: true
      });
      n.onclick = () => { window.focus(); n.close(); };
    } catch(e) {}
  }
  // Update app badge count if supported
  try { if (navigator.setAppBadge) navigator.setAppBadge(1); } catch(e) {}
}
function checkForNewAnnouncements(announcements) {
  if (!announcements || announcements.length === 0) return;
  const activeAnns = announcements.filter(a => a.active);
  if (activeAnns.length === 0) return;
  const latestId = activeAnns[0].id || '';
  if (latestId && latestId !== lastSeenAnnId) {
    // New announcement detected
    const a = activeAnns[0];
    showAnnouncementNotification(a.title, a.message);
    lastSeenAnnId = latestId;
    try { localStorage.setItem('tp_lastSeenAnn', latestId); } catch(e) {}
  }
}
// Listen for announcements in real-time (triggers notification for new ones)
// --- Training Session Notifications ---
// --- Health Tab (Fitness page) ---
function renderHealthTab() {
  const c = $('health-content');
  if (!c) return;
  const h = userProfile?.health || {};
  const now = new Date();
  let html = '';

  // Current stats row + manual sync button
  html += '<div style="display:flex;align-items:center;justify-content:space-between;gap:8px;margin-bottom:12px"><div class="page-title" style="margin:0">Health</div>';
  const lastSyncMs = h.lastSync ? new Date(h.lastSync).getTime() : 0;
  const ageMin = lastSyncMs ? Math.round((Date.now() - lastSyncMs) / 60000) : null;
  const stale = !lastSyncMs || ageMin > 30;
  html += `<div style="display:flex;align-items:center;gap:8px">
    ${lastSyncMs ? `<span style="font-size:11px;color:${stale ? 'var(--warning)' : 'var(--muted-fg)'}">Synced ${escHtml(timeAgo(new Date(h.lastSync)))}</span>` : '<span style="font-size:11px;color:var(--warning)">Not synced yet</span>'}
    <button id="health-resync-btn" data-haptic="medium" type="button" style="padding:5px 10px;border-radius:8px;background:${stale ? 'var(--primary)' : 'rgba(var(--primary-rgb),.10)'};color:${stale ? 'var(--primary-fg)' : 'var(--primary)'};border:1px solid ${stale ? 'var(--primary)' : 'rgba(var(--primary-rgb),.30)'};font-weight:700;font-size:11px;cursor:pointer">Sync now</button>
  </div></div>`;

  // Stat cards
  html += '<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:16px">';
  html += `<div style="text-align:center;padding:16px 8px;background:rgba(var(--destructive-rgb),.06);border:1px solid rgba(var(--destructive-rgb),.1);border-radius:12px">
    <div style="font-size:32px;font-weight:800;color:var(--destructive)">${h.latestHr || '--'}</div>
    <div style="font-size:11px;color:var(--muted-fg);margin-top:4px">❤️ Heart Rate</div>
  </div>`;
  html += `<div style="text-align:center;padding:16px 8px;background:rgba(59,130,246,.06);border:1px solid rgba(59,130,246,.1);border-radius:12px">
    <div style="font-size:32px;font-weight:800;color:#3b82f6">${h.restingHr || '--'}</div>
    <div style="font-size:11px;color:var(--muted-fg);margin-top:4px">💓 Resting HR</div>
  </div>`;
  html += `<div style="text-align:center;padding:16px 8px;background:rgba(var(--success-rgb),.06);border:1px solid rgba(var(--success-rgb),.1);border-radius:12px">
    <div style="font-size:32px;font-weight:800;color:var(--success)">${h.latestSteps ? (h.latestSteps > 999 ? (h.latestSteps/1000).toFixed(1) + 'k' : h.latestSteps) : '--'}</div>
    <div style="font-size:11px;color:var(--muted-fg);margin-top:4px">👟 Steps</div>
  </div>`;
  html += `<div style="text-align:center;padding:16px 8px;background:rgba(124,58,237,.06);border:1px solid rgba(124,58,237,.1);border-radius:12px">
    <div style="font-size:32px;font-weight:800;color:var(--purple)">${h.latestSleep ? h.latestSleep + 'h' : '--'}</div>
    <div style="font-size:11px;color:var(--muted-fg);margin-top:4px">😴 Sleep</div>
  </div>`;
  html += '</div>';

  // Heart Rate chart — from workout data
  const hrWorkouts = userWorkouts.filter(w => w.heartRate && w.heartRate > 0).slice(0, 14).reverse();
  if (hrWorkouts.length > 0) {
    const hrMax = Math.max(...hrWorkouts.map(w => w.heartRate));
    const hrMin = Math.min(...hrWorkouts.map(w => w.heartRate));
    html += `<div style="background:var(--card);border:1px solid var(--border);border-radius:12px;padding:14px;margin-bottom:12px">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:10px">
        <div style="font-size:13px;font-weight:700;color:var(--fg)">❤️ Heart Rate History</div>
        <div style="font-size:11px;color:var(--muted-fg)">Last ${hrWorkouts.length} workouts</div>
      </div>
      <div style="display:flex;align-items:center;gap:12px;margin-bottom:8px">
        <span style="font-size:11px;color:var(--muted-fg)">Avg: <strong style="color:var(--fg)">${Math.round(hrWorkouts.reduce((s,w)=>s+w.heartRate,0)/hrWorkouts.length)}</strong></span>
        <span style="font-size:11px;color:var(--muted-fg)">Low: <strong style="color:var(--success)">${hrMin}</strong></span>
        <span style="font-size:11px;color:var(--muted-fg)">High: <strong style="color:var(--destructive)">${hrMax}</strong></span>
      </div>
      <div style="display:flex;align-items:end;gap:3px;height:80px">`;
    hrWorkouts.forEach(w => {
      const pct = hrMax > hrMin ? ((w.heartRate - hrMin) / (hrMax - hrMin)) * 70 + 30 : 50;
      const color = w.heartRate > 160 ? '#ef4444' : w.heartRate > 140 ? '#f59e0b' : w.heartRate > 120 ? '#22c55e' : '#3b82f6';
      const d = w.date ? (w.date.toDate ? w.date.toDate() : new Date(w.date)) : new Date();
      html += `<div style="flex:1;display:flex;flex-direction:column;align-items:center;gap:2px">
        <div style="font-size:8px;font-weight:600;color:var(--muted-fg)">${w.heartRate}</div>
        <div style="width:100%;height:${pct}%;background:${color};border-radius:4px 4px 0 0;min-height:6px;transition:height .3s"></div>
        <div style="font-size:7px;color:var(--muted-fg)">${d.getDate()}/${d.getMonth()+1}</div>
      </div>`;
    });
    html += '</div>';
    // HR zone legend
    html += `<div style="display:flex;gap:8px;margin-top:8px;flex-wrap:wrap">
      <span style="font-size:9px;color:var(--muted-fg)"><span style="display:inline-block;width:8px;height:8px;border-radius:2px;background:#3b82f6;margin-right:3px"></span>Low &lt;120</span>
      <span style="font-size:9px;color:var(--muted-fg)"><span style="display:inline-block;width:8px;height:8px;border-radius:2px;background:var(--success);margin-right:3px"></span>Moderate 120-140</span>
      <span style="font-size:9px;color:var(--muted-fg)"><span style="display:inline-block;width:8px;height:8px;border-radius:2px;background:var(--warning);margin-right:3px"></span>Hard 140-160</span>
      <span style="font-size:9px;color:var(--muted-fg)"><span style="display:inline-block;width:8px;height:8px;border-radius:2px;background:var(--destructive);margin-right:3px"></span>Max &gt;160</span>
    </div>`;
    html += '</div>';
  }

  // Training volume chart — duration per day for last 14 days
  const days14 = [];
  for (let i = 13; i >= 0; i--) {
    const d = new Date(now); d.setDate(d.getDate() - i); d.setHours(0,0,0,0);
    const key = d.toISOString().split('T')[0];
    const dayWos = userWorkouts.filter(w => { const wd = w.date ? (w.date.toDate ? w.date.toDate() : new Date(w.date)) : null; return wd && wd.toISOString().split('T')[0] === key; });
    const mins = dayWos.reduce((s, w) => s + (w.duration || 0), 0);
    const dist = dayWos.reduce((s, w) => s + (w.distance || 0), 0);
    days14.push({ date: d, key, mins, dist, count: dayWos.length });
  }
  const maxMins = Math.max(1, ...days14.map(d => d.mins));
  html += `<div style="background:var(--card);border:1px solid var(--border);border-radius:12px;padding:14px;margin-bottom:12px">
    <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:10px">
      <div style="font-size:13px;font-weight:700;color:var(--fg)">📊 Training Volume</div>
      <div style="font-size:11px;color:var(--muted-fg)">Last 14 days</div>
    </div>
    <div style="display:flex;align-items:end;gap:2px;height:70px">`;
  days14.forEach(d => {
    const pct = d.mins > 0 ? (d.mins / maxMins) * 100 : 0;
    const isToday = d.key === now.toISOString().split('T')[0];
    html += `<div style="flex:1;display:flex;flex-direction:column;align-items:center;gap:1px">
      ${d.mins > 0 ? `<div style="font-size:7px;font-weight:600;color:var(--muted-fg)">${d.mins}</div>` : ''}
      <div style="width:100%;height:${pct}%;background:${isToday ? 'var(--primary)' : d.mins > 0 ? 'rgba(var(--primary-rgb),.4)' : 'rgba(255,255,255,.04)'};border-radius:3px 3px 0 0;min-height:${d.mins > 0 ? '6' : '2'}px"></div>
      <div style="font-size:7px;color:${isToday ? 'var(--primary)' : 'var(--muted-fg)'};font-weight:${isToday ? '700' : '400'}">${d.date.toLocaleDateString('en-AU',{weekday:'narrow'})}</div>
    </div>`;
  });
  html += '</div></div>';

  // Weekly summary stats
  const thisWeek = days14.slice(-7);
  const lastWeek = days14.slice(0, 7);
  const twMins = thisWeek.reduce((s, d) => s + d.mins, 0);
  const lwMins = lastWeek.reduce((s, d) => s + d.mins, 0);
  const twCount = thisWeek.reduce((s, d) => s + d.count, 0);
  const lwCount = lastWeek.reduce((s, d) => s + d.count, 0);
  const twDist = thisWeek.reduce((s, d) => s + d.dist, 0);
  const minsDiff = twMins - lwMins;
  html += `<div style="background:var(--card);border:1px solid var(--border);border-radius:12px;padding:14px;margin-bottom:12px">
    <div style="font-size:13px;font-weight:700;color:var(--fg);margin-bottom:10px">📈 Week Comparison</div>
    <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px">
      <div style="text-align:center">
        <div style="font-size:9px;color:var(--muted-fg);margin-bottom:4px">Sessions</div>
        <div style="font-size:20px;font-weight:800;color:var(--fg)">${twCount}</div>
        <div style="font-size:10px;color:${twCount >= lwCount ? 'var(--success)' : 'var(--destructive)'}">${twCount >= lwCount ? '↑' : '↓'} vs ${lwCount}</div>
      </div>
      <div style="text-align:center">
        <div style="font-size:9px;color:var(--muted-fg);margin-bottom:4px">Minutes</div>
        <div style="font-size:20px;font-weight:800;color:var(--fg)">${twMins}</div>
        <div style="font-size:10px;color:${minsDiff >= 0 ? 'var(--success)' : 'var(--destructive)'}">${minsDiff >= 0 ? '+' : ''}${minsDiff} min</div>
      </div>
      <div style="text-align:center">
        <div style="font-size:9px;color:var(--muted-fg);margin-bottom:4px">Distance</div>
        <div style="font-size:20px;font-weight:800;color:var(--fg)">${twDist > 0 ? twDist.toFixed(1) : '--'}</div>
        <div style="font-size:10px;color:var(--muted-fg)">${twDist > 0 ? 'km' : ''}</div>
      </div>
    </div>
  </div>`;

  // RPE effort trend
  const rpeWorkouts = userWorkouts.filter(w => w.rpe).slice(0, 14).reverse();
  if (rpeWorkouts.length >= 3) {
    html += `<div style="background:var(--card);border:1px solid var(--border);border-radius:12px;padding:14px;margin-bottom:12px">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:10px">
        <div style="font-size:13px;font-weight:700;color:var(--fg)">💪 Effort Trend (RPE)</div>
        <div style="font-size:11px;color:var(--muted-fg)">Last ${rpeWorkouts.length}</div>
      </div>
      <div style="display:flex;align-items:end;gap:3px;height:60px">`;
    rpeWorkouts.forEach(w => {
      const pct = (w.rpe / 10) * 100;
      const color = w.rpe >= 8 ? '#ef4444' : w.rpe >= 6 ? '#f59e0b' : w.rpe >= 4 ? '#22c55e' : '#3b82f6';
      const d = w.date ? (w.date.toDate ? w.date.toDate() : new Date(w.date)) : new Date();
      html += `<div style="flex:1;display:flex;flex-direction:column;align-items:center;gap:2px">
        <div style="font-size:8px;font-weight:600;color:var(--muted-fg)">${w.rpe}</div>
        <div style="width:100%;height:${pct}%;background:${color};border-radius:4px 4px 0 0;min-height:6px"></div>
        <div style="font-size:7px;color:var(--muted-fg)">${d.getDate()}/${d.getMonth()+1}</div>
      </div>`;
    });
    html += '</div></div>';
  }

  // Sync setup prompt if no health data
  if (!h.latestHr && !h.latestSteps && !h.latestSleep) {
    html += `<div style="text-align:center;padding:24px 16px;background:var(--card);border:1px solid var(--border);border-radius:12px">
      <div style="font-size:32px;margin-bottom:8px">❤️</div>
      <div style="font-size:15px;font-weight:700;color:var(--fg);margin-bottom:6px">No Health Data Yet</div>
      <div style="font-size:12px;color:var(--muted-fg);line-height:1.5;margin-bottom:12px">Connect your wearable to see heart rate, steps, and sleep data here with charts and trends.</div>
      <div style="font-size:12px;color:var(--muted-fg);line-height:1.6;text-align:left;padding:10px;background:var(--bg);border-radius:8px;margin-bottom:8px">
        <strong style="color:var(--fg)">Option 1:</strong> Connect Strava in Profile — auto-imports workouts with heart rate<br><br>
        <strong style="color:var(--fg)">Option 2:</strong> Open the TurboPrep iPhone app and grant Health permission — heart rate, steps, and sleep sync automatically from HealthKit.
      </div>
      <button class="btn btn-primary" id="health-go-profile" style="padding:10px 20px;font-size:13px">Go to Profile → Health Sync</button>
    </div>`;
  }

  // Personal bests
  const allDurations = userWorkouts.map(w => w.duration || 0).filter(d => d > 0);
  const allDistances = userWorkouts.map(w => w.distance || 0).filter(d => d > 0);
  const allSpeeds = userWorkouts.map(w => w.avgSpeed || 0).filter(s => s > 0);
  if (allDurations.length > 0 || allDistances.length > 0) {
    html += `<div style="background:var(--card);border:1px solid var(--border);border-radius:12px;padding:14px;margin-bottom:12px">
      <div style="font-size:13px;font-weight:700;color:var(--fg);margin-bottom:10px">🏆 Personal Bests</div>
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px">
        ${allDurations.length > 0 ? `<div style="padding:8px;background:var(--bg);border-radius:8px;text-align:center">
          <div style="font-size:18px;font-weight:800;color:var(--primary)">${Math.max(...allDurations)}</div>
          <div style="font-size:10px;color:var(--muted-fg)">Longest session (min)</div>
        </div>` : ''}
        ${allDistances.length > 0 ? `<div style="padding:8px;background:var(--bg);border-radius:8px;text-align:center">
          <div style="font-size:18px;font-weight:800;color:var(--primary)">${Math.max(...allDistances).toFixed(1)}</div>
          <div style="font-size:10px;color:var(--muted-fg)">Longest ride (km)</div>
        </div>` : ''}
        ${allSpeeds.length > 0 ? `<div style="padding:8px;background:var(--bg);border-radius:8px;text-align:center">
          <div style="font-size:18px;font-weight:800;color:var(--primary)">${Math.max(...allSpeeds).toFixed(1)}</div>
          <div style="font-size:10px;color:var(--muted-fg)">Top speed (km/h)</div>
        </div>` : ''}
        ${userWorkouts.length > 0 ? `<div style="padding:8px;background:var(--bg);border-radius:8px;text-align:center">
          <div style="font-size:18px;font-weight:800;color:var(--primary)">${userWorkouts.length}</div>
          <div style="font-size:10px;color:var(--muted-fg)">Total workouts</div>
        </div>` : ''}
      </div>
    </div>`;
  }

  c.innerHTML = html;

  // Bind
  $('health-go-profile')?.addEventListener('click', () => { openProfile(); });
  // Manual sync — re-poke the native bridge to run a fresh HealthKit
  // foreground query (which lands back via tpNative.onHealthSummary)
  // and also poke the watch so it pushes its own latest snapshot.
  $('health-resync-btn')?.addEventListener('click', async (e) => {
    const btn = e.currentTarget;
    btn.disabled = true; const orig = btn.textContent; btn.textContent = 'Syncing…';
    try {
      // Bump the native side — it has a UIApplication.didBecomeActive
      // hook that triggers a fresh sync. We piggyback by sending a no-op
      // ping which the bridge handler treats as a hint to refresh.
      window.webkit?.messageHandlers?.tpNative?.postMessage({ type: 'request-health-sync' });
      // Also ask the watch to re-push (if paired). The watch fires
      // ConnectivityService.shared.onSnapshotRequested when this lands.
      try { pushWatchState(); } catch(_) {}
      // Give the bridge a beat to round-trip — the actual update lands
      // via onHealthSummary which re-renders this tab.
      setTimeout(() => {
        btn.textContent = '✓ Synced';
        setTimeout(() => { renderHealthTab(); }, 600);
      }, 1200);
    } catch (err) {
      btn.textContent = orig;
      btn.disabled = false;
      showToast?.('Could not sync — make sure Health is enabled in Settings.', 'warn');
    }
  });
}

// --- Health Dashboard ---
function openHealthDashboard() {
  const h = userProfile?.health || {};
  const workoutsWithHr = userWorkouts.filter(w => w.heartRate).slice(0, 10);
  const avgHr = workoutsWithHr.length > 0 ? Math.round(workoutsWithHr.reduce((s, w) => s + w.heartRate, 0) / workoutsWithHr.length) : null;
  const maxHr = workoutsWithHr.length > 0 ? Math.max(...workoutsWithHr.map(w => w.heartRate)) : null;
  const totalMins = userWorkouts.reduce((s, w) => s + (w.duration || 0), 0);
  const totalDist = userWorkouts.reduce((s, w) => s + (w.distance || 0), 0);
  let html = '<div class="sheet-title">Health Dashboard</div>';
  // Current stats
  html += '<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:14px">';
  if (h.latestHr) html += `<div style="text-align:center;padding:14px 8px;background:rgba(var(--destructive-rgb),.06);border:1px solid rgba(var(--destructive-rgb),.1);border-radius:12px">
    <div style="font-size:28px;font-weight:800;color:var(--destructive)">${h.latestHr}</div>
    <div style="font-size:11px;color:var(--muted-fg);margin-top:2px">Current HR</div>
  </div>`;
  if (h.restingHr) html += `<div style="text-align:center;padding:14px 8px;background:rgba(59,130,246,.06);border:1px solid rgba(59,130,246,.1);border-radius:12px">
    <div style="font-size:28px;font-weight:800;color:#3b82f6">${h.restingHr}</div>
    <div style="font-size:11px;color:var(--muted-fg);margin-top:2px">Resting HR</div>
  </div>`;
  if (h.latestSteps) html += `<div style="text-align:center;padding:14px 8px;background:rgba(var(--success-rgb),.06);border:1px solid rgba(var(--success-rgb),.1);border-radius:12px">
    <div style="font-size:28px;font-weight:800;color:var(--success)">${h.latestSteps > 999 ? (h.latestSteps / 1000).toFixed(1) + 'k' : h.latestSteps}</div>
    <div style="font-size:11px;color:var(--muted-fg);margin-top:2px">Steps Today</div>
  </div>`;
  if (h.latestSleep) html += `<div style="text-align:center;padding:14px 8px;background:rgba(124,58,237,.06);border:1px solid rgba(124,58,237,.1);border-radius:12px">
    <div style="font-size:28px;font-weight:800;color:var(--purple)">${h.latestSleep}h</div>
    <div style="font-size:11px;color:var(--muted-fg);margin-top:2px">Sleep</div>
  </div>`;
  if (h.vo2max) html += `<div style="text-align:center;padding:14px 8px;background:rgba(var(--warning-rgb),.06);border:1px solid rgba(var(--warning-rgb),.1);border-radius:12px">
    <div style="font-size:28px;font-weight:800;color:var(--warning)">${h.vo2max}</div>
    <div style="font-size:11px;color:var(--muted-fg);margin-top:2px">VO2 Max</div>
  </div>`;
  html += '</div>';
  // Workout heart rate history
  if (workoutsWithHr.length > 0) {
    html += '<div style="font-size:13px;font-weight:700;color:var(--fg);margin-bottom:8px">Workout Heart Rate</div>';
    html += `<div style="display:flex;gap:12px;margin-bottom:10px">
      ${avgHr ? `<div style="font-size:12px;color:var(--muted-fg)">Avg: <strong style="color:var(--fg)">${avgHr}</strong> bpm</div>` : ''}
      ${maxHr ? `<div style="font-size:12px;color:var(--muted-fg)">Peak: <strong style="color:var(--destructive)">${maxHr}</strong> bpm</div>` : ''}
    </div>`;
    // Simple bar chart of recent HR
    html += '<div style="display:flex;align-items:end;gap:3px;height:60px;margin-bottom:12px">';
    const hrMax = Math.max(...workoutsWithHr.map(w => w.heartRate));
    workoutsWithHr.reverse().forEach(w => {
      const pct = hrMax > 0 ? (w.heartRate / hrMax) * 100 : 0;
      const d = w.date ? (w.date.toDate ? w.date.toDate() : new Date(w.date)) : new Date();
      const color = w.heartRate > 160 ? '#ef4444' : w.heartRate > 140 ? '#f59e0b' : '#22c55e';
      html += `<div style="flex:1;display:flex;flex-direction:column;align-items:center;gap:2px">
        <div style="font-size:8px;color:var(--muted-fg)">${w.heartRate}</div>
        <div style="width:100%;height:${pct}%;min-height:4px;background:${color};border-radius:3px 3px 0 0"></div>
        <div style="font-size:7px;color:var(--muted-fg)">${d.getDate()}/${d.getMonth() + 1}</div>
      </div>`;
    });
    html += '</div>';
  }
  // Training totals
  html += '<div style="font-size:13px;font-weight:700;color:var(--fg);margin-bottom:8px">Training Totals</div>';
  html += `<div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px;margin-bottom:14px">
    <div style="text-align:center;padding:10px 4px;background:var(--bg);border-radius:10px">
      <div style="font-size:18px;font-weight:800;color:var(--fg)">${userWorkouts.length}</div>
      <div style="font-size:10px;color:var(--muted-fg)">workouts</div>
    </div>
    <div style="text-align:center;padding:10px 4px;background:var(--bg);border-radius:10px">
      <div style="font-size:18px;font-weight:800;color:var(--fg)">${totalMins > 60 ? (totalMins / 60).toFixed(1) + 'h' : totalMins + 'm'}</div>
      <div style="font-size:10px;color:var(--muted-fg)">total time</div>
    </div>
    <div style="text-align:center;padding:10px 4px;background:var(--bg);border-radius:10px">
      <div style="font-size:18px;font-weight:800;color:var(--fg)">${totalDist > 0 ? totalDist.toFixed(1) + 'km' : '--'}</div>
      <div style="font-size:10px;color:var(--muted-fg)">distance</div>
    </div>
  </div>`;
  // Sync info
  html += '<div style="font-size:13px;font-weight:700;color:var(--fg);margin-bottom:6px">How to Sync</div>';
  html += `<div style="font-size:12px;color:var(--muted-fg);line-height:1.5;margin-bottom:8px">
    <strong style="color:var(--fg)">Strava:</strong> Profile → Connect Strava<br>
    <strong style="color:var(--fg)">Apple Watch:</strong> Open the TurboPrep iPhone app once and grant Health permission. Heart rate, steps, and sleep sync automatically from HealthKit during workouts.
  </div>`;
  if (h.lastSync) html += `<div style="font-size:10px;color:var(--muted-fg)">Last sync: ${timeAgo(new Date(h.lastSync))}</div>`;
  $('sheet-content').innerHTML = html;
  openSheet();
}
// --- Weather ---
const WEATHER_KEY = 'c286357e02b8753b54b5b7bf3e4ee1ce';
async function loadWeather() {
  // Check if fresh data needed (15 min TTL)
  try {
    const cached = JSON.parse(localStorage.getItem('tp_weather') || '{}');
    if (cached.ts && Date.now() - cached.ts < 15 * 60 * 1000) return; // Cache is fresh, already rendered inline
  } catch(e) {}
  // Get location
  let lat = -37.81, lon = 144.96; // Default: Melbourne
  try {
    const pos = await new Promise((res, rej) => navigator.geolocation.getCurrentPosition(res, rej, { timeout: 5000 }));
    lat = pos.coords.latitude;
    lon = pos.coords.longitude;
  } catch(e) {}
  try {
    const resp = await fetch(`https://api.openweathermap.org/data/2.5/weather?lat=${lat}&lon=${lon}&units=metric&appid=${WEATHER_KEY}`);
    if (!resp.ok) return;
    const data = await resp.json();
    const w = {
      temp: Math.round(data.main?.temp || 0),
      feels: Math.round(data.main?.feels_like || 0),
      desc: data.weather?.[0]?.description || '',
      icon: data.weather?.[0]?.icon || '01d',
      wind: Math.round((data.wind?.speed || 0) * 3.6),
      humidity: data.main?.humidity || 0,
      city: data.name || '',
      ts: Date.now()
    };
    try { localStorage.setItem('tp_weather', JSON.stringify(w)); } catch(e) {}
    // Soft-update the card if it exists on screen
    const el = $('weather-card');
    if (el) renderWeatherCard(el, w);
  } catch(e) {}
}
function renderWeatherCard(el, w) {
  const iconUrl = `https://openweathermap.org/img/wn/${w.icon}@2x.png`;
  const advice = w.wind >= 30 ? 'Strong winds — consider indoor training'
    : w.temp < 8 ? 'Cold out — wear layers'
    : w.temp > 35 ? 'Extreme heat — train early or indoors'
    : w.temp >= 20 ? 'Great conditions for training'
    : 'Good conditions for training';
  const bgGrad = w.icon?.includes('n') ? 'linear-gradient(135deg,rgba(30,41,59,.9),rgba(51,65,85,.8))' : 'linear-gradient(135deg,rgba(59,130,246,.12),rgba(124,58,237,.06))';
  const borderCol = w.icon?.includes('n') ? 'rgba(100,116,139,.3)' : 'rgba(59,130,246,.2)';
  el.innerHTML = `<div style="padding:14px 16px;background:${bgGrad};border:1px solid ${borderCol};border-radius:14px;margin-bottom:10px">
    <div style="display:flex;align-items:center;gap:12px;margin-bottom:6px">
      <img src="${iconUrl}" style="width:52px;height:52px;margin:-8px" alt="${escHtml(w.desc)}">
      <div style="flex:1">
        <div style="display:flex;align-items:baseline;gap:6px">
          <span style="font-size:32px;font-weight:800;color:var(--fg);line-height:1">${w.temp}°</span>
          <span style="font-size:13px;color:var(--muted-fg);text-transform:capitalize">${escHtml(w.desc)}</span>
        </div>
        <div style="font-size:12px;color:var(--muted-fg);margin-top:2px">Feels ${w.feels}°${w.city ? ' · ' + escHtml(w.city) : ''}</div>
      </div>
    </div>
    <div style="display:flex;gap:12px;margin-bottom:6px">
      <span style="font-size:11px;color:var(--muted-fg)">Wind ${w.wind} km/h</span>
      <span style="font-size:11px;color:var(--muted-fg)">Humidity ${w.humidity}%</span>
    </div>
    <div style="font-size:12px;font-weight:600;color:var(--fg)">${advice}</div>
  </div>`;
}
function addSessionToCalendar(session) {
  const startDate = new Date(session.date + 'T' + (session.time || '16:00') + ':00');
  const endDate = session.endTime ? new Date(session.date + 'T' + session.endTime + ':00') : new Date(startDate.getTime() + 60 * 60 * 1000);
  const title = session.title || 'Training Session';
  const loc = session.location || '';
  const notes = session.notes || '';
  // ICS / Google / Outlook formatters that emit FLOATING LOCAL time —
  // was previously emitting UTC stamps (`.toISOString()`), which on
  // AEST devices shifted a 4pm event to 6am the next day in the
  // calendar. Floating times mean "use the device's local timezone"
  // when the event is rendered, which is what users expect for a
  // school training session at "16:00".
  const pad = (n) => String(n).padStart(2, '0');
  const floatLocal = (d) =>
    d.getFullYear() + pad(d.getMonth() + 1) + pad(d.getDate()) + 'T' +
    pad(d.getHours()) + pad(d.getMinutes()) + pad(d.getSeconds());
  const fmt = floatLocal;       // for ICS DTSTART/DTEND (floating)
  const fmtLocal = floatLocal;  // for Google's `dates=` param
  // Show calendar picker
  const content = `<div style="padding:4px 0">
    <div style="font-size:14px;font-weight:700;margin-bottom:12px">Add to Calendar</div>
    <button class="btn cal-opt" data-cal="google" style="width:100%;padding:12px;margin-bottom:8px;font-size:13px;font-weight:600;background:var(--card);border:1px solid var(--border);border-radius:10px;color:var(--fg);text-align:left;cursor:pointer">Google Calendar</button>
    <button class="btn cal-opt" data-cal="apple" style="width:100%;padding:12px;margin-bottom:8px;font-size:13px;font-weight:600;background:var(--card);border:1px solid var(--border);border-radius:10px;color:var(--fg);text-align:left;cursor:pointer">Apple Calendar (.ics)</button>
    <button class="btn cal-opt" data-cal="outlook" style="width:100%;padding:12px;font-size:13px;font-weight:600;background:var(--card);border:1px solid var(--border);border-radius:10px;color:var(--fg);text-align:left;cursor:pointer">Outlook Calendar</button>
  </div>`;
  $('sheet-content').innerHTML = content;
  openSheet();
  document.querySelectorAll('.cal-opt').forEach(btn => {
    btn.addEventListener('click', () => {
      const cal = btn.dataset.cal;
      if (cal === 'google') {
        const gUrl = `https://calendar.google.com/calendar/render?action=TEMPLATE&text=${encodeURIComponent(title)}&dates=${fmtLocal(startDate)}/${fmtLocal(endDate)}&location=${encodeURIComponent(loc)}&details=${encodeURIComponent(notes)}`;
        window.open(gUrl, '_blank');
        showToast('Opening Google Calendar...', 'success');
      } else if (cal === 'outlook') {
        const oUrl = `https://outlook.live.com/calendar/0/action/compose?subject=${encodeURIComponent(title)}&startdt=${startDate.toISOString()}&enddt=${endDate.toISOString()}&location=${encodeURIComponent(loc)}&body=${encodeURIComponent(notes)}`;
        window.open(oUrl, '_blank');
        showToast('Opening Outlook Calendar...', 'success');
      } else {
        // Apple / generic .ics download
        const ics = [
          'BEGIN:VCALENDAR', 'VERSION:2.0', 'PRODID:-//TurboPrep//Training//EN',
          'BEGIN:VEVENT',
          'DTSTART:' + fmt(startDate), 'DTEND:' + fmt(endDate),
          'SUMMARY:' + title, 'LOCATION:' + loc,
          'DESCRIPTION:' + notes.replace(/\n/g, '\\n'),
          'BEGIN:VALARM', 'TRIGGER:-PT30M', 'ACTION:DISPLAY', 'DESCRIPTION:Training in 30 minutes', 'END:VALARM',
          'END:VEVENT', 'END:VCALENDAR'
        ].join('\r\n');
        const blob = new Blob([ics], { type: 'text/calendar;charset=utf-8' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = title.replace(/[^a-zA-Z0-9]/g, '_') + '.ics';
        a.click();
        URL.revokeObjectURL(url);
        showToast('Calendar file downloaded!', 'success');
      }
      closeSheet();
    });
  });
}
function checkTrainingReminder() {
  if (!('Notification' in window) || Notification.permission !== 'granted') return;
  // Skip when the page is hidden — Chrome / iOS Safari throttle
  // setInterval but still fire occasionally; firing reminders against
  // a backgrounded tab is wasteful + can race with stale state.
  if (document.visibilityState === 'hidden') return;
  if (!currentUser) return;  // user signed out — no point
  const today = localDateKey();
  const lastReminder = localStorage.getItem('tp_reminder_date');
  if (lastReminder === today) return;
  // Check upcoming training sessions
  try {
    const sessions = JSON.parse(localStorage.getItem('tp_training_sessions') || '[]');
    const now = new Date();
    const todaySessions = sessions.filter(s => s.date === today && new Date(s.date + 'T' + (s.time || '16:00')) > new Date(now.getTime() - 3600000));
    if (todaySessions.length > 0) {
      localStorage.setItem('tp_reminder_date', today);
      const s = todaySessions[0];
      const msg = s.title + (s.location ? ' at ' + s.location : '') + (s.time ? ' — ' + s.time : '');
      try {
        if (navigator.serviceWorker && navigator.serviceWorker.ready) {
          navigator.serviceWorker.ready.then(reg => {
            reg.showNotification('Training Session Today', { body: msg, tag: 'training-session', data: { url: '/' } });
          });
        } else {
          new Notification('Training Session Today', { body: msg, tag: 'training-session' });
        }
      } catch(e) {}
    }
  } catch(e) {}
}
// Stored handle so the sign-out cleanup can clearInterval — was leaking
// a 15-min reminder check forever after logout.
let _trainingReminderInterval = setInterval(checkTrainingReminder, 15 * 60 * 1000);
